const ITP_QUESTIONS = [{"id": 1, "q": "A社はB社に業務を委託している。B社の従業員がA社の指揮命令に従って作業する場合，労働関係法令上どのような問題が生じるか。", "opts": ["適法な請負", "業務委託契約の正常な履行", "労働者派遣法の適用除外", "偽装請負"], "ans": 3, "exp": "請負契約において発注者が受注者の従業員を指揮命令すると偽装請負となり，違法。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 2, "q": "クラウドサービスのセキュリティ管理に特化した情報セキュリティの国際規格として最も適切なものはどれか。", "opts": ["ISO 9001", "JIS Q 15001", "ISO 14001", "ISO/IEC 27017"], "ans": 3, "exp": "ISO/IEC 27017はクラウドサービスに特化したセキュリティ管理ガイドライン規格。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 3, "q": "官民データ活用推進基本法において，オープンデータの公開が義務付けられているのはどれか。", "opts": ["民間企業", "独立行政法人のみ", "国および地方公共団体", "地方公共団体のみ"], "ans": 2, "exp": "官民データ活用推進基本法では，国および地方公共団体にオープンデータ公開が義務付けられている。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 4, "q": "経営資源の強み・弱み・機会・脅威を分析するフレームワークとして最も適切なものはどれか。", "opts": ["4P分析", "PPM", "SWOT分析", "VRIO分析"], "ans": 2, "exp": "SWOT分析はStrengths/Weaknesses/Opportunities/Threatsの四要素で経営環境を分析するフレームワーク。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 5, "q": "売上原価を「期首棚卸高＋当期仕入高－期末棚卸高」で計算するとき，期末棚卸高の評価に先入先出法を用いた場合，移動平均法と比べ物価上昇局面での期末棚卸高はどうなるか。", "opts": ["低くなる", "計算できない", "高くなる", "変わらない"], "ans": 2, "exp": "先入先出法は古い（安い）在庫から払い出すため，期末には新しい（高い）在庫が残り，物価上昇局面では期末棚卸高が高くなる。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 6, "q": "特定電子メール法において，受信者の同意なく送信が原則禁止されている電子メールはどれか。", "opts": ["社内通知メール", "請求書メール", "業務連絡メール", "広告宣伝メール"], "ans": 3, "exp": "特定電子メール法は一方的な広告宣伝メールの送信を規制しており，オプトイン方式（事前同意）が必要。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 7, "q": "新技術やアイデアが実用化可能かどうかを事前に小規模で検証する取り組みを表す用語はどれか。", "opts": ["PoC", "ベンチマーキング", "バックキャスティング", "アジャイル開発"], "ans": 0, "exp": "PoC（Proof of Concept：概念実証）は，本格開発前にアイデアの実現可能性を検証する取り組み。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 8, "q": "AIの学習データに関するバイアス低減の取り組みとして，適切なものだけを全て挙げたものはどれか。a 多様なデータソースからデータを収集する。b データの入手元・作成来歴を確認する。", "opts": ["b", "a，b", "a", "なし"], "ans": 1, "exp": "バイアス低減のためには多様なデータ収集と来歴確認が両方必要。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 9, "q": "複数の参加チームが短期間でプロトタイプを作成し競い合うイベントを何というか。", "opts": ["ブレインストーミング", "リーンスタートアップ", "デザインシンキング", "ハッカソン"], "ans": 3, "exp": "ハッカソンはプログラマーやデザイナーなどが集まり，短期間でプロダクトを開発して競い合うイベント。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 10, "q": "AIが事実とは異なる情報を自信を持って出力する現象を表す用語として，最も適切なものはどれか。", "opts": ["シンギュラリティ", "エコーチェンバー", "ハルシネーション", "ディープフェイク"], "ans": 2, "exp": "ハルシネーション（幻覚）は生成AIがもっともらしいが事実と異なる内容を出力する現象。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 11, "q": "複数の工作機械や産業用ロボットを有機的に結合し，生産プロセス全体を統括的に制御・管理するシステムはどれか。", "opts": ["FMS", "ERP", "MRP", "SCM"], "ans": 0, "exp": "FMS（Flexible Manufacturing System）は複数の工作機械やロボットを統合して柔軟に生産管理するシステム。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 12, "q": "輸送業者や金融業者が提供するサービスを，他社のサービスと区別するために表示する商標はどれか。", "opts": ["ブランドマーク", "サービスマーク", "商品商標", "トレードマーク"], "ans": 1, "exp": "サービスマークはサービス業者が自社サービスを他社と区別するために使う商標。商品商標との違いを理解すること。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 13, "q": "ベンダ企業にITソリューションの活用事例や技術情報の提供を依頼するための文書はどれか。", "opts": ["EDI", "RFP", "SLA", "RFI"], "ans": 3, "exp": "RFI（Request for Information）は情報提供依頼書。RFP（提案依頼書）とは異なり，具体的な提案ではなく情報収集が目的。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 14, "q": "知的財産情報を経営分析に活用し，知財戦略を経営戦略に反映させる手法を表す用語はどれか。", "opts": ["CVC", "SWOT分析", "MOT", "IPランドスケープ"], "ans": 3, "exp": "IPランドスケープは特許などの知財情報を経営分析に取り込み，知財戦略と経営戦略を連携させる手法。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 15, "q": "事業領域ごとに独立した組織を設け，各組織が独立採算で事業運営する組織形態はどれか。", "opts": ["プロジェクト組織", "カンパニー制組織", "機能別組織", "マトリックス組織"], "ans": 1, "exp": "カンパニー制組織は企業内に独立した事業会社を設置し，意思決定の迅速化と独立採算を目指す組織形態。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 16, "q": "他人の利用者IDとパスワードを正当な理由なく第三者に提供する行為を規制する法律はどれか。", "opts": ["著作権法", "不正アクセス禁止法", "個人情報保護法", "電子署名法"], "ans": 1, "exp": "不正アクセス禁止法は不正アクセス行為とその助長行為（ID・パスワードの無断提供等）を規制する。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 17, "q": "業務システムの操作ログを収集・分析し，現行の業務プロセスを可視化・改善する手法はどれか。", "opts": ["RPA", "BPR", "プロセスマイニング", "ERP"], "ans": 2, "exp": "プロセスマイニングはシステムログを基に業務プロセスを可視化し，ボトルネックの特定や改善を行う手法。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 18, "q": "高齢者や障害者を含む幅広い人が等しく利用できるように設計するITの考え方はどれか。", "opts": ["UX", "ユーザビリティ", "アクセシビリティ", "ユニバーサルデザイン"], "ans": 2, "exp": "アクセシビリティはITにおいて様々な能力・特性の人が等しく利用できるよう配慮する設計概念。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 19, "q": "現実世界の映像に仮想情報を重ね合わせる技術の活用事例として最も適切なものはどれか。", "opts": ["ゴーグルで完全仮想空間に入り訓練する", "VRゲームでコントローラを使ってプレイする", "3D映画館で立体映像を楽しむ", "スマートフォンカメラ越しに家具を実際の部屋に重ねて試し置きする"], "ans": 3, "exp": "AR（拡張現実）は現実映像に仮想情報を重ねる技術。家具の試し置きや道案内等に活用される。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 20, "q": "ソフトウェアのシステム化構想立案時にベンダ企業から収集する情報として最も適切なものはどれか。", "opts": ["自社の業務プロセスの詳細", "発注元企業の役割と責任", "システム化する分野の情報技術動向", "プロジェクトメンバーの個人情報"], "ans": 2, "exp": "システム化構想の企画段階では，ベンダ企業から当該分野の技術動向・製品情報を収集するのが適切。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 21, "q": "基本機能を無料で提供し，追加機能を有料で提供することで収益を上げるビジネスモデルはどれか。", "opts": ["シェアリングエコノミー", "フリーウェア", "サブスクリプション", "フリーミアム"], "ans": 3, "exp": "フリーミアムはFree+Premiumの造語。基本サービス無料，上位機能を有料で提供するビジネスモデル。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 22, "q": "複数担当者の売上データを集計してグラフ化するのに最も適したツールはどれか。", "opts": ["ワープロソフト", "データベースソフト", "表計算ソフト", "プレゼンテーションソフト"], "ans": 2, "exp": "表計算ソフトは数値データの入力・集計・グラフ化に最適なオフィスツール。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 23, "q": "コーポレートガバナンス強化に有効な施策として適切なものだけを全て挙げたものはどれか。a 執行役員制度の導入  b 独立性の高い社外取締役の選任", "opts": ["どちらも不適切", "aのみ", "a，b", "bのみ"], "ans": 2, "exp": "コーポレートガバナンス強化には経営と執行の分離（執行役員制）と外部からの監督（社外取締役）が有効。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 24, "q": "ホワイトカラーの定型的な事務作業をソフトウェアのロボットで自動化する技術はどれか。", "opts": ["AI", "IoT", "BPR", "RPA"], "ans": 3, "exp": "RPA（Robotic Process Automation）はソフトウェアロボットを使って定型業務を自動化する技術。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 25, "q": "取引データを分散管理し，改ざんが困難な仕組みによって信頼性を確保する技術はどれか。", "opts": ["エッジコンピューティング", "ブロックチェーン", "クラウドコンピューティング", "ビッグデータ"], "ans": 1, "exp": "ブロックチェーンは分散台帳技術を用いて取引データを連鎖的に記録し改ざんを困難にする技術。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 26, "q": "4月から6月の取引で，6月末時点の売掛金を計算する問題として，売上計上済みかつ未回収の金額はいくらか。（取引内容に応じて計算）", "opts": ["1,000万円", "2,700万円", "2,300万円", "1,400万円"], "ans": 2, "exp": "売上計上済みで現金回収されていない取引の合計が売掛金。受注のみや回収済みは含まない。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 27, "q": "業務と情報システムの現状を把握し，あるべき姿とのギャップを明確にして改善計画を立案する手法はどれか。", "opts": ["BI", "SOA", "MOT", "EA"], "ans": 3, "exp": "EA（Enterprise Architecture）は業務・情報システムの現状とあるべき姿を整理し，移行計画を策定するフレームワーク。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 28, "q": "大量の学習データを基に様々なタスクに汎用的に対応できるAIモデルを何というか。", "opts": ["畳み込みニューラルネットワーク", "エキスパートシステム", "基盤モデル", "アノテーション"], "ans": 2, "exp": "基盤モデル（Foundation Model）は大規模データで訓練され，ファインチューニングで様々な用途に適応できるAI。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 29, "q": "企業の行動指針や判断基準となる価値観を，MVV（ミッション・ビジョン・バリュー）のうちバリューが表すものとして適切なものはどれか。", "opts": ["業績管理指標", "行動指針・価値観", "企業の存在意義", "ありたい姿"], "ans": 1, "exp": "バリュー（Value）は企業が大切にする価値観・行動指針。ミッションは使命，ビジョンはありたい姿。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 30, "q": "著作権法でソースプログラムは保護されるが，アルゴリズム自体は保護されない理由として最も適切なものはどれか。", "opts": ["アルゴリズムは数学的概念であり思想だから", "アルゴリズムは特許で保護されるから", "アルゴリズムは著作物の定義を満たさないから", "アルゴリズムは表現形式であるから"], "ans": 0, "exp": "著作権法は「表現」を保護し「アイデア・思想」は保護しない。アルゴリズムは表現でなく思想・アイデアに該当。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 31, "q": "経理・人事・生産・販売などの基幹業務を一元管理して経営資源を最適配分するシステムはどれか。", "opts": ["SCM", "SFA", "ERP", "CRM"], "ans": 2, "exp": "ERP（Enterprise Resource Planning）は企業の基幹業務を統合管理し，経営資源を効率的に配分するシステム。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 32, "q": "個人の移動や購買履歴などの活動記録データを蓄積・活用する技術を何というか。", "opts": ["トランザクション", "ライフログ", "メタデータ", "アクティビティ"], "ans": 1, "exp": "ライフログは個人の生活行動（移動・購買・SNS投稿等）を記録・蓄積したデータ。", "cat": "ストラテジ", "diff": "easy", "year": 2025}, {"id": 33, "q": "自動運転において，運転主体はシステムだが作動継続が困難な場合は人間が引き継ぐ水準はどれか。", "opts": ["レベル2", "レベル4", "レベル3", "レベル5"], "ans": 2, "exp": "レベル3（条件付運転自動化）はシステムが主体だが，困難時に人間への引継ぎが必要なレベル。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 34, "q": "ある商品の変動費が1個あたり6,000円，固定費が総額400万円，販売価格が1個10,000円のとき，損益分岐点の販売数量はいくらか。", "opts": ["800個", "1,000個", "500個", "1,500個"], "ans": 1, "exp": "損益分岐点 = 固定費÷（販売価格－変動費）= 4,000,000÷(10,000-6,000) = 1,000個。", "cat": "ストラテジ", "diff": "hard", "year": 2025}, {"id": 35, "q": "マーケティングの3C分析で，自社の強みを活かして顧客ニーズに応える際に考慮すべきものとして適切なものはどれか。", "opts": ["Customer，Competitor，Company", "Segmentation，Targeting，Positioning", "Cost，Convenience，Communication", "Product，Price，Place"], "ans": 0, "exp": "3C分析はCustomer（顧客），Competitor（競合），Company（自社）の3視点で市場を分析するフレームワーク。", "cat": "ストラテジ", "diff": "mid", "year": 2025}, {"id": 36, "q": "合意したサービス提供時間に対して，実際に利用できた時間の割合を表す指標はどれか。", "opts": ["保守性", "信頼性", "可用性", "効率性"], "ans": 2, "exp": "可用性（Availability）= 実際のサービス提供時間÷合意したサービス提供時間 × 100(%)", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 37, "q": "ITサービスマネジメントにおいて，サービス品質に関する合意書の遵守状況を確認し品質維持・改善を行う活動はどれか。", "opts": ["インシデント管理", "SLA管理", "SLM（サービスレベル管理）", "変更管理"], "ans": 2, "exp": "SLM（Service Level Management）はSLAの遵守状況を監視し，ITサービスの品質を継続的に改善する活動。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 38, "q": "情報セキュリティ監査の説明として，最も適切なものはどれか。", "opts": ["コンピュータの盗難を防止するセキュリティツールの導入", "組織のITシステム利活用のあるべき姿を示すIT戦略の策定", "ITシステムへの物理的な侵入を防ぐ対策", "情報資産のリスク管理が効果的に行われているかを検証・評価すること"], "ans": 3, "exp": "情報セキュリティ監査は，組織の情報資産に関わるリスクマネジメントが適切かを独立した立場で検証・評価。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 39, "q": "アジャイル開発モデルの特徴として，最も適切なものはどれか。", "opts": ["外部パッケージを最大限活用して開発期間を短縮する", "工程ごとに完全なドキュメントを作成してから次工程へ進む", "開発工程の変更に迅速に対応できる反復的な開発手法", "全要件を確定してから開発を開始する"], "ans": 2, "exp": "アジャイル開発はウォーターフォールと異なり，変化への迅速な対応を可能にする反復型開発手法の総称。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 40, "q": "プロジェクトで変更要求が発生したとき，変更管理委員会の役割として適切なものはどれか。", "opts": ["ステークホルダーが変更要求を審議する", "コスト増を理由に変更を全て却下する", "プロジェクトマネージャだけで全変更を決定する", "全変更を自動承認する"], "ans": 0, "exp": "変更管理委員会はプロジェクト関係者が参加し，変更要求の影響を評価して承認・却下を決定する機関。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 41, "q": "システム開発でスケジュール作成に用いる技法として，最も適切なものはどれか。", "opts": ["クリティカルパス法", "DFD", "UML", "回帰分析"], "ans": 0, "exp": "クリティカルパス法はPERT/CPMとも呼ばれ，プロジェクトの最長経路（クリティカルパス）を求めてスケジュール管理に用いる。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 42, "q": "床下にネットワーク配線用の空間をとり，フロアパネルを自由に取り外せる床構造はどれか。", "opts": ["OAフロア防塵タイプ", "フリースペース", "フリーアクセスフロア", "フリーアドレス"], "ans": 2, "exp": "フリーアクセスフロアは床下に配線スペースを設けた二重床。ネットワーク配線の変更が容易。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 43, "q": "組織のけん制として，経費精算書類を作成した者とは別の者が審査する仕組みはどれか。", "opts": ["職務の分離", "アクセス制御", "監査ログ", "バックアップ"], "ans": 0, "exp": "内部統制のけん制（相互牽制）は，同一人物が業務を完結できないよう職務を分離すること。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 44, "q": "開発早期に利用者の要求を目に見える形で確認できるソフトウェアを作成して検証する開発モデルはどれか。", "opts": ["ウォーターフォールモデル", "RADモデル", "プロトタイピングモデル", "スパイラルモデル"], "ans": 2, "exp": "プロトタイピングモデルは試作品（プロトタイプ）を早期に作成し利用者と確認しながら要件を明確化する手法。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 45, "q": "プロジェクトの計画予算に対する実績コストの割合（コスト効率）を表すEVMの指標はどれか。", "opts": ["SPI", "CPI", "AC", "EV"], "ans": 1, "exp": "CPI（Cost Performance Index）= EV（出来高）÷AC（実績コスト）。1より小さければコスト超過。", "cat": "マネジメント", "diff": "hard", "year": 2025}, {"id": 46, "q": "開発完了したソフトウェアを本番環境に移行・導入する工程として適切なものはどれか。", "opts": ["ソフトウェア導入", "要件定義", "システムテスト", "受入テスト"], "ans": 0, "exp": "ソフトウェア導入はリリース管理の一部で，開発済みソフトウェアを本番環境にインストール・設定する工程。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 47, "q": "ATMの利用者インタフェース設計において，使用性（ユーザビリティ）を考慮すべき対象として最も適切なものはどれか。", "opts": ["利用者と操作パネルのインタフェース", "ソフトウェア間のインタフェース", "ATMとホストコンピュータ間のインタフェース", "OSとハードウェアのインタフェース"], "ans": 0, "exp": "使用性（ユーザビリティ）は利用者が実際に操作する部分のインタフェース設計で考慮する。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 48, "q": "委託システム開発において，プロジェクトのスコープに含まれるものとして適切なものはどれか。", "opts": ["顧客の業務マニュアル全般", "市販のプロジェクト管理ツール", "プロジェクトで作成する成果物", "外部ベンダとの契約書"], "ans": 2, "exp": "プロジェクトスコープは，そのプロジェクトが実施する作業と成果物の範囲。既製品や外部文書は含まない。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 49, "q": "24時間対応可能なサービスデスク機能を実現するためにチャットボットを導入する最大の効果はどれか。", "opts": ["電話対応件数が増加する", "オペレータのスキルが向上する", "問合せ受付時間が拡大する", "FAQの内容が充実する"], "ans": 2, "exp": "チャットボットは24時間365日自動応答できるため，受付時間の大幅な拡大が最大の導入効果。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 50, "q": "自然言語で指示を受け，学習済みデータを基に新しいテキスト・画像・音楽などを生成するAIはどれか。", "opts": ["エキスパートシステム", "強化学習AI", "生成AI", "推薦システム"], "ans": 2, "exp": "生成AI（Generative AI）は大量のデータから学習し，テキスト・画像等の新しいコンテンツを生成するAI。", "cat": "マネジメント", "diff": "easy", "year": 2025}, {"id": 51, "q": "社内の経理システムに対して内部監査を実施する場合，システム監査人として最も適切な者はどれか。", "opts": ["経理システムの利用者である経理担当者", "経理システムの開発を担当した社員", "経理とITの知識を持つ経営者直轄組織の従業員", "経理システムの運用担当者"], "ans": 2, "exp": "内部監査人は監査対象業務から独立している必要があり，経営者直轄の独立した立場の者が適切。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 52, "q": "外部委託したシステム開発プロジェクトにおいて，品質管理手続きの遵守状況を監査する人物として適切なのはどれか。", "opts": ["委託先の品質管理責任者", "委託先に関与しない委託元の管理部門リーダー", "委託元のプロジェクトマネージャ", "委託先のプロジェクトリーダー"], "ans": 1, "exp": "監査人は対象業務から独立している必要がある。委託先に関与しない委託元の第三者が適切。", "cat": "マネジメント", "diff": "hard", "year": 2025}, {"id": 53, "q": "内部統制の「ITへの対応」において適切な記述はどれか。", "opts": ["全業務をIT自動化すると内部統制が容易になる", "業務がITに大きく依存すると内部統制目的の達成が困難になる", "既存ITで目標達成できるなら新システム導入は不要", "IT活用で全てのミスを防止できる"], "ans": 2, "exp": "内部統制でのIT活用は目的達成手段。既存システムで目的を達成できるなら，新システム導入を強要しない。", "cat": "マネジメント", "diff": "hard", "year": 2025}, {"id": 54, "q": "AIを導入したコールセンターで，AI対応でグループAの対応時間が50%短縮し，グループBは変化なしのとき，全体の短縮率は何%か。（グループA：全体の60%，グループB：全体の40%）", "opts": ["40%", "30%", "20%", "50%"], "ans": 1, "exp": "全体短縮率 = 0.6×50% + 0.4×0% = 30%。グループAだけが短縮されるため全体では30%の短縮。", "cat": "マネジメント", "diff": "hard", "year": 2025}, {"id": 55, "q": "プロジェクト開始時に人的資源計画を立てる際，適切な対応として最も適切なものはどれか。", "opts": ["役割と責任はプロジェクト開始後に定める", "スキル不足の要員にはトレーニングを計画する", "外部調達は計画に含めない", "スキルより要員確保を常に優先する"], "ans": 1, "exp": "人的資源計画では必要スキルを特定し，不足スキルへの対応（トレーニング・外部調達等）を計画する。", "cat": "マネジメント", "diff": "mid", "year": 2025}, {"id": 56, "q": "省電力性に優れ，IoTデバイスの長期運用に適したBluetoothの規格はどれか。", "opts": ["PLC", "BLE", "NFC", "IrDA"], "ans": 1, "exp": "BLE（Bluetooth Low Energy）はBluetooth 4.0以降の省電力規格。IoTセンサなどの長期バッテリ駆動に適する。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 57, "q": "PCからインターネット上のWebサーバへの接続要求を代理で受け取り，Webサーバへ接続してデータを中継するサーバはどれか。", "opts": ["DHCPサーバ", "DNSサーバ", "HTTPプロキシサーバ", "メールサーバ"], "ans": 2, "exp": "HTTPプロキシサーバはクライアントの代理としてWebサーバに接続し，レスポンスを中継する。キャッシュ機能も持つ。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 58, "q": "ホスト名をIPアドレスに変換する仕組みはどれか。", "opts": ["DHCP", "DNS", "FTP", "SMTP"], "ans": 1, "exp": "DNS（Domain Name System）はホスト名（ドメイン名）とIPアドレスを相互に変換する仕組み。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 59, "q": "ISMSの内部監査において，JIS Q 27001の要求事項を監査基準とし，ISMS活動の有効性も判定する記述として適切なものはどれか。", "opts": ["JIS Q 27001と組織の規定を両方基準とする", "抜き打ちで実施する", "組織自体の規定のみを基準とする", "前回結果を考慮しない"], "ans": 0, "exp": "ISMS内部監査は規格要求事項（JIS Q 27001）と組織が規定した要求事項の両方を基準に実施する。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 60, "q": "TCP/IPネットワークでファイル転送に使われるプロトコルはどれか。", "opts": ["SMTP", "HTTP", "FTP", "POP3"], "ans": 2, "exp": "FTP（File Transfer Protocol）はファイルをPC間で転送するためのプロトコル。ポート番号は21。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 61, "q": "DBMSのトランザクション管理において，一連の処理が全成功なら確定し，途中失敗なら処理前に戻す機能はどれか。", "opts": ["インデックス", "バックアップ", "コミットとロールバック", "レプリケーション"], "ans": 2, "exp": "トランザクションはACID特性を持ち，全成功でコミット（確定），失敗でロールバック（取消）する。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 62, "q": "OSの仮想記憶方式において，主記憶の物理的容量を超えた論理的なアドレス空間を提供する説明として適切なものはどれか。", "opts": ["物理的な主記憶を増設することで仮想空間を拡張する", "論理アドレスと物理アドレスは常に一致する", "主記憶の物理的容量に論理的アドレスが制約される", "補助記憶を主記憶として扱い論理的なアドレス空間を提供する"], "ans": 3, "exp": "仮想記憶は補助記憶（HDDなど）を主記憶の延長として使い，プログラムに論理的に大きなアドレス空間を提供する。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 63, "q": "データの尺度のうち，値の差に意味があるが比には意味がないのはどれか。", "opts": ["間隔尺度", "名義尺度", "比例尺度", "順序尺度"], "ans": 0, "exp": "間隔尺度は差の比較が可能（温度差など）だが絶対的な0がないため比率は無意味。時刻・西暦等が該当。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 64, "q": "Webサイトの新着情報をまとめて配信するための標準的なフォーマットはどれか。", "opts": ["HTTPS", "CSS", "RSS", "VPN"], "ans": 2, "exp": "RSS（Rich Site Summary）はWebサイトの見出し・要約・更新日等を配信するXMLベースのフォーマット。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 65, "q": "データベースの検索速度を向上させるために設定するデータ構造はどれか。", "opts": ["外部キー", "スキーマ", "主キー", "インデックス"], "ans": 3, "exp": "インデックス（索引）はデータ検索を高速化するためにDBMSが管理するデータ構造。書籍の索引と同様。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 66, "q": "関係データベースのSQL操作で，条件に合うレコードを取得するSQL文に用いる句はどれか。", "opts": ["CREATE TABLE", "SELECT WHERE", "UPDATE SET", "INSERT INTO"], "ans": 1, "exp": "SELECT文のWHERE句で条件指定した行を取得する。SELECT 列名 FROM テーブル名 WHERE 条件。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 67, "q": "3次元グラフィックスの高速処理や動画処理に特化したハードウェアはどれか。", "opts": ["GPU", "CGI", "UPS", "GUI"], "ans": 0, "exp": "GPU（Graphics Processing Unit）は大量の並列演算を得意とし，3Dグラフィックス・AI計算等に広く使われる。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 68, "q": "セキュリティ事故発生時に，影響範囲の調査と被害拡大防止を支援する組織はどれか。", "opts": ["IPA", "ISMS認証機関", "CSIRT", "ISP"], "ans": 2, "exp": "CSIRT（Computer Security Incident Response Team）は情報セキュリティインシデントの対応・調整を行う組織。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 69, "q": "バイオメトリクス認証で，他人を誤って本人と認識する率を低く抑えようとすると上がるものはどれか。", "opts": ["安全性", "可用性", "信頼性", "利便性"], "ans": 0, "exp": "他人受入率を下げるために認証閾値を厳しくすると，安全性は上がるが本人拒否率も上がり，利便性が低下する。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 70, "q": "ソフトウェアの脆弱性を突いて，修正プログラム提供前に攻撃する手法はどれか。", "opts": ["DDoS攻撃", "フィッシング攻撃", "ブルートフォース攻撃", "ゼロデイ攻撃"], "ans": 3, "exp": "ゼロデイ攻撃は脆弱性が発見されてからセキュリティパッチが提供される前（ゼロデイ）に実行される攻撃。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 71, "q": "コンピュータに関する犯罪や法的紛争の際に，証拠を収集・保全する技術や手続きはどれか。", "opts": ["デジタル署名", "VPN", "ペネトレーションテスト", "デジタルフォレンジックス"], "ans": 3, "exp": "デジタルフォレンジックスは，デジタルデバイスから証拠を収集・分析・保全する法科学技術。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 72, "q": "記憶素子として半導体メモリを用いた記憶媒体だけを全て挙げたものはどれか。a RAM b SSD c USBメモリ d DVD-RAM", "opts": ["a，c，d", "b，c，d", "a，b", "a，b，c"], "ans": 3, "exp": "RAM・SSD・USBメモリは半導体メモリを使用。DVD-RAMは光磁気ディスクであり半導体メモリではない。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 73, "q": "表計算ソフトで絶対参照を使って消費税率セルを固定し，複数商品の税込価格を計算する式はどれか（税率はB1セル，税抜価格はB4セル）。", "opts": ["B4*(1+B1)", "$B4*(1+B1)", "B$4*(1+B$1)", "B4*(1+$B$1)"], "ans": 3, "exp": "列も行も固定するには$B$1の形式（絶対参照）を使う。コピー先でもB1セルの税率を参照し続ける。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 74, "q": "ネットワークやホストを監視し，不正アクセスや不審な通信を検知・報告するシステムはどれか。", "opts": ["DMZ", "VPN", "WAF", "IDS"], "ans": 3, "exp": "IDS（Intrusion Detection System：侵入検知システム）はネットワーク・ホストを監視し不正アクセスを検知する。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 75, "q": "1から7の整数のうち3の倍数の合計を求めるプログラムの出力値はどれか。", "opts": ["3", "6", "9", "12"], "ans": 2, "exp": "3の倍数は3，6の2つ。合計 = 3+6 = 9。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 76, "q": "画像や文書ファイルの内容を縮小して表示したものを何というか。", "opts": ["アバター", "アイコン", "ファビコン", "サムネイル"], "ans": 3, "exp": "サムネイルは画像・動画・文書の内容を小さく縮小して表示したもの。一覧表示などに使われる。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 77, "q": "大量のデータで事前学習し，ファインチューニングで多様なタスクに対応できるAIモデルはどれか。", "opts": ["決定木", "エキスパートシステム", "基盤モデル", "畳み込みニューラルネットワーク"], "ans": 2, "exp": "基盤モデル（Foundation Model）は大規模データで訓練した汎用AIモデル。GPT系などが代表例。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 78, "q": "スキャナで読み取った画像から文字を認識してテキストデータに変換する技術はどれか。", "opts": ["CCD", "OCR", "DVI", "GPU"], "ans": 1, "exp": "OCR（Optical Character Recognition）は画像中の文字を認識しテキストデータに変換する技術。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 79, "q": "データベースの内容を別のサーバにコピーして同期させるDBMSの機能はどれか。", "opts": ["バックアップ", "レプリケーション", "アーカイブ", "ロールバック"], "ans": 1, "exp": "レプリケーションは複数のDBサーバ間でデータを同期・複製し，可用性や負荷分散を実現するDBMS機能。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 80, "q": "ISMSのPDCAサイクルにおいて「Check（点検）」フェーズで実施する作業として適切なものはどれか。", "opts": ["情報セキュリティ目標の設定", "定められた手順に従って監視・測定・分析する", "方針と手順の実施", "発見した問題点の是正処置"], "ans": 1, "exp": "PDCAのCheck（点検）では，計画・実施の結果を監視・測定・分析・評価する。Doが実施，Actが改善。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 81, "q": "ISMSの情報セキュリティ方針に関する適切な記述はどれか。", "opts": ["機密情報なので社内でも共有範囲を限定する", "ISMSの継続的改善へのコミットメントを含む必要がある", "部門ごとに独立した方針を定める", "トップダウンでなくボトムアップで策定する"], "ans": 1, "exp": "ISMS方針には，継続的改善のコミットメント，適用範囲，情報セキュリティ目標が含まれる必要がある。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 82, "q": "AIシステムの正解率が現在30%で，1回の学習ごとに誤り率が5%低下するとき，正解率35%超えに必要な学習回数は最低何回か。", "opts": ["2回", "4回", "1回", "3回"], "ans": 0, "exp": "誤り率：70%→0.95×70%=66.5%（1回）→0.95×66.5%≈63.2%（2回）。正解率：36.8%>35%なので2回。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 83, "q": "大量の画像データから動物の特徴を自動抽出して分類するAI技術はどれか。", "opts": ["ディープラーニング", "e-ラーニング", "アクティブラーニング", "アダプティブラーニング"], "ans": 0, "exp": "ディープラーニング（深層学習）は多層ニューラルネットワークで特徴を自動抽出する機械学習手法。画像認識が得意。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 84, "q": "PKIにおいて，有効期間内に失効したデジタル証明書の情報を公開するリストはどれか。", "opts": ["CA一覧", "公開鍵リスト", "証明書チェーン", "CRL"], "ans": 3, "exp": "CRL（Certificate Revocation List：証明書失効リスト）は有効期間内に失効した証明書のシリアル番号を公開するリスト。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 85, "q": "ICカードによる入退室管理はどの種類のセキュリティ対策か。", "opts": ["人的セキュリティ対策", "管理的セキュリティ対策", "技術的セキュリティ対策", "物理的セキュリティ対策"], "ans": 3, "exp": "ICカードによる入退室管理は物理的な空間へのアクセスを制御する物理的セキュリティ対策。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 86, "q": "Aさんが復号できるメッセージとして適切なものを選べ。a 共通鍵で暗号化 b Aの公開鍵で暗号化 c Bの公開鍵で暗号化 d Bの秘密鍵で暗号化", "opts": ["a，b，d", "c，d", "a，b，c", "b，c"], "ans": 0, "exp": "共通鍵→Aが持つ共通鍵で復号可。Aの公開鍵→Aの秘密鍵で復号可。Bの秘密鍵→Bの公開鍵で復号可（デジタル署名）。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 87, "q": "WPA2はWEPより高い信頼性をもつ無線LAN暗号化技術である，という記述として適切なものはどれか。", "opts": ["WPA2はAES暗号を採用しWEPより強固である", "WPA2はMACアドレスフィルタリングを行う", "WPA2はVPNと同じ機能を持つ", "WPA2はSSIDを非公開にする"], "ans": 0, "exp": "WPA2はAES-CCMP（128bit）を採用し，RC4ベースのWEPより格段に安全な無線LAN暗号化規格。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 88, "q": "ノートPCの紛失・盗難に備えてより厳重に管理することは，情報セキュリティのリスク対応のどれに該当するか。", "opts": ["リスク保有", "リスク低減", "リスク回避", "リスク移転"], "ans": 1, "exp": "管理強化によりリスクの発生確率や影響を小さくする対策はリスク低減（リスク軽減）に該当する。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 89, "q": "ランサムウェア感染時のデータ損失を最小化する対策として最も効果的なものはどれか。", "opts": ["多要素認証の導入", "ウイルス対策ソフトの導入", "強力なパスワードの設定", "定期的なオフラインバックアップの取得"], "ans": 3, "exp": "ランサムウェアはデータを暗号化して身代金要求するため，オフライン（ネット切断）バックアップが最も有効な対策。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 90, "q": "情報セキュリティにおける「脅威」の説明として最も適切なものはどれか。", "opts": ["情報システムの脆弱性", "被害を受ける可能性", "リスクの顕在化後の被害", "情報資産に損害を与える原因"], "ans": 3, "exp": "脅威とは情報資産に損害を与える潜在的な原因。脆弱性（弱点）×脅威（原因）でリスクが生じる。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 91, "q": "稼働率0.9の装置で並列システムを構成し稼働率0.999を達成するには最低何台必要か。", "opts": ["2台", "3台", "5台", "4台"], "ans": 1, "exp": "n台並列の稼働率 = 1-(1-0.9)^n。n=3: 1-0.001=0.999。よって3台。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 92, "q": "データベース設計のデータ分析において，必要なデータ項目を洗い出して項目間の関連を整理する作業はどれか。", "opts": ["SQLによるデータ抽出", "データウェアハウスの構築", "概念設計（エンティティとリレーションの整理）", "ビッグデータ分析"], "ans": 2, "exp": "データ分析では必要な項目を識別し，エンティティとそのリレーションを整理する概念設計が基本。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 93, "q": "OSSに関する記述として適切なものだけを全て挙げたものはどれか。a 個人・企業・団体が開発できる b 著作権は放棄されない c 再配布は一般に自由", "opts": ["a，b，c", "a，b", "a，c", "b，c"], "ans": 2, "exp": "OSSは著作権は保持される（放棄ではない）。個人・法人問わず開発可能で，ライセンス条件の下で再配布が可能。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 94, "q": "DoS攻撃でシステムが処理不能になった事象は情報セキュリティの三要素のどれを損なうか。", "opts": ["可用性", "完全性", "真正性", "機密性"], "ans": 0, "exp": "DoS攻撃はサービスを利用不能にする攻撃。必要なときに利用できない状態は可用性の損失。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 95, "q": "[27, 42, 33, 12]を選択ソートで昇順整列するとき，整列完了までに繰り返し回数は何回か。", "opts": ["2回", "4回", "5回", "3回"], "ans": 3, "exp": "n=4要素の選択ソートはn-1=3回のパスで完了。各パスで最大値を末尾と入替えて範囲を縮小する。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 96, "q": "改善額20万円・短縮3日と，改善額5万円・短縮14日のケースで関数の出力合計はいくらか（改善額10万円以上かつ短縮7日未満→2000円，それ以外→条件に応じ）。", "opts": ["5,500円", "1,000円", "1,500円", "3,000円"], "ans": 3, "exp": "改善額20万≥10万，短縮3日<7日→2000円。改善額5万<10万，短縮14日≥7日→1000円。合計3000円。", "cat": "テクノロジ", "diff": "hard", "year": 2025}, {"id": 97, "q": "認証の三要素のうち「所有物」を用いた認証の例として最も適切なものはどれか。", "opts": ["パスワード認証", "スマートフォンを使ったSMS認証", "虹彩認証", "秘密の質問による認証"], "ans": 1, "exp": "所有物認証はICカード・スマートフォン等の物理的デバイスを使う認証。SMSはスマートフォン（所有物）を利用。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 98, "q": "クラウドサービスの提供形態のうち，利用者がOSやミドルウェアも自由に選択できる形態はどれか。", "opts": ["SaaS", "PaaS", "DaaS", "IaaS"], "ans": 3, "exp": "IaaS（Infrastructure as a Service）はハードウェアリソースを提供しOSも利用者が選択できる。SaaSはアプリ，PaaSは開発環境を提供。", "cat": "テクノロジ", "diff": "easy", "year": 2025}, {"id": 99, "q": "入力フォームに悪意あるSQL文を埋め込んでデータベースを不正操作する攻撃はどれか。", "opts": ["ブルートフォース攻撃", "SQLインジェクション", "クロスサイトスクリプティング", "ディレクトリトラバーサル"], "ans": 1, "exp": "SQLインジェクションはWebアプリの入力欄にSQL命令を挿入してDBを不正操作する攻撃。対策はプリペアドステートメント。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 100, "q": "サーバの一部に障害が発生しても，残りのサーバでサービスを継続できるシステム設計はどれか。", "opts": ["フェールソフト", "フールプルーフ", "フェールセーフ", "フォールトトレランス"], "ans": 3, "exp": "フォールトトレランスは一部の障害があってもシステム全体が動作し続けるよう冗長化・縮退運転する設計。", "cat": "テクノロジ", "diff": "mid", "year": 2025}, {"id": 101, "q": "DX（デジタルトランスフォーメーション）の説明として最も適切なものはどれか。", "opts": ["クラウドサービスへの移行のみ", "ペーパーレス化を推進すること", "既存業務システムのバージョンアップ", "デジタル技術を活用して業務プロセスや組織文化を抜本的に変革し価値を生み出すこと"], "ans": 3, "exp": "DXは単なるデジタル化ではなく，デジタル技術で事業・組織・文化を変革し競争優位を確立するプロセス。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 102, "q": "Society 5.0の説明として最も適切なものはどれか。", "opts": ["第4次産業革命以前の農業・工業社会", "インターネットが普及した情報社会", "AIが人間を超えるシンギュラリティ到来後の社会", "サイバー空間と現実空間を融合し人間中心の新たな社会"], "ans": 3, "exp": "Society 5.0は狩猟・農耕・工業・情報に続く第5の社会形態。IoT/AI/ビッグデータを活用した人間中心の超スマート社会。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 103, "q": "SDGsの目標数として正しいものはどれか。", "opts": ["17", "10", "20", "15"], "ans": 0, "exp": "SDGs（持続可能な開発目標）は2015年に国連が採択した17の目標・169のターゲットからなる国際目標。2030年までの達成を目指す。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 104, "q": "ESG投資の説明として最も適切なものはどれか。", "opts": ["短期的な財務指標のみで投資先を選定する手法", "個人投資家向けの少額分散投資", "環境・社会・ガバナンスの非財務情報も考慮した投資手法", "新興国市場への集中投資戦略"], "ans": 2, "exp": "ESG投資はEnvironment（環境），Social（社会），Governance（ガバナンス）を評価軸に加えた長期視点の投資手法。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 105, "q": "廃棄物を出さずに資源を循環させるビジネスモデルを表す用語はどれか。", "opts": ["リニアエコノミー", "プラットフォームエコノミー", "サーキュラーエコノミー", "シェアリングエコノミー"], "ans": 2, "exp": "サーキュラーエコノミー（循環型経済）は製品・材料・資源を循環させ廃棄物ゼロを目指す経済モデル。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 106, "q": "STP分析のうち「T」が表すものはどれか。", "opts": ["Technology（技術力）", "Targeting（ターゲット市場の選択）", "Threat（脅威）", "Trading（取引手法）"], "ans": 1, "exp": "STPはSegmentation（市場細分化）・Targeting（標的市場選択）・Positioning（位置付け）の3ステップのマーケティング戦略。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 107, "q": "顧客が製品・サービスを認知してから購入・利用に至るまでの行動と感情を可視化する手法はどれか。", "opts": ["カスタマージャーニーマップ", "バリューチェーン分析", "SWOT分析", "ビジネスモデルキャンバス"], "ans": 0, "exp": "カスタマージャーニーマップは顧客の体験（認知→検討→購入→継続利用）をステップごとに可視化するマーケティング手法。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 108, "q": "顧客が生涯を通じて企業にもたらす価値の総計を表す指標はどれか。", "opts": ["LTV", "ROI", "CAC", "NPS"], "ans": 0, "exp": "LTV（Life Time Value：顧客生涯価値）は1顧客が取引期間全体で生み出す利益の合計。顧客維持戦略の重要指標。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 109, "q": "実店舗・ECサイト・モバイルなど全チャネルで一貫した購買体験を提供する戦略はどれか。", "opts": ["クロスチャネル", "オムニチャネル", "シングルチャネル", "マルチチャネル"], "ans": 1, "exp": "オムニチャネルはあらゆる販売チャネルを統合し顧客にシームレスな購買体験を提供する戦略。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 110, "q": "製造業者が中間業者を介さず消費者へ直接販売するビジネスモデルはどれか。", "opts": ["フランチャイズ", "OEM", "ODM", "D2C"], "ans": 3, "exp": "D2C（Direct to Consumer）はメーカーがECサイト等で消費者に直接販売するモデル。マージン削減と顧客データ取得が利点。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 111, "q": "BSC（バランススコアカード）の4視点として正しいものはどれか。", "opts": ["コスト・品質・納期・柔軟性", "強み・弱み・機会・脅威", "財務・顧客・内部プロセス・学習と成長", "計画・実行・評価・改善"], "ans": 2, "exp": "BSCはKaplan&Nortonが提唱。財務・顧客・内部プロセス・学習と成長の4視点でKPIを設定しバランスよく経営を管理。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 112, "q": "KGIとKPIの関係として最も適切な記述はどれか。", "opts": ["KGIとKPIは同じ意味で使われる", "KPIは財務指標のみを指す", "KPIは最終目標，KGIは中間指標", "KGIは最終目標，KPIはそれを達成するための中間指標"], "ans": 3, "exp": "KGI（重要目標達成指標）は最終的な達成目標，KPI（重要業績評価指標）はKGI達成に向けた中間プロセス指標。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 113, "q": "Googleが提唱した目標管理フレームワークで，野心的な目標と測定可能な主要結果を設定するものはどれか。", "opts": ["MBO", "OKR", "BSC", "KPI"], "ans": 1, "exp": "OKR（Objectives and Key Results）はIntelやGoogleが活用した目標管理法。挑戦的なObjectiveと具体的なKey Resultsを四半期ごとに設定。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 114, "q": "アンゾフの成長マトリクスで，既存製品を新市場に展開する戦略はどれか。", "opts": ["市場浸透", "多角化", "製品開発", "市場開拓"], "ans": 3, "exp": "アンゾフの成長マトリクスは製品×市場の2軸。既存製品×新市場＝市場開拓戦略（新地域・新顧客層への展開）。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 115, "q": "BCGのPPMで，市場成長率が高くシェアも高い製品カテゴリはどれか。", "opts": ["花形", "問題児", "負け犬", "金のなる木"], "ans": 0, "exp": "花形（Star）は高成長・高シェア。投資継続で将来「金のなる木」になる可能性がある。金のなる木は低成長・高シェア。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 116, "q": "企業買収・合併によって２社以上の組み合わせで得られる相乗効果を表す用語はどれか。", "opts": ["シナジー効果", "アウトソーシング", "アライアンス", "スピンオフ"], "ans": 0, "exp": "シナジー効果はM&A等で結合した組織が単独の合計以上の成果を生み出す効果（1+1>2）。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 117, "q": "スタートアップ企業に資金と経営支援を提供し，株式を取得して利益を目指す投資家や機関はどれか。", "opts": ["ベンチャーキャピタル", "証券会社", "エンジェル投資家", "銀行"], "ans": 0, "exp": "VC（Venture Capital）は未上場スタートアップに出資し，IPO等のエグジット時のキャピタルゲインを目的とする投資機関。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 118, "q": "未上場企業が証券取引所への上場手続きを経て株式を公開する行為はどれか。", "opts": ["LBO", "IPO", "MBO", "TOB"], "ans": 1, "exp": "IPO（Initial Public Offering：新規株式公開）は未上場企業が株式市場に初めて株式を公開すること。資金調達・知名度向上が目的。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 119, "q": "インターネットを通じて不特定多数から資金を調達する仕組みはどれか。", "opts": ["リースバック", "ファクタリング", "クラウドファンディング", "私募債"], "ans": 2, "exp": "クラウドファンディングは資金需要者がWebで不特定多数の支援者に直接訴え，小口の資金を集める新しい金融モデル。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 120, "q": "特許権の存続期間として正しいものはどれか（出願日を起点とする）。", "opts": ["20年", "存続期間はない", "10年", "25年"], "ans": 0, "exp": "特許権の存続期間は出願日から20年（特許法第67条）。実用新案は10年，著作権は著作者の死後70年。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 121, "q": "不正競争防止法が保護する「営業秘密」の3要件として正しいものはどれか。", "opts": ["秘匿性・独自性・商業性", "登録性・独占性・有用性", "秘密管理性・有用性・非公知性", "公知性・有用性・独自性"], "ans": 2, "exp": "営業秘密の3要件：①秘密管理性（管理されている）②有用性（ビジネスで有用）③非公知性（一般に知られていない）。", "cat": "ストラテジ", "diff": "hard", "year": 2024}, {"id": 122, "q": "AIが個人の信用スコアを算出する際に注意すべき倫理的課題として最も適切なものはどれか。", "opts": ["モデルが複雑すぎる", "学習データに偏りがあると特定属性に不公平な判定が生じる", "計算コストが高い", "クラウド費用が増大する"], "ans": 1, "exp": "AIバイアス問題。偏った学習データは性別・人種等の属性で不公正な判定を生む。AIの公平性・説明可能性が重要。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 123, "q": "データに基づいて意思決定・戦略立案を行う経営手法はどれか。", "opts": ["データドリブン経営", "勘と経験に基づく経営", "トップダウン経営", "コンセンサス経営"], "ans": 0, "exp": "データドリブン経営はデータを収集・分析し，その結果を根拠として意思決定を行う経営アプローチ。BI・AIの活用が前提。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 124, "q": "物理空間のデータをリアルタイムにデジタル空間に再現し，シミュレーションや予測に活用する技術はどれか。", "opts": ["デジタルツイン", "デジタルサイネージ", "仮想現実", "サイバーフィジカルシステム"], "ans": 0, "exp": "デジタルツインは現実世界の設備・都市等を仮想空間に精密に再現し，シミュレーションや障害予測に活用する技術。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 125, "q": "インターネット上に構築された3次元の仮想空間で，アバターを通じて活動する空間を表す用語はどれか。", "opts": ["メタバース", "AR（拡張現実）", "クラウドコンピューティング", "スマートシティ"], "ans": 0, "exp": "メタバースはインターネット上の3次元仮想空間。アバターで他者と交流・経済活動を行う新しいデジタル空間。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 126, "q": "特定の管理者を持たず，スマートコントラクトで自律的に運営される組織形態はどれか。", "opts": ["株式会社", "DAO", "有限責任事業組合", "NPO法人"], "ans": 1, "exp": "DAO（Decentralized Autonomous Organization：分散型自律組織）はブロックチェーン上のスマートコントラクトで運営される中央管理者不在の組織。", "cat": "ストラテジ", "diff": "hard", "year": 2024}, {"id": 127, "q": "投資額100万円で得られた利益が25万円のとき，ROI（投資利益率）はどれか。", "opts": ["25%", "4%", "125%", "20%"], "ans": 0, "exp": "ROI = 利益÷投資額×100 = 25÷100×100 = 25%。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 128, "q": "企業の一定期間の収益と費用を対応させて利益を表す財務諸表はどれか。", "opts": ["キャッシュフロー計算書", "損益計算書", "株主資本等変動計算書", "貸借対照表"], "ans": 1, "exp": "損益計算書（P/L）は一定期間の収益・費用・利益を示す。貸借対照表（B/S）は一時点の資産・負債・純資産を示す。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 129, "q": "売上高に占める各製品の貢献度を分析し，上位20%の製品が全体の80%の売上を占めるという法則はどれか。", "opts": ["ロングテール", "パレートの法則", "80:20理論", "ABC分析"], "ans": 1, "exp": "パレートの法則（80:20の法則）はイタリアの経済学者パレートが発見。上位20%の要素が全体の80%の成果をもたらす傾向。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 130, "q": "業界内の競争に影響する5つの力を分析するフレームワークはどれか。", "opts": ["マイケル・ポーターの5フォース分析", "3C分析", "PEST分析", "SWOT分析"], "ans": 0, "exp": "5フォース分析は新規参入・代替品・買手交渉力・売手交渉力・既存競合の5要因で業界の収益性を分析するフレームワーク。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 131, "q": "社会・経済・政治・技術の外部環境要因を分析するフレームワークはどれか。", "opts": ["3C分析", "5フォース分析", "SWOT分析", "PEST分析"], "ans": 3, "exp": "PEST分析はPolitical（政治），Economic（経済），Social（社会），Technological（技術）の4視点で外部環境を分析する手法。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 132, "q": "製品が市場に登場してから衰退するまでのサイクルを表すモデルはどれか。", "opts": ["アンゾフの成長マトリクス", "PPM", "BCGマトリクス", "製品ライフサイクル"], "ans": 3, "exp": "製品ライフサイクルは導入期→成長期→成熟期→衰退期の4段階。各ステージで最適なマーケティング戦略が異なる。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 133, "q": "企業の社会的責任として，利益追求だけでなく環境保護・地域貢献等の活動を積極的に行う概念はどれか。", "opts": ["ガバナンス", "コアコンピタンス", "CSR", "コンプライアンス"], "ans": 2, "exp": "CSR（Corporate Social Responsibility：企業の社会的責任）は利益創出と同時に環境・社会・人権等への貢献を果たす経営姿勢。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 134, "q": "自社が他社に比べて優位性を持ち競争の源泉となる能力や技術をどれか。", "opts": ["バリューチェーン", "コアビジネス", "コアコンピタンス", "オープンイノベーション"], "ans": 2, "exp": "コアコンピタンスはハメル&プラハラードが提唱。顧客価値創造・競合困難・多市場展開の3条件を満たす企業の中核能力。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 135, "q": "外部の知識・技術・アイデアを積極的に取り込み，自社イノベーションに活用する戦略はどれか。", "opts": ["コアコンピタンス経営", "水平展開", "垂直統合", "オープンイノベーション"], "ans": 3, "exp": "オープンイノベーションはH.チェスブロウが提唱。社外の技術・知見を積極活用してイノベーション速度を高める戦略。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 136, "q": "ITサービスマネジメントにおいてサービスデスクのうち，複数拠点を1か所で集中的に対応する形態はどれか。", "opts": ["フォロー・ザ・サン", "バーチャルサービスデスク", "セントラルサービスデスク", "ローカルサービスデスク"], "ans": 2, "exp": "セントラルサービスデスクは複数拠点のユーザーからの問合せを1拠点で集約・対応する形態。コスト効率が高い。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 137, "q": "サービスデスクで解決できない問い合わせを上位の専門部門に引き継ぐ対応を何というか。", "opts": ["フォワーディング", "ルーティング", "エスカレーション", "チケッティング"], "ans": 2, "exp": "エスカレーションは一次対応で解決できない問題を上位者・専門部門に引き継ぐ。機能的エスカレーションと階層的エスカレーションがある。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 138, "q": "BCPにおけるRTOの説明として最も適切なものはどれか。", "opts": ["バックアップデータの最大許容損失時間", "システム全体の年間稼働率", "ディザスタリカバリの総コスト", "障害発生から業務再開までの目標時間"], "ans": 3, "exp": "RTO（Recovery Time Objective：目標復旧時間）は障害発生からシステム・業務を復旧させるまでの目標時間。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 139, "q": "BCPにおけるRPOの説明として最も適切なものはどれか。", "opts": ["障害発生から業務再開までの目標時間", "リカバリに必要なコスト", "システムの最大許容停止時間", "バックアップを取得すべき最大許容損失データの時間的範囲"], "ans": 3, "exp": "RPO（Recovery Point Objective：目標復旧時点）は障害時にどの時点までのデータ損失を許容するかの目標。バックアップ頻度の基準。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 140, "q": "スクラム開発でチームが1〜4週間の反復サイクルで開発を行う単位を何というか。", "opts": ["イテレーション", "スプリント", "ベロシティ", "インクリメント"], "ans": 1, "exp": "スクラムのスプリントは1〜4週間の固定タイムボックス。各スプリント終了時にリリース可能な成果物を作成する。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 141, "q": "スクラムにおいて，プロダクトの要求事項を優先順位付きで管理するリストはどれか。", "opts": ["ベロシティ", "スプリントバックログ", "バーンダウンチャート", "プロダクトバックログ"], "ans": 3, "exp": "プロダクトバックログはプロダクトオーナーが管理するユーザーストーリーの優先順位リスト。スプリントの入力ソース。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 142, "q": "チームが完了した作業量（ポイント数）をスプリントごとに可視化し，残作業の推移を示すグラフはどれか。", "opts": ["バーンダウンチャート", "フローチャート", "ガントチャート", "アクティビティ図"], "ans": 0, "exp": "バーンダウンチャートはスプリント期間内に残タスクが減少していく様子を可視化。理想線と実績の乖離で進捗を把握。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 143, "q": "プロジェクトの利害関係者を特定し，影響力と関心度に応じて管理戦略を立てる活動はどれか。", "opts": ["スコープ管理", "品質管理", "リスク管理", "ステークホルダーマネジメント"], "ans": 3, "exp": "ステークホルダーマネジメントは関係者を特定・分析し，コミュニケーション計画を立てて適切に関与させる活動。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 144, "q": "プロジェクトリスクの「影響度×発生確率」で優先度を評価する手法はどれか。", "opts": ["リスク回避", "定量的リスク分析", "定性的リスク分析", "リスク移転"], "ans": 2, "exp": "定性的リスク分析は発生確率と影響度を組み合わせてリスクの優先度を評価（高/中/低）。定量的分析は数値化（金額等）で評価。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 145, "q": "プロジェクトで実施する作業を階層的に分解し，管理可能な単位に整理した構造はどれか。", "opts": ["ネットワーク図", "WBS", "組織図", "ガントチャート"], "ans": 1, "exp": "WBS（Work Breakdown Structure：作業分解構造）はプロジェクトの全作業を階層的に分解し，成果物ベースで管理単位を明確化する。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 146, "q": "システム開発の最終工程において利用者が実際の業務に即して行うテストはどれか。", "opts": ["統合テスト", "システムテスト", "受入テスト", "単体テスト"], "ans": 2, "exp": "受入テスト（UAT）はシステムを引き渡す前にユーザーが業務要件を満たすか最終確認するテスト。発注者の承認が目的。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 147, "q": "ウォークスルーの説明として最も適切なものはどれか。", "opts": ["専門のモデレータが進行するフォーマルな欠陥発見レビュー", "ユーザーが操作を実際に確認するテスト", "コードを自動テストツールで検証する手法", "作成者が他のメンバーに成果物を説明しながらレビューを受けるレビュー手法"], "ans": 3, "exp": "ウォークスルーは成果物の作成者が主導し，関係者に内容を説明しながら誤りや問題点を発見するインフォーマルレビュー手法。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 148, "q": "ITサービスマネジメントにおいて，ビジネスの継続性を確保するための計画・管理活動はどれか。", "opts": ["SLM", "ITサービス継続性管理", "問題管理", "インシデント管理"], "ans": 1, "exp": "ITサービス継続性管理はITILで定義。災害等でITサービスが停止した場合に合意したレベルで復旧できるよう計画・管理する活動。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 149, "q": "監査人が依頼者から独立した第三者の立場で行う監査を何というか。", "opts": ["外部監査", "内部監査", "情報システム監査", "自己評価"], "ans": 0, "exp": "外部監査は企業外部の独立した第三者（公認会計士等）が実施。内部監査は企業内部の独立した部門が実施。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 150, "q": "ITへの投資効果を定量的に評価する手法として，投資によるコスト削減額や利益向上額を算出して判断するものはどれか。", "opts": ["IRR法", "ROI計算", "TCO分析", "NPV法"], "ans": 1, "exp": "ITシステムへのROI（投資対効果）評価は，投資額に対してコスト削減・売上向上等の効果を比較して費用対効果を測定。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 151, "q": "システム開発において，アーキテクチャの基本設計を行い，コンポーネント間のインタフェースを定義する工程はどれか。", "opts": ["実装", "概要設計（外部設計）", "詳細設計（内部設計）", "要件定義"], "ans": 1, "exp": "概要設計（外部設計）はシステム全体のアーキテクチャ，コンポーネント構成，インタフェース，画面・帳票設計を行う工程。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 152, "q": "ソフトウェアの品質特性として「機能が正確に動作する度合い」を表す品質副特性はどれか。", "opts": ["信頼性", "機能適合性", "性能効率性", "保守性"], "ans": 1, "exp": "ISO/IEC 25010の機能適合性は，機能正確性（指定された精度での結果提供）を含む品質特性。", "cat": "マネジメント", "diff": "hard", "year": 2024}, {"id": 153, "q": "アジャイル開発の原則を示したアジャイルソフトウェア開発宣言で重視されているものはどれか。", "opts": ["プロセスとツール > 個人と対話", "計画に従うこと > 変化への対応", "包括的なドキュメント > 動くソフトウェア", "契約交渉 > 顧客との協調"], "ans": 1, "exp": "アジャイル宣言は「個人と対話」「動くソフトウェア」「顧客との協調」「変化への対応」を右辺より重視。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 154, "q": "完成済みのプログラムを本番環境に組み込む前に行う，新旧システムの並行稼働とはどれか。", "opts": ["一斉移行", "段階移行", "パイロット移行", "並行稼働"], "ans": 3, "exp": "並行稼働は新旧システムを同時稼働させ結果を比較しながら移行する方式。安全だがコストが高い。", "cat": "マネジメント", "diff": "easy", "year": 2024}, {"id": 155, "q": "情報システム監査において，リスクアプローチに基づく監査では何を優先するか。", "opts": ["リスクが高い領域に重点的に監査資源を投入する", "過去の監査結果がない領域は除外する", "全システムを同じ深度で監査する", "管理者の指示に従って領域を選定する"], "ans": 0, "exp": "リスクアプローチは重大な損害を生む可能性が高いリスク領域に監査資源を重点投入し，効率的に監査を行う手法。", "cat": "マネジメント", "diff": "hard", "year": 2024}, {"id": 156, "q": "OSI参照モデルで，ルータが動作する層はどれか。", "opts": ["ネットワーク層", "アプリケーション層", "データリンク層", "トランスポート層"], "ans": 0, "exp": "ルータはネットワーク層（第3層）でIPアドレスをもとにルーティングを行う機器。スイッチはデータリンク層（第2層）。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 157, "q": "TCPとUDPの違いとして正しいものはどれか。", "opts": ["UDPは再送制御をする", "TCPは信頼性が高く，UDPは高速・低信頼性", "TCPは非接続型，UDPは接続型", "TCPはリアルタイム通信に適している"], "ans": 1, "exp": "TCP（Transmission Control Protocol）は接続確立・順序制御・再送で信頼性確保。UDPは軽量で高速だが信頼性なし。動画・音声はUDP。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 158, "q": "HTTPSで使われるポート番号はどれか。", "opts": ["443", "25", "21", "80"], "ans": 0, "exp": "ポート番号：FTP=21，SSH=22，SMTP=25，DNS=53，HTTP=80，POP3=110，HTTPS=443。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 159, "q": "192.168.1.0/24のネットワークで利用可能なホストアドレス数はどれか。", "opts": ["512", "255", "254", "256"], "ans": 2, "exp": "/24はサブネットマスク255.255.255.0。256アドレスのうちネットワークアドレスとブロードキャストアドレスの2つを除いた254台が利用可能。", "cat": "テクノロジ", "diff": "hard", "year": 2024}, {"id": 160, "q": "IPv4の問題を解決し128ビットのアドレス空間を持つIPのバージョンはどれか。", "opts": ["IPv8", "IPv6", "IPng", "IPv5"], "ans": 1, "exp": "IPv6は128ビットのアドレス空間（約340澗個）を持ち，IPv4のアドレス枯渇・NATの複雑さを解決。16進数で表記。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 161, "q": "拠点間やリモートアクセスで安全な通信路を確立するプロトコルとして適切なものはどれか。", "opts": ["TELNET", "VPN（IPsec）", "FTP", "HTTP"], "ans": 1, "exp": "VPN（Virtual Private Network）はインターネット上に暗号化された仮想専用線を構築。IPsecやSSL/TLSを使用。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 162, "q": "クラウドサービスのうち，OSやミドルウェアを含む開発環境をサービスとして提供するものはどれか。", "opts": ["IaaS", "PaaS", "SaaS", "BaaS"], "ans": 1, "exp": "PaaS（Platform as a Service）はアプリケーション開発環境（OS・ミドルウェア・DB等）をクラウドで提供。開発者はアプリ開発に集中できる。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 163, "q": "複数のクラウドプロバイダのサービスを組み合わせて利用する形態はどれか。", "opts": ["マルチクラウド", "コミュニティクラウド", "プライベートクラウド", "ハイブリッドクラウド"], "ans": 0, "exp": "マルチクラウドは複数の異なるクラウドプロバイダのサービスを組み合わせて利用する戦略。ベンダーロックイン回避が主な目的。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 164, "q": "アプリケーションとその依存関係を軽量な実行環境にパッケージ化して移植性を高める技術はどれか。", "opts": ["仮想マシン（VM）", "コンテナ", "マイクロサービス", "ハイパーバイザ"], "ans": 1, "exp": "コンテナ（Dockerなど）はOSカーネルを共有しプロセスレベルで隔離。VMより軽量で起動が速く，環境差異をなくせる。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 165, "q": "内部ネットワークと外部ネットワークの境界に設置し，パケットのヘッダ情報で通信を制御する機器はどれか。", "opts": ["ファイアウォール", "ルータ", "プロキシサーバ", "ロードバランサ"], "ans": 0, "exp": "ファイアウォールはパケットフィルタリング・ステートフルインスペクション等で不正通信を遮断しネットワークを保護する。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 166, "q": "WebサーバをHTTPレベルの攻撃（XSS・SQLインジェクション等）から保護するセキュリティ機器はどれか。", "opts": ["IDS", "UTM", "WAF", "IPS"], "ans": 2, "exp": "WAF（Web Application Firewall）はHTTPレベルでWebアプリへの攻撃を検知・遮断。通常のFWでは防げないアプリ層攻撃に対応。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 167, "q": "Webページを閲覧したとき，攻撃者が埋め込んだスクリプトが利用者のブラウザで実行される攻撃はどれか。", "opts": ["ディレクトリトラバーサル", "SQLインジェクション", "クロスサイトスクリプティング（XSS）", "クロスサイトリクエストフォージェリ（CSRF）"], "ans": 2, "exp": "XSSはWebアプリの出力処理の不備を突き，攻撃者のスクリプトを被害者のブラウザで実行させる攻撃。Cookie盗取等の被害。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 168, "q": "ログイン中のユーザーの権限で攻撃者が意図したHTTPリクエストを送信させる攻撃はどれか。", "opts": ["SQLインジェクション", "XSS", "ブルートフォース", "CSRF"], "ans": 3, "exp": "CSRF（クロスサイトリクエストフォージェリ）は被害者が意図せずリクエストを送信させられる攻撃。Tokenによるセッション検証が対策。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 169, "q": "標的型攻撃メールで特定の組織・個人を狙った高度なフィッシングを何というか。", "opts": ["スミッシング", "ボイスフィッシング", "スピアフィッシング", "ファーミング"], "ans": 2, "exp": "スピアフィッシングは特定の標的を絞り込み，個人情報を調査した上で信頼度の高い偽メール等で騙す高度な攻撃。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 170, "q": "データベースの第1正規形の条件として正しいものはどれか。", "opts": ["主キー以外の属性が全て主キーに従属している", "推移的関数従属が除去されている", "全ての属性がアトミック（繰り返し項目なし）である", "外部キーが全て参照整合性を持つ"], "ans": 2, "exp": "第1正規形（1NF）は全属性がアトミック（1セルに1値）で繰り返しグループがない状態。第2NF→主キー全体に従属。第3NF→推移的依存を除去。", "cat": "テクノロジ", "diff": "hard", "year": 2024}, {"id": 171, "q": "関係データベースで，エンティティ間の関係を表す設計図はどれか。", "opts": ["フローチャート", "DFD", "ER図", "クラス図"], "ans": 2, "exp": "ER図（Entity-Relationship Diagram）はエンティティとその関係（1:1，1:N，M:N）を表すデータモデリング手法。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 172, "q": "トランザクションのACID特性のうち「C」が表す性質はどれか。", "opts": ["Commitment（確定性）", "Continuity（継続性）", "Concurrency（並行性）", "Consistency（一貫性）"], "ans": 3, "exp": "ACID特性：Atomicity（原子性），Consistency（一貫性），Isolation（独立性），Durability（永続性）。整合性制約が保たれる性質。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 173, "q": "複数トランザクションが互いのロックを待ち合い，処理が進まなくなる状態はどれか。", "opts": ["デッドロック", "スラッシング", "バッファオーバーフロー", "スワッピング"], "ans": 0, "exp": "デッドロックはトランザクションAがリソース1を，BがリソースR2をロックし，互いに相手のリソースを待つ状態。タイムアウト・ロック順序固定で防止。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 174, "q": "ビッグデータの非構造化データ（SNS投稿・ログ等）の管理に適したDBMSはどれか。", "opts": ["階層型データベース", "NoSQL", "関係データベース（RDBMS）", "ネットワーク型データベース"], "ans": 1, "exp": "NoSQLはキー・バリュー型，ドキュメント型等があり，スキーマレスで大量の非構造化データを高速処理するのに適している。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 175, "q": "機械学習のうち，教師なし学習で似たデータをグループに分類する手法はどれか。", "opts": ["サポートベクターマシン", "クラスタリング", "決定木", "回帰分析"], "ans": 1, "exp": "クラスタリング（k-means等）は正解ラベルなしでデータを類似性に基づきグループ分けする教師なし学習手法。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 176, "q": "学習データに過度に適合し，未知データへの汎化性能が低下する機械学習の問題を何というか。", "opts": ["オーバーフィッティング（過学習）", "アンダーフィッティング", "バギング", "ブースティング"], "ans": 0, "exp": "過学習（オーバーフィッティング）は訓練データに特化しすぎて未知データに対して誤差が大きくなる問題。正則化・交差検証で対策。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 177, "q": "条件分岐の繰り返しでデータを分類する木構造の機械学習モデルはどれか。", "opts": ["SVM", "ニューラルネットワーク", "決定木", "ランダムフォレスト"], "ans": 2, "exp": "決定木はYes/Noの質問を繰り返しデータを分類する木構造モデル。説明可能性が高く，直感的に理解しやすい。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 178, "q": "1組のデータの平均値・中央値・最頻値の中で，極端な外れ値の影響を最も受けにくいものはどれか。", "opts": ["平均値", "最頻値", "中央値", "どれも同じ"], "ans": 2, "exp": "中央値（メジアン）はデータを並べた中央の値。外れ値の影響を受けにくい。平均値は外れ値に影響される。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 179, "q": "データの散らばり具合を表す統計量で，各データと平均値の差の二乗の平均値はどれか。", "opts": ["標準偏差", "分散", "範囲", "偏差値"], "ans": 1, "exp": "分散 = Σ(xi-平均)²/n。標準偏差は分散の正の平方根で，元のデータと同じ単位になるため解釈しやすい。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 180, "q": "自然界の多くの現象が従う左右対称の釣り鐘型の確率分布はどれか。", "opts": ["二項分布", "ポアソン分布", "一様分布", "正規分布"], "ans": 3, "exp": "正規分布はガウス分布とも呼ばれ，平均を中心に左右対称の釣り鐘型。中心極限定理により広く自然現象に現れる。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 181, "q": "2進数の11010011を16進数に変換したものはどれか。", "opts": ["C3", "D3", "E3", "B3"], "ans": 1, "exp": "1101=D，0011=3。よって16進数D3。4ビットずつ区切り：1101=13=D，0011=3=3→D3。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 182, "q": "MIPS（Million Instructions Per Second）は何を表す単位か。", "opts": ["1秒あたり100万命令の処理速度", "メモリ容量", "CPU周波数", "1秒あたりのデータ転送量"], "ans": 0, "exp": "MIPSは毎秒何百万命令を処理できるかを表すCPU性能指標。100MIPS = 毎秒1億命令処理。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 183, "q": "CPUと主記憶の速度差を補い，最近使ったデータを一時保存する高速な記憶装置はどれか。", "opts": ["キャッシュメモリ", "二次記憶", "仮想記憶", "バッファ"], "ans": 0, "exp": "キャッシュメモリはCPUと主記憶の間に置かれる高速小容量メモリ。局所参照性を利用してアクセス速度を向上させる。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 184, "q": "1台の物理サーバ上に複数の仮想的なサーバを作成し，効率的にリソースを活用する技術はどれか。", "opts": ["フォールトトレランス", "仮想化技術", "クラスタリング", "RAID"], "ans": 1, "exp": "仮想化技術（VMware, HyperV等）は1台の物理サーバにハイパーバイザを置き，複数のVMを実行しリソースを効率活用。", "cat": "テクノロジ", "diff": "easy", "year": 2024}, {"id": 185, "q": "UMLのうち，システムの動的な振る舞いとしてオブジェクト間のメッセージのやり取りを時系列で示す図はどれか。", "opts": ["シーケンス図", "クラス図", "コンポーネント図", "ユースケース図"], "ans": 0, "exp": "シーケンス図はオブジェクト間の相互作用を時系列（縦軸）で示すUMLの振る舞い図。処理の流れやメッセージ順序が分かる。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 186, "q": "WebサービスのAPIでHTTPメソッドを利用し，リソースをURIで表現する設計スタイルはどれか。", "opts": ["SOAP", "GraphQL", "RESTful API", "RPC"], "ans": 2, "exp": "RESTful APIはREST原則（ステートレス・URIでリソース識別・HTTPメソッド活用）に基づくWeb APIの設計スタイル。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 187, "q": "DXに関して，企業が既存ITシステムの複雑化・老朽化により対応が困難になる問題を何というか。", "opts": ["技術的負債", "デジタルデバイド", "レガシーマイグレーション", "2025年の崖"], "ans": 3, "exp": "「2025年の崖」はIPA提唱の概念。2025年頃にレガシーシステムの保守限界到来→DX推進・維持コストで年間最大12兆円の損失リスク。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 188, "q": "テレワークで自宅からオフィスネットワークに安全に接続するためのコア技術はどれか。", "opts": ["ビデオ会議", "VPN", "SNS", "クラウドストレージ"], "ans": 1, "exp": "VPN（仮想専用線）はインターネット上に暗号化された安全なトンネルを構築し，遠隔地からのオフィスLANへの安全接続を実現。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 189, "q": "スマートシティの説明として最も適切なものはどれか。", "opts": ["IT・データを活用して都市の課題解決と生活の質向上を目指す都市", "高層ビルが集中した都市計画", "工業団地を中心とした産業集積都市", "再開発によって整備された新興住宅地"], "ans": 0, "exp": "スマートシティはIoT・AI・データ分析を活用して交通・エネルギー・防災等を最適化し，市民の生活の質を向上させる都市概念。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 190, "q": "企業がCO2排出量を実質ゼロにするために，排出量を削減しきれない分を他社・団体の吸収量で相殺する仕組みはどれか。", "opts": ["グリーンウォッシュ", "カーボンニュートラル", "カーボンプライシング", "カーボンオフセット"], "ans": 3, "exp": "カーボンオフセットは自社で削減しきれないCO2を，植林・再エネ等の他のプロジェクトが削減・吸収したクレジットで相殺する仕組み。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 191, "q": "ITシステムの省エネ化や廃熱利用でIT機器の環境負荷を低減する取り組みはどれか。", "opts": ["ESG", "グリーンウォッシュ", "グリーンIT", "GX"], "ans": 2, "exp": "グリーンITはIT機器の消費電力削減・廃熱利用・資源効率化を通じてICT分野の環境負荷を低減する取り組み。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 192, "q": "消費者の行動・購買動向を調査して傾向を分析し，マーケティング戦略立案に活用することを何というか。", "opts": ["デジタルマーケティング", "ブランドマネジメント", "PR（パブリックリレーションズ）", "マーケティングリサーチ"], "ans": 3, "exp": "マーケティングリサーチは消費者の行動・ニーズ・動向を体系的に調査・分析し，意思決定に活用する活動。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 193, "q": "SNSで顧客が商品・サービスを自発的に紹介することで口コミ効果を生む低コストのマーケティング手法はどれか。", "opts": ["デジタルサイネージ", "テレビCM", "バイラルマーケティング", "ダイレクトメール"], "ans": 2, "exp": "バイラルマーケティングはSNSや口コミで消費者が自発的に情報を拡散するウイルス的な普及を狙うマーケティング手法。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 194, "q": "顧客獲得コストを示すマーケティング指標CACとして正しい計算式はどれか。", "opts": ["CAC = リピート率×売上", "CAC = 利益÷顧客数", "CAC = 獲得コスト合計÷新規顧客数", "CAC = 売上÷顧客数"], "ans": 2, "exp": "CAC（Customer Acquisition Cost）は新規顧客1人を獲得するためにかかったマーケティング・営業コストの平均額。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 195, "q": "製品のコンセプト検証から量産化まで迅速に行うため，試作品を繰り返し改善するアプローチはどれか。", "opts": ["ウォーターフォール", "シックスシグマ", "リーンスタートアップ", "カイゼン"], "ans": 2, "exp": "リーンスタートアップはMVP（最小機能製品）を素早くリリースし，ユーザーフィードバックを元にBuild-Measure-Learnサイクルを回す手法。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 196, "q": "AIが生成したコンテンツが人間の著作物と判別困難になった際の著作権帰属問題のうち，AI生成物の著作権者は原則誰か（日本の現行解釈）。", "opts": ["著作権は発生しない", "AIを開発した企業", "AIを利用したユーザー", "政府"], "ans": 0, "exp": "日本の現行著作権法ではAIが自律的に生成したコンテンツには著作権が発生しないとされる（人間の創作性が要件）。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 197, "q": "個人情報の第三者提供時に取得する同意において，提供前に本人の同意を得る方式はどれか。", "opts": ["パーミッションマーケティング", "情報銀行", "オプトアウト", "オプトイン"], "ans": 3, "exp": "オプトインは利用・提供前に事前同意を取得する方式。オプトアウトは提供後に拒否できる方式。個人情報保護法は原則オプトイン。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 198, "q": "顧客との長期的な関係を管理し，顧客満足と収益を最大化するシステムはどれか。", "opts": ["SFA", "ERP", "CRM", "SCM"], "ans": 2, "exp": "CRM（Customer Relationship Management）は顧客情報を一元管理し，ニーズに応じた対応で顧客満足・LTV向上を目指すシステム。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 199, "q": "営業活動を可視化・自動化して商談管理・進捗追跡を支援するシステムはどれか。", "opts": ["ERP", "SCM", "SFA", "CRM"], "ans": 2, "exp": "SFA（Sales Force Automation）は営業活動（商談・訪問・提案等）を支援・自動化し，営業の生産性向上と案件管理を行うシステム。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 200, "q": "原材料調達から製造・流通・小売りまでの供給連鎖全体を効率化するシステムはどれか。", "opts": ["SCM", "CRM", "SFA", "ERP"], "ans": 0, "exp": "SCM（Supply Chain Management）は原材料調達から最終消費者への供給チェーン全体をリアルタイムに把握・最適化するシステム。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 201, "q": "グローバル展開する企業が地域ごとの法規制や文化に合わせた戦略をとることを何というか。", "opts": ["グローカリゼーション", "ローカライゼーション", "コングロマリット", "グローバル標準化"], "ans": 0, "exp": "グローカリゼーション（Glocalization）はグローバルな視点を持ちつつ，現地の文化・規制・ニーズに合わせた適応戦略をとること。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 202, "q": "利用者が所有せず必要な時だけ使いたい分だけ利用でき，使った分だけ支払うモデルはどれか。", "opts": ["サブスクリプション", "ライセンス購入", "フリーミアム", "従量課金制（ペイアズユーゴー）"], "ans": 3, "exp": "従量課金制は利用した量（処理時間・データ量等）に応じて料金が変わる課金モデル。クラウドサービスで広く採用。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 203, "q": "流動資産から流動負債を引いた額として定義される指標はどれか。", "opts": ["運転資本", "総資本", "自己資本", "有利子負債"], "ans": 0, "exp": "運転資本（Working Capital）= 流動資産－流動負債。企業の短期的な支払い能力を示す。プラスであれば短期資金に余裕がある。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 204, "q": "在庫管理で注文点と注文量を都度決定し，在庫が一定水準を下回ったら発注する方式はどれか。", "opts": ["MRP", "定期発注方式", "JIT生産方式", "定量発注方式"], "ans": 3, "exp": "定量発注方式（固定量発注）は発注点に達したら一定量を発注する方式。在庫管理が簡単。定期発注は定期的に在庫を確認して変動量を発注。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 205, "q": "企業の財務状況を一時点で示し，資産・負債・純資産の関係を表す財務諸表はどれか。", "opts": ["損益計算書", "キャッシュフロー計算書", "製造原価明細書", "貸借対照表"], "ans": 3, "exp": "貸借対照表（B/S）は決算日時点の全資産（左辺）と全負債＋純資産（右辺）を一覧し，財務状況を示す。左右は必ず一致する。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 206, "q": "労働者が自分のスキルや意向に基づいて自律的にキャリアを設計・開発していく考え方はどれか。", "opts": ["年功序列", "キャリア自律", "メンバーシップ型雇用", "終身雇用"], "ans": 1, "exp": "キャリア自律は企業主導でなく個人が主体的にスキル開発・キャリア設計を行う考え方。ジョブ型雇用の普及で重要性増大。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 207, "q": "法律で定められた基準以上の取り組みを企業が自主的に行う社会的責任の考え方はどれか。", "opts": ["IR", "コーポレートガバナンス", "コンプライアンス", "CSR"], "ans": 3, "exp": "CSR（企業の社会的責任）はコンプライアンス（法令遵守）を超え，環境・社会・人権・地域貢献等へ自主的に取り組む概念。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 208, "q": "企業が投資家等に向けて財務・非財務情報を積極的に開示し，信頼関係を構築する活動はどれか。", "opts": ["IR", "PR", "ESG", "CSR"], "ans": 0, "exp": "IR（Investor Relations）は投資家・株主への企業情報開示活動。財務状況・戦略等の情報提供で適正な株価評価を目指す。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 209, "q": "特定の業務に対してライセンスを受けた専門家だけが独占的に業務を行える制度はどれか。", "opts": ["免許制度（業務独占資格）", "資格", "登録制度", "届出制度"], "ans": 0, "exp": "業務独占資格は有資格者のみが特定業務を行える制度（弁護士・医師等）。名称独占資格は資格名称の独占のみ（社会福祉士等）。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 210, "q": "AI・IoT等の新技術を限定的な環境で安全に試験・実証できる制度はどれか。", "opts": ["規制緩和", "規制サンドボックス", "特区制度", "オープンイノベーション"], "ans": 1, "exp": "規制サンドボックスは新技術・新ビジネスモデルを一定条件のもとで既存規制の適用を留保しながら実証実験できる制度。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 211, "q": "複数の企業や大学が連携し，共有の研究施設やリソースを活用して新技術を共同開発する取り組みはどれか。", "opts": ["産学官連携", "垂直統合", "フランチャイズ", "M&A"], "ans": 0, "exp": "産学官連携は産業界・大学・政府機関が研究資源・資金・人材を持ち寄り，イノベーション創出を目指す協力体制。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 212, "q": "製品の企画から廃棄まで全ライフサイクルにわたる環境負荷を定量評価する手法はどれか。", "opts": ["エコデザイン", "LCA（ライフサイクルアセスメント）", "EMAS", "ISO 14001"], "ans": 1, "exp": "LCA（Life Cycle Assessment）は原材料採取→製造→輸送→使用→廃棄の全工程でCO2排出量等の環境負荷を定量化する手法。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 213, "q": "固定費50万円，変動費率60%，販売単価5,000円の製品で損益分岐点の売上高を求めよ。", "opts": ["200万円", "125万円", "75万円", "150万円"], "ans": 1, "exp": "損益分岐点売上高 = 固定費÷(1-変動費率) = 50万÷(1-0.6) = 125万円。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 214, "q": "組織内の情報伝達において，同じ階層の部門間で水平的に情報を共有する仕組みはどれか。", "opts": ["横断的情報共有", "命令系統", "上位下達", "稟議"], "ans": 0, "exp": "横断的情報共有は縦方向（上下間）でなく，同じ階層の部門間で水平に情報を共有・連携する仕組み。サイロ化防止に重要。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 215, "q": "スタートアップが社内での新規事業立ち上げを指すとき，既存企業の中で起業家精神を発揮する概念はどれか。", "opts": ["イントラプレナーシップ", "アウトソーシング", "スピンアウト", "フランチャイズ"], "ans": 0, "exp": "イントラプレナーシップ（社内起業家精神）は既存企業の中で従業員が起業家のように新規事業を推進する概念。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 216, "q": "サービス提供者が利用者の同意なく利用データを販売・転用することを防ぐための権利はどれか。", "opts": ["データポータビリティ権", "プライバシー権", "忘れられる権利", "情報自己決定権"], "ans": 3, "exp": "情報自己決定権は自己の個人情報をいつ・誰に・どのように提供するかを本人が決定できる権利。EUのGDPRでも強調。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 217, "q": "利用者が特定のサービスで保有するデータを他サービスへ持ち出す権利をGDPRでは何というか。", "opts": ["忘れられる権利", "データポータビリティ権", "異議申立て権", "アクセス権"], "ans": 1, "exp": "データポータビリティ権（GDPR第20条）は自己データを機械読取り可能な形式で受け取り，他社へ移転を求める権利。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 218, "q": "自社の競争優位を守るために重要情報を外部に漏洩させないための施策として最も重要なものはどれか。", "opts": ["取引先への情報公開", "ソーシャルメディアへの積極発信", "秘密保持契約（NDA）の締結", "プレスリリースの発行"], "ans": 2, "exp": "NDA（Non-Disclosure Agreement：秘密保持契約）は取引・提携時に情報を共有する相手と機密情報の漏洩を禁じる法的契約。", "cat": "ストラテジ", "diff": "easy", "year": 2023}, {"id": 219, "q": "企業が外部の専門業者に業務を委託する際，業務プロセス全体を委託するものはどれか。", "opts": ["人材派遣", "BPO", "アウトスタッフィング", "SaaS"], "ans": 1, "exp": "BPO（Business Process Outsourcing）は給与計算・経理・コールセンター等の業務プロセス全体を外部専門業者に委託すること。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 220, "q": "従来の垂直統合型産業構造を解体し，各機能を独立サービスとして提供しやすくするデジタル化の現象はどれか。", "opts": ["バンドリング", "アンバンドリング", "プラットフォーム化", "垂直統合"], "ans": 1, "exp": "アンバンドリングは，従来一体化していたサービス要素を分離して独立提供する動き。金融・メディア等でデジタル化に伴い進行。", "cat": "ストラテジ", "diff": "hard", "year": 2023}, {"id": 221, "q": "複数の金融サービス（銀行口座・投資・保険等）をひとつのアプリで提供するサービスモデルはどれか。", "opts": ["フィンテック", "スーパーアプリ", "ウォレット", "ロボアドバイザー"], "ans": 1, "exp": "スーパーアプリは1つのアプリで多種サービスを提供するプラットフォームアプリ（WeChat，LINE等）。", "cat": "ストラテジ", "diff": "mid", "year": 2023}, {"id": 222, "q": "サービスマネジメントにおいて，日常業務の中でサービス品質を向上させる継続的な改善活動はどれか。", "opts": ["CSI（継続的サービス改善）", "変更管理", "SLM", "インシデント管理"], "ans": 0, "exp": "CSI（Continual Service Improvement）はITILの継続的サービス改善。PDCAサイクルでITサービスを継続的に改善する活動。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 223, "q": "ITサービスマネジメントで，インシデントの根本原因を特定して恒久対策を講じる管理活動はどれか。", "opts": ["インシデント管理", "変更管理", "問題管理", "リリース管理"], "ans": 2, "exp": "問題管理はインシデントの根本原因（問題）を特定・除去し，将来的なインシデント発生を防ぐ恒久的対策を講じる活動。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 224, "q": "プロジェクトマネジメントで，想定外の良い機会を活用する戦略として最も適切なものはどれか。", "opts": ["機会の活用", "リスク回避", "コンティンジェンシー計画", "リスク軽減"], "ans": 0, "exp": "PMBOKではリスクには「脅威」（悪影響）と「機会」（好影響）の両面がある。機会を活用・強化・受容する戦略が含まれる。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 225, "q": "プロジェクトのクリティカルパスに含まれる作業の特徴として適切なものはどれか。", "opts": ["余裕時間がゼロで遅延するとプロジェクト全体が遅延する", "余裕時間（フロート）が最も大きい", "コストが最も高い作業", "最も人員が必要な作業"], "ans": 0, "exp": "クリティカルパスはPERT/CPMで計算されたプロジェクトの最長経路。パス上の作業にはフロートがなく，遅延=全体遅延。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 226, "q": "EVM（アーンドバリューマネジメント）でSPIが1.0未満を示す場合の状態はどれか。", "opts": ["コストが予算を超過している", "スケジュールが計画より遅れている", "コストが予算内に収まっている", "計画より早く進んでいる"], "ans": 1, "exp": "SPI（Schedule Performance Index）= EV÷PV。1未満ならEV<PV，つまり計画より出来高が少なく進捗遅延を意味する。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 227, "q": "システム開発において，詳細設計の工程で作成するものとして最も適切なものはどれか。", "opts": ["要件定義書", "プログラム仕様書", "受入テスト仕様書", "システム化計画書"], "ans": 1, "exp": "詳細設計（内部設計）ではプログラム仕様書（モジュール設計書）を作成。概要設計はシステム全体の基本設計書，要件定義は要件定義書。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 228, "q": "セキュリティ上の意図した以外のアクセスがないか確認するためにシステムに対して模擬攻撃を行うテストはどれか。", "opts": ["ペネトレーションテスト", "脆弱性スキャン", "ファジング", "コードレビュー"], "ans": 0, "exp": "ペネトレーションテストは倫理的ハッカー（ペンテスター）が実際の攻撃者と同様の手法でシステムの弱点を発見するテスト。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 229, "q": "情報システム監査で，監査人が合理的な保証を提供するために収集する証拠を何というか。", "opts": ["内部統制評価書", "監査報告書", "監査証拠", "監査調書"], "ans": 2, "exp": "監査証拠は監査結論の基礎となる情報。インタビュー・書類・観察・再実施等の手続きで収集し，十分性・適切性が求められる。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 230, "q": "テスト管理において，テストの網羅範囲を把握するための表はどれか。", "opts": ["ガントチャート", "テスト仕様書", "バグ管理表", "テストマトリクス"], "ans": 3, "exp": "テストマトリクス（テスト網羅マトリクス）は機能×テスト条件を表にして，テストの網羅状況を可視化する管理手法。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 231, "q": "ソフトウェアの品質特性のうち，要求された機能を正しい精度で提供できる度合いはどれか。", "opts": ["信頼性", "使用性", "移植性", "機能適合性"], "ans": 3, "exp": "ISO/IEC 25010の機能適合性（Functional suitability）には機能完全性・正確性・適切性が含まれる。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 232, "q": "システム開発のV字モデルで，統合テストに対応する上流工程はどれか。", "opts": ["要件定義", "概要設計", "詳細設計", "プログラム設計"], "ans": 1, "exp": "V字モデルの対応関係：要件定義↔システムテスト，概要設計↔統合テスト，詳細設計↔単体テスト。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 233, "q": "情報システムの開発・運用にかかる総所有コストを表す指標はどれか。", "opts": ["TCO", "EVM", "ROI", "NPV"], "ans": 0, "exp": "TCO（Total Cost of Ownership：総所有コスト）はシステムの取得費用だけでなく，運用・保守・廃棄まで含む生涯コストの合計。", "cat": "マネジメント", "diff": "easy", "year": 2023}, {"id": 234, "q": "プロジェクト憲章に含まれる内容として最も適切なものはどれか。", "opts": ["プログラムのバグ一覧", "プロジェクトの目的・スコープ・主要マイルストーン", "詳細なコード設計仕様", "テスト仕様書"], "ans": 1, "exp": "プロジェクト憲章はPMが任命され，プロジェクト開始を正式に承認する文書。目的・スコープ・予算・期間・PMの権限を記載。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 235, "q": "アジャイル開発でスプリントの終わりにチームが改善点を話し合う振り返りセッションはどれか。", "opts": ["スプリントレトロスペクティブ", "デイリースクラム", "スプリントプランニング", "スプリントレビュー"], "ans": 0, "exp": "スプリントレトロスペクティブはスプリント終了後にチームプロセス・協力体制を振り返り，次スプリントへの改善策を決める会議。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 236, "q": "IT投資に対して，期間ごとの正味現在価値を合計してプロジェクトの採算性を評価する手法はどれか。", "opts": ["ROI法", "NPV法（正味現在価値法）", "ペイバック法", "IRR法"], "ans": 1, "exp": "NPV（Net Present Value）法は将来キャッシュフローを現在価値に割り引いて合計し，正ならば投資採算あり，と判断する手法。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 237, "q": "内部統制の構成要素のうち，目標達成を妨げるリスクを分析し対応策を決定するプロセスはどれか。", "opts": ["情報と伝達", "統制活動", "リスクの評価と対応", "統制環境"], "ans": 2, "exp": "COSO内部統制の5要素：統制環境・リスクの評価と対応・統制活動・情報と伝達・モニタリング。リスク評価は目標設定後に実施。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 238, "q": "IT統制において，アクセス権のレビューや本番データへの変更管理など，個別業務を制御する統制はどれか。", "opts": ["ITガバナンス", "内部監査", "業務処理統制", "全般統制"], "ans": 2, "exp": "業務処理統制はアプリケーション単位の入力・処理・出力の正確性を確保する統制。全般統制はIT環境全体を管理する統制。", "cat": "マネジメント", "diff": "hard", "year": 2023}, {"id": 239, "q": "変更管理において，緊急変更（緊急修正）の特徴として最も適切なものはどれか。", "opts": ["事後承認を含む簡略化された手続きで迅速に実施できる", "CABの全員同意が必要", "通常の変更承認プロセスを必ず踏む", "変更は週1回の定期タイミングのみ実施する"], "ans": 0, "exp": "緊急変更（Emergency Change）は重大障害等の緊急時に，簡略化された手続きで迅速に実施し，事後でCABの承認を得る変更。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 240, "q": "情報システムの災害対策として，主サイトから物理的に離れた場所に別の施設を設けることを何というか。", "opts": ["ロードバランシング", "フェールオーバー", "ホットスタンバイ", "バックアップサイト（遠隔地バックアップ）"], "ans": 3, "exp": "バックアップサイト（ディザスタリカバリサイト）は主センターから物理的に離れた場所に設置。被災時に業務継続を可能にする。", "cat": "マネジメント", "diff": "mid", "year": 2023}, {"id": 241, "q": "QCDのうち「D」が示すものとして正しいものはどれか。", "opts": ["Delivery（納期・納量）", "Design（設計品質）", "Documentation（文書化）", "Decision（意思決定）"], "ans": 0, "exp": "QCDはQuality（品質）・Cost（コスト）・Delivery（納期・納量）。ものづくり・プロジェクト管理で重視される3指標。", "cat": "マネジメント", "diff": "easy", "year": 2023}, {"id": 242, "q": "ARP（Address Resolution Protocol）の機能として正しいものはどれか。", "opts": ["ドメイン名からIPアドレスへの変換", "電子メールの転送", "IPアドレスからMACアドレスへの変換", "ファイルの転送"], "ans": 2, "exp": "ARPはIPアドレスをもとにMACアドレスを求めるプロトコル。同一LAN上での通信時に宛先MACを解決するために使用。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 243, "q": "TCPの3ウェイハンドシェイクの手順として正しいものはどれか。", "opts": ["SYN → SYN-ACK → ACK", "ACK → SYN → SYN-ACK", "SYN → ACK → SYN-ACK", "CONNECT → ACCEPT → CONFIRM"], "ans": 0, "exp": "TCPの接続確立は①SYN②SYN-ACK③ACKの3手順（3ウェイハンドシェイク）。この後にデータ転送が始まる。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 244, "q": "メールの受信に使われるプロトコルで，サーバ上にメールを保管したまま複数の端末から読める方式はどれか。", "opts": ["SMTP", "MIME", "POP3", "IMAP"], "ans": 3, "exp": "IMAP（Internet Message Access Protocol）はメールをサーバに保管したまま複数端末で同期できる。POP3はローカルにダウンロードする。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 245, "q": "公開鍵暗号方式で，電子署名を検証する際に使用する鍵はどれか。", "opts": ["送信者の秘密鍵", "受信者の秘密鍵", "受信者の公開鍵", "送信者の公開鍵"], "ans": 3, "exp": "電子署名は署名者の秘密鍵で生成し，署名者の公開鍵で検証する。「公開鍵で検証できる＝秘密鍵所有者が署名した」ことが証明される。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 246, "q": "PKI（公開鍵基盤）においてデジタル証明書を発行・管理する機関はどれか。", "opts": ["RA（登録局）", "ISMS認証機関", "ISP", "CA（認証局）"], "ans": 3, "exp": "CA（Certificate Authority：認証局）はデジタル証明書の発行・失効管理を行う信頼できる第三者機関。VeriSign等が代表例。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 247, "q": "ハッシュ関数の特性として正しいものはどれか。", "opts": ["入力データのわずかな変化で出力が大きく変化する", "ハッシュ値から元のデータを復元できる", "同じ入力でも毎回異なるハッシュ値が生成される", "異なる入力に同じハッシュ値が生成されることは理論上ない"], "ans": 0, "exp": "ハッシュ関数の特性：①一方向性（逆算不可），②わずかな変化で出力が大変化（雪崩効果），③衝突困難性（同値生成困難）。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 248, "q": "Webサービスでユーザー認証を外部サービス（Google等）に委譲する標準プロトコルはどれか。", "opts": ["LDAP", "OpenID Connect", "OAuth", "SAML"], "ans": 1, "exp": "OpenID ConnectはOAuth 2.0上に認証層を追加したプロトコル。Googleアカウントで他サービスにログインする仕組みに使用。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 249, "q": "パスワードの総当たり攻撃（ブルートフォース）への対策として最も有効なものはどれか。", "opts": ["一定回数の失敗でアカウントをロックする", "パスワードをメモしておく", "全ユーザー同じパスワードにする", "パスワードを短くする"], "ans": 0, "exp": "アカウントロックアウトは一定回数のログイン失敗でアカウントを一時ロックし，ブルートフォース攻撃を防ぐ効果的な対策。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 250, "q": "DNSキャッシュポイズニング攻撃の説明として最も適切なものはどれか。", "opts": ["ドメイン名を盗むフィッシング", "DNSサーバへのDDoS攻撃", "DNSサーバに偽のIPアドレス情報を注入し，ユーザーを不正サイトに誘導する", "DNSレコードの暗号化を解除する"], "ans": 2, "exp": "DNSキャッシュポイズニングはDNSキャッシュに偽の名前解決結果を注入し，正規サイトへのアクセスを攻撃者サイトに誘導する攻撃。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 251, "q": "IT機器やシステムに存在する欠陥・弱点のことを何というか。", "opts": ["脆弱性", "リスク", "インシデント", "脅威"], "ans": 0, "exp": "脆弱性（Vulnerability）はシステムやソフトウェアに存在するセキュリティ上の欠陥・弱点。CVEデータベースで公開管理される。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 252, "q": "ビッグデータの3つのV（3V）として正しい組み合わせはどれか。", "opts": ["Volume, Velocity, Variety", "Velocity, Value, Venue", "Value, Vision, Variety", "Volume, Validity, Virtue"], "ans": 0, "exp": "ビッグデータの3V：Volume（容量大），Velocity（速度），Variety（多様性）。近年はValue（価値）やVeracity（正確性）も追加。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 253, "q": "大量のデータを高速処理するために，専用のデータ収集システムが必要とされる事例として適切なものはどれか。", "opts": ["個人がブログを書く", "年1回の決算書を作成する", "月次の売上報告を集計する", "工場のIoTセンサが毎秒データを送信する"], "ans": 3, "exp": "IoTセンサが毎秒大量データを送信するユースケースは高頻度・大量データでビッグデータ処理基盤が必要。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 254, "q": "機械学習で，学習データとテストデータに分けて評価を行う基本的な方法はどれか。", "opts": ["ホールドアウト法", "アンサンブル学習", "次元削減", "主成分分析"], "ans": 0, "exp": "ホールドアウト法は全データを学習用（訓練データ）とテスト用に分割し，テストデータで汎化性能を評価する最も基本的な手法。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 255, "q": "自然言語処理で，文章を構成する単語の意味的な類似度を空間上の距離で表現する技術はどれか。", "opts": ["感情分析", "形態素解析", "構文解析", "単語埋め込み（Word Embedding）"], "ans": 3, "exp": "単語埋め込み（Word2Vec等）は単語を低次元の実数ベクトルに変換し，意味的に近い単語が近距離になるよう学習する技術。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 256, "q": "コンピュータで「1000」（2進数4ビット）の補数表現による負の整数はどれか。", "opts": ["-0", "-1", "-8", "-7"], "ans": 2, "exp": "4ビット2の補数：1000 = 最上位ビットが1なので負数。絶対値 = ビット反転+1 → 0111+1=1000=8。よって-8。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 257, "q": "CPUの性能を表す指標として，1GHzのクロック周波数が意味するものはどれか。", "opts": ["1秒あたり10億回クロックを刻む", "1秒あたり10億命令を処理", "1GBのキャッシュを搭載", "1秒あたり1GB転送"], "ans": 0, "exp": "クロック周波数1GHz = 1秒あたり10億回（10⁹回）のクロックパルス。実際の命令処理速度はIPC（1クロックあたり命令数）にも依存。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 258, "q": "RAIDの中で，1台の障害時にデータ復旧が可能で，読み取り速度が向上するものはどれか。", "opts": ["RAID 5", "RAID 1", "RAID 10", "RAID 0"], "ans": 0, "exp": "RAID 5はストライピング＋パリティ（分散）。1台障害時に残りのデータとパリティから復旧可能。読み取り高速。書き込み時パリティ計算のオーバーヘッドあり。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 259, "q": "スタックのデータ構造において，最後に挿入したデータが最初に取り出される原則はどれか。", "opts": ["FIFO", "LIFO", "LILO", "FILO"], "ans": 1, "exp": "スタック（Stack）はLIFO（Last In First Out）構造。最後にpushされたデータが最初にpopされる。関数呼び出しの管理等に使用。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 260, "q": "再帰的なデータ構造で，各ノードが最大2つの子を持つ木構造はどれか。", "opts": ["リスト", "グラフ", "スタック", "二分木"], "ans": 3, "exp": "二分木（Binary Tree）は各ノードが最大2つの子ノードを持つ木構造。二分探索木は左<親<右の順序を保持し，検索効率が高い。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 261, "q": "プログラムのソースコードを解析して設計文書を再生成するリバースエンジニアリングの目的として適切なものはどれか。", "opts": ["セキュリティ強化", "既存システムの仕様理解と保守性向上", "プログラムの圧縮", "プログラムの高速化"], "ans": 1, "exp": "リバースエンジニアリングはドキュメントが失われた既存システムの仕様を再解析し，保守・移行・互換性確保に活用する手法。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 262, "q": "IoTデバイスのセキュリティリスクとして最も適切なものはどれか。", "opts": ["データ処理速度が遅い", "ネットワークに接続できない", "出荷時のデフォルトパスワードが変更されず悪用される", "消費電力が多い"], "ans": 2, "exp": "IoTデバイスのデフォルトパスワード未変更は重大なセキュリティリスク。Miraiボットネット等の攻撃事例で顕在化している。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 263, "q": "WebブラウザとWebサーバ間でHTTPSを使って通信するときに証明書の正当性を確認する流れとして適切なものはどれか。", "opts": ["サーバがブラウザの証明書を確認する", "ブラウザが信頼するCAが発行した証明書をサーバが提示し，ブラウザが検証する", "ブラウザが自己署名証明書を信頼する", "証明書の確認は行われない"], "ans": 1, "exp": "HTTPS接続時，サーバはCAが発行したデジタル証明書を提示。ブラウザは信頼されたCA一覧（ルートCA）で証明書の正当性を検証。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 264, "q": "AIモデルの学習に使うデータに正解ラベルを付与する作業はどれか。", "opts": ["前処理", "クレンジング", "アノテーション", "正規化"], "ans": 2, "exp": "アノテーション（Annotation）は機械学習の教師データとして画像や文章に正解ラベル（タグ）を付与する作業。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 265, "q": "AIにおいて，学習済みモデルの判断根拠を人間が理解・説明できるようにする研究分野はどれか。", "opts": ["敵対的学習", "転移学習", "説明可能AI（XAI）", "強化学習"], "ans": 2, "exp": "XAI（Explainable AI）は「ブラックボックス」であるAIの判断根拠を解釈可能にする研究領域。医療・金融等の規制対応で重要。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 266, "q": "バーチャルアシスタント（Siri, Alexa等）に使われる，人間の言語を理解・処理するAI技術分野はどれか。", "opts": ["画像認識", "自然言語処理（NLP）", "強化学習", "ロボティクス"], "ans": 1, "exp": "NLP（Natural Language Processing）は人間の言語（テキスト・音声）をコンピュータが理解・生成する技術。機械翻訳・音声認識等に応用。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 267, "q": "不揮発性メモリでデータの書き換えが可能，電源なしでもデータ保持するメモリはどれか。", "opts": ["DRAM", "キャッシュメモリ", "SRAM", "フラッシュメモリ"], "ans": 3, "exp": "フラッシュメモリはUSBメモリ・SSD・SDカード等に使われる不揮発性半導体メモリ。電源切断後もデータが保持される。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 268, "q": "5Gの特徴として最も適切なものはどれか。", "opts": ["高速・大容量・低遅延・多数接続が実現", "無線LANとBluetoothを統合した規格", "通信速度は4Gと同等だが遅延が改善", "衛星通信のみを利用した規格"], "ans": 0, "exp": "5Gは超高速（最大20Gbps）・超低遅延（1ms以下）・多数同時接続（100万台/km²）が特徴。自動運転・遠隔医療等に対応。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 269, "q": "製品やサービスにIoTを組み込んで価値を高め，従来の製造業がサービス業を兼ねるビジネス変革を何というか。", "opts": ["マス・カスタマイゼーション", "プロダクト・アズ・ア・サービス", "スマートファクトリー", "インダストリー4.0"], "ans": 1, "exp": "Product as a Service（PaaS）は機械等の製品にIoTを組み込み，使用量・稼働状況に応じた課金やメンテナンスサービスを提供するビジネスモデル。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 270, "q": "工場・インフラ等の機器にセンサを取り付け，クラウドへデータを集めてAIで分析するシステムをどれか。", "opts": ["BEMS", "インダストリアルIoT（IIoT）", "SCADA", "スマートグリッド"], "ans": 1, "exp": "IIoT（Industrial IoT）は工場・エネルギー・交通等の産業設備にIoTを適用し，生産性向上・予知保全・品質管理を実現する概念。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 271, "q": "複数の企業が連携してサプライチェーン上のデータを共有し，全体最適を目指す取り組みはどれか。", "opts": ["データスペース", "オープンAPI", "EDI", "サプライチェーンマネジメント"], "ans": 3, "exp": "SCMは原材料から最終製品まで一連の供給連鎖を統合管理。デジタル化でリアルタイム在庫共有や需給予測が可能に。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 272, "q": "新型コロナウイルス対応でテレワーク普及が加速したことで顕在化した課題として最も適切なものはどれか。", "opts": ["オフィス賃料の増加", "セキュリティリスクの増大と孤立感・マネジメント困難", "会議室の不足", "通勤時間の増加"], "ans": 1, "exp": "テレワーク普及でVPN・クラウドへの不正アクセスリスク増大，孤立感，対面管理困難等の課題が顕在化。ゼロトラストモデルが注目。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 273, "q": "ネットワークへのアクセスを「全て信頼しない」前提で，常に認証・認可・検証を行うセキュリティモデルはどれか。", "opts": ["ゼロトラストセキュリティ", "ペリメータセキュリティ", "DMZ", "エアギャップ"], "ans": 0, "exp": "ゼロトラストはVPNや社内ネットワークも含め全アクセスを検証。「侵入前提」でテレワーク・クラウド時代のセキュリティモデル。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 274, "q": "電子商取引（EC）の形態のうち，企業間取引を表すものはどれか。", "opts": ["B2C", "C2C", "G2C", "B2B"], "ans": 3, "exp": "B2B（Business to Business）は企業間電子商取引。B2CはAmazon等の企業対消費者，C2CはメルカリのようなC2C，G2Cは政府対市民。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 275, "q": "消費者が商品をSNS等で自発的に紹介・推薦し，ブランド認知を広げる人々を何というか。", "opts": ["アンバサダー", "クリエイター", "インフルエンサー", "アフィリエイター"], "ans": 2, "exp": "インフルエンサーは多くのフォロワーを持ちSNSで影響力を持つ人物。企業はインフルエンサーマーケティングで認知拡大を図る。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 276, "q": "組織が自社のコアでない業務を外部専門業者に任せる戦略をどれか。", "opts": ["インソーシング", "コアコンピタンス経営", "アウトソーシング", "バリューチェーン"], "ans": 2, "exp": "アウトソーシングは給与計算・IT運用等のノンコア業務を外部専門業者に委託し，自社はコア事業に集中する戦略。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 277, "q": "著作権の支分権のうち，著作物を複製する権利はどれか。", "opts": ["複製権", "頒布権", "翻案権", "公衆送信権"], "ans": 0, "exp": "複製権は著作権の基本的な支分権。著作物を印刷・コピー・録音等の方法で再製する権利を著作権者が専有する。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 278, "q": "AIを活用した新薬開発で，有望な候補物質を大量のデータから絞り込む手法として適切なものはどれか。", "opts": ["フェーズ3試験", "ランダム化比較試験", "クリニカルトライアル", "インシリコスクリーニング（AI創薬）"], "ans": 3, "exp": "AI創薬（インシリコスクリーニング）は大量の化合物データからAIが候補物質を予測・絞込み，創薬コスト・時間を大幅削減する技術。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 279, "q": "ムーアの法則として正しいものはどれか。", "opts": ["ネットワーク利用者数が2倍になるとネットワーク価値は4倍になる", "AIの能力は毎年2倍になる", "半導体集積度は約18〜24か月で2倍になる", "ストレージ単価は毎年50%下がる"], "ans": 2, "exp": "ムーアの法則はIntelのゴードン・ムーアが提唱。半導体チップの集積度が約18〜24か月で倍増するという経験則。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 280, "q": "メトカーフの法則として正しいものはどれか。", "opts": ["半導体集積度は約2年で2倍になる", "コンピュータ性能は毎年向上する", "ソフトウェア開発生産性は人員増加に反比例する", "ネットワークの価値は接続数の2乗に比例する"], "ans": 3, "exp": "メトカーフの法則：ネットワーク価値∝n²（nはノード数）。SNS・電話等のネットワーク効果を説明する法則。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 281, "q": "情報セキュリティの方針書を示す文書で，組織全体のセキュリティに関する基本的な考え方を定めたものはどれか。", "opts": ["セキュリティポリシー", "インシデント対応計画", "BCP", "SLA"], "ans": 0, "exp": "セキュリティポリシーは組織の情報セキュリティに関する基本方針・規則を定めた文書。方針→対策基準→実施手順の階層構造。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 282, "q": "電子政府の取り組みとしてデジタル庁が推進するマイナンバーカードの多目的活用で，民間サービスへの活用例として最も適切なものはどれか。", "opts": ["住所変更の自動処理", "犯罪捜査への提供", "所得税の支払い", "オンライン本人確認（eKYC）"], "ans": 3, "exp": "マイナンバーカードのICチップや電子証明書は民間のeKYC（電子的本人確認）にも活用。スマホ完結での口座開設等に使用。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 283, "q": "企業が事業継続計画（BCP）を策定する主な目的として最も適切なものはどれか。", "opts": ["人材採用を効率化する", "災害・事故等の緊急時に重要業務を継続または早期再開させる", "利益を最大化する", "新規事業を開拓する"], "ans": 1, "exp": "BCP（Business Continuity Plan）は大地震・パンデミック等の緊急事態に重要業務を継続し，顧客・社会への損害を最小化する計画。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 284, "q": "内部通報者保護法の目的として最も適切なものはどれか。", "opts": ["内部監査の実施を義務付ける", "顧客からの苦情を処理する", "個人情報の取り扱いを規制する", "企業の不正を告発した従業員を保護する"], "ans": 3, "exp": "公益通報者保護法は組織内の法令違反等を当局・マスコミ等に通報した従業員を不利益取り扱い（解雇等）から保護する法律。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 285, "q": "企業の情報漏洩対策として最も重要な組織的施策はどれか。", "opts": ["全員の端末にパスワードを設定する", "ウイルス対策ソフトの導入", "外部との通信を全て禁止する", "情報セキュリティ教育・訓練の定期実施"], "ans": 3, "exp": "人的ミス・内部不正が情報漏洩の主要因。定期的なセキュリティ教育・フィッシング訓練・意識向上が最重要の組織的対策。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 286, "q": "職業倫理として，システムエンジニアが利用者の個人情報を取り扱う際に守るべき原則として最も適切なものはどれか。", "opts": ["バックアップのために個人PCに保存する", "目的外利用をせず適切に管理する", "業務効率化のため自由に活用する", "必要に応じて同僚に共有する"], "ans": 1, "exp": "エンジニアの情報倫理として，個人情報は収集目的の範囲内でのみ利用し，目的外利用・不正アクセス・漏洩防止が必須。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 287, "q": "資本金1億円，売上高5億円の中小企業が新しいシステムを導入するとき，中小企業診断士が助言する観点として最も適切なものはどれか。", "opts": ["常に最新鋭のシステムを導入すべき", "投資対効果を見極め経営目標に合ったシステムを選択する", "競合他社と同じシステムにする", "IT補助金を活用しないと意味がない"], "ans": 1, "exp": "中小企業のIT投資は経営目標との整合性・費用対効果・保守体制等を総合的に判断して選択するのが適切。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 288, "q": "利用者の行動・嗜好データを収集しAIで個人に最適化した情報・広告を提供する仕組みはどれか。", "opts": ["プッシュ通知", "コンテンツマーケティング", "レコメンドシステム", "マスメディア広告"], "ans": 2, "exp": "レコメンドシステムは閲覧・購買履歴等のデータからAIが嗜好を推定し，個人に最適な商品・コンテンツを自動提示する仕組み。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 289, "q": "新規参入者が既存市場を根本的に変革する技術・ビジネスモデルを何というか。", "opts": ["イノベーション", "オープンイノベーション", "ディスラプション（破壊的イノベーション）", "インクリメンタルイノベーション"], "ans": 2, "exp": "ディスラプション（C.クリステンセン提唱）は低コスト・シンプルな新技術が既存市場を根底から覆す現象。Uberの配車業界参入等が代表例。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 290, "q": "総資本のうち純資産（自己資本）の割合を示す安全性指標はどれか。", "opts": ["固定比率", "自己資本比率", "流動比率", "ROE"], "ans": 1, "exp": "自己資本比率 = 自己資本÷総資本×100。高いほど財務安定性が高い。一般に40%以上で優良とされる。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 291, "q": "企業の知的資産のうち，目に見えない「ブランド・顧客関係・従業員スキル」等を資本として捉えた概念はどれか。", "opts": ["金融資産", "有形資産", "知的資本", "物的資本"], "ans": 2, "exp": "知的資本（Intellectual Capital）は人的資本・構造資本・関係資本からなる無形の企業価値。財務諸表に表れにくいが競争優位の源泉。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 292, "q": "プラットフォームビジネスで，ユーザーが増えるほどサービスの価値が高まる効果はどれか。", "opts": ["スコープの経済", "ネットワーク効果", "規模の経済", "ラーニングカーブ効果"], "ans": 1, "exp": "ネットワーク効果は利用者増加により価値が増大する現象（SNS・OS等）。勝者総取り（Winner Takes All）の傾向を生む。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 293, "q": "経営者がITの利活用を主導し，IT投資・リスク・価値を管理する概念はどれか。", "opts": ["情報セキュリティマネジメント", "ITアーキテクチャ", "ITガバナンス", "プロジェクトマネジメント"], "ans": 2, "exp": "ITガバナンスは経営者の責任において，IT投資の方向性設定・リスク管理・価値創造をリードするコーポレートガバナンスの一部。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 294, "q": "デジタルトランスフォーメーションで重要な「アジャイルな組織文化」に必要な要素はどれか。", "opts": ["権限委譲と自律的なチーム", "完全な仕様書の完成後に開発開始", "トップダウンのみの指示", "稟議を経た意思決定"], "ans": 0, "exp": "DX推進にはスピードと変化対応が必要。権限委譲による自律的チーム・心理的安全性・実験文化がアジャイル組織の基盤。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 295, "q": "電子証明書やブロックチェーンを使った本人確認をオンラインで完結させる仕組みはどれか。", "opts": ["バイオメトリクス", "eKYC", "2要素認証", "シングルサインオン"], "ans": 1, "exp": "eKYC（electronic Know Your Customer）は電子的に本人確認を完結させる仕組み。マイナンバーカード・運転免許証等のIC読み取りで実現。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 296, "q": "固定費÷（1－変動費率）で求めた売上高のことを何というか。", "opts": ["粗利益", "経常利益", "損益分岐点売上高", "営業利益"], "ans": 2, "exp": "損益分岐点売上高 = 固定費÷貢献利益率（=1-変動費率）。この売上高を超えると利益が発生する。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 297, "q": "テレワーク環境での情報漏洩リスクとして，自宅の画面を他者に見られることを防ぐ対策はどれか。", "opts": ["プライバシーフィルタの貼付・画面の向きの工夫", "VPNの利用", "ファイアウォールの設置", "パスワードの強化"], "ans": 0, "exp": "テレワークでの画面のぞき見（ショルダーハッキング）対策はプライバシーフィルタ・壁向き設置・カーテン等の物理的対策が有効。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 298, "q": "1単位あたり変動費が400円，固定費合計が120万円，販売単価800円の製品の損益分岐点販売量はどれか。", "opts": ["4,000個", "3,000個", "5,000個", "2,000個"], "ans": 1, "exp": "損益分岐点数量 = 固定費÷（単価-変動費）= 1,200,000÷（800-400）= 3,000個。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 299, "q": "情報通信技術を活用して市民の利便性を高め，行政サービスをデジタル化する概念はどれか。", "opts": ["GovTech", "デジタルファースト", "スマートシティ", "電子政府"], "ans": 3, "exp": "電子政府（e-Government）はITで行政手続きのオンライン化・効率化を図り，市民の利便性を高める取り組みの総称。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 300, "q": "特定の大企業や機関を狙い，組織内の取引先等を踏み台にして侵入を試みる攻撃はどれか。", "opts": ["ゼロデイ攻撃", "DDoS攻撃", "APT攻撃（標的型持続的脅威）", "フィッシング"], "ans": 2, "exp": "APT（Advanced Persistent Threat）攻撃は高度な手法を駆使して特定組織を長期間にわたり執拗に攻撃し，情報窃取を狙う。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 301, "q": "企業の経営理念・行動指針が従業員に浸透し，自律的に動く文化を醸成するために有効なものはどれか。", "opts": ["マニュアルの作成のみ", "給与の一律カット", "懲罰規定の強化", "リーダーによる一貫した言動と教育・研修の継続"], "ans": 3, "exp": "企業文化の醸成には経営者・マネジャーの一貫した言動と継続的な教育・対話が有効。懲罰だけでは内面化されない。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 302, "q": "ITIL 4でサービスを提供する組織と顧客が共に価値を創造するという概念はどれか。", "opts": ["ITILコアプラクティス", "インシデント管理", "SLM", "共同価値創造（コ・クリエーション）"], "ans": 3, "exp": "ITIL 4ではサービス提供者と顧客が共に価値を創造するCoCreation（共同価値創造）概念を重視。SVS（サービス価値システム）の中心概念。", "cat": "マネジメント", "diff": "hard", "year": 2022}, {"id": 303, "q": "ソフトウェア開発の工数見積もり手法として，プログラムの機能数を基に見積もる方法はどれか。", "opts": ["類推法", "COCOMOモデル", "ファンクションポイント法", "経験則法"], "ans": 2, "exp": "ファンクションポイント（FP）法は入出力・照会・ファイル等の論理機能数を計測して開発規模・工数を見積もる手法。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 304, "q": "インシデント管理の目的として最も適切なものはどれか。", "opts": ["SLAを策定する", "インシデントを可能な限り早く解決してサービスを復旧させる", "新しい変更を承認する", "インシデントの根本原因を除去する"], "ans": 1, "exp": "インシデント管理はサービスへの影響を最小化し，最短時間で通常サービスを復旧することが目的。根本原因除去は問題管理の役割。", "cat": "マネジメント", "diff": "easy", "year": 2022}, {"id": 305, "q": "プロジェクトのスケジュール管理で，並行実行できない作業の依存関係を矢印で示す図はどれか。", "opts": ["WBS", "バーンダウンチャート", "ガントチャート", "PERT/CPMのネットワーク図"], "ans": 3, "exp": "PERT（Program Evaluation and Review Technique）のネットワーク図は作業の先行・後続関係と期間を矢印（アロー）で示す。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 306, "q": "プロジェクトコスト管理でEACの説明として正しいものはどれか。", "opts": ["Estimated Approved Change：承認変更見積", "Estimate At Completion：完了時のコスト予測値", "Equivalent Actual Cost：等価実績コスト", "Earned Actual Cost：出来高コスト"], "ans": 1, "exp": "EAC（Estimate at Completion）はプロジェクト全体の最終コスト予測。EAC=AC+(BAC-EV)/CPIで計算することが多い。", "cat": "マネジメント", "diff": "hard", "year": 2022}, {"id": 307, "q": "システムの受入テストを行うユーザーへのサポートとして最も重要なものはどれか。", "opts": ["テストスクリプトをユーザーが全て作成する", "全テストを開発者が代行する", "本番環境でテストを実施する", "ユーザーが業務視点でテストできるよう，テスト環境・テストデータを整備する"], "ans": 3, "exp": "受入テストは発注者（ユーザー）が主体。ベンダはユーザーが業務要件に沿ってテストできる環境・データ・サポートを提供する。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 308, "q": "外部委託先のリスク管理として，委託先のセキュリティ対策状況を確認する活動はどれか。", "opts": ["パッチ管理", "脆弱性管理", "インシデント対応", "サードパーティリスク管理"], "ans": 3, "exp": "サードパーティリスク管理はベンダ・委託先のセキュリティ・コンプライアンス状況を評価・モニタリングし，リスクを制御する活動。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 309, "q": "情報システム監査において，監査人が業務の遂行状況を現場で直接確認する手続きはどれか。", "opts": ["再実施", "観察", "質問", "書類レビュー"], "ans": 1, "exp": "観察（Observation）は監査人が業務遂行の現場に立ち会い，手続きやコントロールが実際に機能しているかを直接確認する監査手続き。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 310, "q": "組織のリスクを一元的に把握・管理する経営レベルのリスク管理フレームワークはどれか。", "opts": ["BCP", "個別リスク管理", "ERM（全社的リスク管理）", "ISMS"], "ans": 2, "exp": "ERM（Enterprise Risk Management）は組織全体のリスクを網羅的に特定・評価・対応・モニタリングする全社的リスク管理の枠組み。COSOが代表的フレームワーク。", "cat": "マネジメント", "diff": "hard", "year": 2022}, {"id": 311, "q": "CMMI（能力成熟度モデル統合）レベル3の特徴として正しいものはどれか。", "opts": ["プロセスが場当たり的で再現性が低い", "組織全体で標準化されたプロセスが定義・展開されている", "プロセス改善が継続的に最適化されている", "定量的管理が行われている"], "ans": 1, "exp": "CMMIのレベル3（定義済み）は組織全体で標準プロセスが定義され，プロジェクトにカスタマイズして展開する段階。", "cat": "マネジメント", "diff": "hard", "year": 2022}, {"id": 312, "q": "アジャイル開発でProductOwnerが優先度を管理するバックログに積まれる作業単位を何というか。", "opts": ["スプリント", "エピック", "ユーザーストーリー", "スパイク"], "ans": 2, "exp": "ユーザーストーリーはアジャイルの要求単位。「（ユーザーとして）〇〇したい，なぜなら〜〜だから」の形式で機能要求を記述。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 313, "q": "テスト工程で，バグを修正した後に他の機能に影響が出ていないかを再テストすることを何というか。", "opts": ["デバッグ", "単体テスト", "リグレッションテスト", "探索的テスト"], "ans": 2, "exp": "リグレッションテスト（退行テスト）は修正・変更後に既存機能の動作が壊れていないかを確認するためのテスト。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 314, "q": "エンドユーザーへのITサービス提供で，複数の問い合わせを一元管理するシステムはどれか。", "opts": ["サービスデスクツール（チケット管理システム）", "ITSM", "CRM", "SFA"], "ans": 0, "exp": "チケット管理システム（Jira Service Desk, ServiceNow等）はインシデント・問い合わせを一元管理しエスカレーション・追跡を効率化するツール。", "cat": "マネジメント", "diff": "easy", "year": 2022}, {"id": 315, "q": "SLAに記載する内容として適切でないものはどれか。", "opts": ["サービスデスクの応答時間", "違反時のペナルティ", "サービスの可用性（稼働率）", "担当エンジニアの個人名"], "ans": 3, "exp": "SLA（Service Level Agreement）には可用性・応答時間・解決時間・ペナルティ等を記載する。特定個人名は記載しない。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 316, "q": "独立したテストチームがソフトウェアを公式に検査し，欠陥を発見する体系的なレビュー手法はどれか。", "opts": ["インスペクション", "コードレビュー", "ウォークスルー", "ピアレビュー"], "ans": 0, "exp": "インスペクション（Fagan Inspection）はモデレータが進行し，あらかじめ役割（読み手・記録者等）を分担して成果物を体系的に検査するフォーマルレビュー。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 317, "q": "CISOの役割として最も適切なものはどれか。", "opts": ["組織の情報セキュリティ全体を統括する最高情報セキュリティ責任者", "システム開発の主担当者", "ネットワーク運用管理者", "個人情報保護担当者"], "ans": 0, "exp": "CISO（Chief Information Security Officer）は組織の情報セキュリティ戦略・施策を統括する経営幹部。CIOとは別にセキュリティに特化した責任者。", "cat": "マネジメント", "diff": "easy", "year": 2022}, {"id": 318, "q": "DevOpsの説明として最も適切なものはどれか。", "opts": ["ウォーターフォールの改善手法", "開発チームだけでソフトウェアを開発する手法", "開発チームと運用チームが協力し，CI/CDパイプラインで高頻度のデプロイを実現する手法", "テストチームを独立させる手法"], "ans": 2, "exp": "DevOpsはDevelopment（開発）とOperations（運用）を統合。自動化・CI/CD・コラボレーションで迅速なデリバリーと高品質を実現。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 319, "q": "ソフトウェアの結合テストで用いる，実際のモジュールの代替となる未完成の呼び出し先（下位）モジュールを何というか。", "opts": ["モック", "ドライバ", "ハーネス", "スタブ"], "ans": 3, "exp": "スタブ（Stub）は呼び出される側（下位）の未実装モジュールの代替。ドライバは呼び出す側（上位）の代替。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 320, "q": "IT投資の費用対効果を評価する際，回収期間法の説明として正しいものはどれか。", "opts": ["全期間のキャッシュフローを現在価値に割り引いて評価する", "内部収益率を求めて評価する", "投資金額を回収するまでの期間を計算して評価する", "ROIを計算して評価する"], "ans": 2, "exp": "ペイバック（回収期間）法は投資額÷年間利益等でシンプルに回収期間を求める。時間価値を考慮しないが直感的で中小企業に多用。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 321, "q": "内部統制において，管理職が部下の業務を直接確認・評価する統制活動はどれか。", "opts": ["アクセス制御", "職務分離", "監督コントロール", "調整コントロール"], "ans": 2, "exp": "監督コントロールは上位者が部下の業務遂行状況を監督・確認することで，誤りや不正を発見・是正する内部統制活動。", "cat": "マネジメント", "diff": "hard", "year": 2022}, {"id": 322, "q": "Wi-Fi 6（IEEE 802.11ax）の特徴として正しいものはどれか。", "opts": ["2.4GHz帯のみ使用", "最大通信速度が9.6Gbpsで多数接続環境での効率が向上", "Bluetooth 5.0と完全互換", "有線LANと同等のセキュリティを標準提供"], "ans": 1, "exp": "Wi-Fi 6（802.11ax）は最大理論値9.6Gbps，OFDMA・TWT等で混雑環境での効率向上。スタジアム・IoT環境に適する。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 323, "q": "HTTPの無状態（ステートレス）な性質を補うために，WebサーバがブラウザにIDを保存させる仕組みはどれか。", "opts": ["クッキー（Cookie）", "JWT", "キャッシュ", "セッション変数"], "ans": 0, "exp": "Cookie（クッキー）はWebサーバがブラウザに小さなデータを保存させる仕組み。ログイン状態やカート情報の維持に使用。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 324, "q": "電子メールの送信ドメイン認証技術で，DNSにドメインの公開鍵を登録し電子署名でなりすましを防ぐ方式はどれか。", "opts": ["DMARC", "S/MIME", "DKIM", "SPF"], "ans": 2, "exp": "DKIM（DomainKeys Identified Mail）は送信メールに電子署名を付加し，DNS登録の公開鍵で検証することでなりすましを防ぐ。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 325, "q": "コンピュータウイルスの中で，ユーザーが実行すると有害動作を行うが，ウイルスとは異なり自己複製しないプログラムはどれか。", "opts": ["ワーム", "トロイの木馬", "ルートキット", "スパイウェア"], "ans": 1, "exp": "トロイの木馬は正規ソフトに偽装して侵入し有害動作を行うが自己複製しない。ワームは自己複製で拡散，ウイルスはファイルに寄生。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 326, "q": "企業ネットワークで，通信内容を暗号化せずに全パケットをキャプチャして解析するツールをどれか。", "opts": ["IDS", "プロキシ", "パケットアナライザ（ワイヤシャーク等）", "ファイアウォール"], "ans": 2, "exp": "パケットアナライザ（スニファ）はネットワーク上のパケットをキャプチャし内容を解析するツール。トラブルシュートや不正監視に使用。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 327, "q": "マルウェアに感染したコンピュータが外部の指令サーバから命令を受けて攻撃に加担するネットワークをどれか。", "opts": ["ボットネット", "TORネットワーク", "CDN", "P2Pネットワーク"], "ans": 0, "exp": "ボットネットはマルウェア感染PC（ボット）をC&C（コマンド&コントロール）サーバで統制。DDoS攻撃・スパム送信等に悪用される。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 328, "q": "HTTPS通信でサーバ・ブラウザ間の暗号化に使われる，公開鍵と共通鍵を組み合わせたプロトコルはどれか。", "opts": ["SSH", "S/MIME", "IPsec", "TLS（SSL）"], "ans": 3, "exp": "TLS（Transport Layer Security）はHTTPS等に使用。公開鍵で共通鍵を交換後，共通鍵暗号で通信を暗号化するハイブリッド暗号方式。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 329, "q": "リレーショナルデータベースのビュー（View）の説明として最も適切なものはどれか。", "opts": ["物理的に存在する別テーブルにデータをコピーする", "テーブルの物理的なバックアップ", "インデックスの一種", "SELECT文の結果を仮想テーブルとして定義し，参照を簡単にする"], "ans": 3, "exp": "ビュー（仮想テーブル）はSELECT文を元に定義した仮想的なテーブル。データは持たず，参照のたびにSELECTが実行される。アクセス制御・複雑クエリ簡略化に活用。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 330, "q": "結合処理（JOIN）のうち，両テーブルに一致するレコードだけを取得するJOINはどれか。", "opts": ["RIGHT JOIN", "INNER JOIN", "LEFT JOIN", "FULL OUTER JOIN"], "ans": 1, "exp": "INNER JOINは両テーブルの結合キーが一致するレコードだけを取得。LEFT JOINは左テーブルの全件＋一致する右側を取得。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 331, "q": "情報量の単位で，1バイトは何ビットか。", "opts": ["32ビット", "4ビット", "16ビット", "8ビット"], "ans": 3, "exp": "1バイト＝8ビット。1ニブル＝4ビット，1ワード（32bit CPU）＝32ビット＝4バイト。", "cat": "テクノロジ", "diff": "easy", "year": 2022}, {"id": 332, "q": "FLOPSの説明として正しいものはどれか。", "opts": ["ネットワーク転送速度の単位", "HDDの読み込み速度", "1秒あたりの浮動小数点演算回数", "メモリのアクセス速度"], "ans": 2, "exp": "FLOPS（Floating-point Operations Per Second）はAI・科学技術計算で使われる浮動小数点演算速度の単位。GPUは数テラFLOPS以上を実現。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 333, "q": "画像認識・音声認識・自然言語処理で革命をもたらした，多層のニューラルネットワークを用いる学習手法はどれか。", "opts": ["ディープラーニング", "線形回帰", "サポートベクターマシン", "ベイズ推定"], "ans": 0, "exp": "ディープラーニングは多層（ディープ）なニューラルネットワークで特徴を自動抽出。畳み込み層を使ったCNNが画像認識で圧倒的性能。", "cat": "テクノロジ", "diff": "easy", "year": 2022}, {"id": 334, "q": "強化学習の説明として最も適切なものはどれか。", "opts": ["正解ラベルのある学習データで予測モデルを作成する", "データのパターンを正解なしで発見する", "複数のモデルを組み合わせて精度を上げる", "エージェントが環境と相互作用し，報酬最大化を学習する"], "ans": 3, "exp": "強化学習はエージェントが行動→環境から報酬→価値関数を更新を繰り返して最適方策を学習。ゲーム・ロボット制御等に使用。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 335, "q": "データサイエンスで，学習データとテストデータを複数回分割して汎化性能を評価する手法はどれか。", "opts": ["k分割交差検証", "バギング", "ホールドアウト法", "ブートストラップ法"], "ans": 0, "exp": "k-fold Cross Validationはデータをk分割し，1つをテスト・残りを学習に使う評価を k回繰り返し，平均性能を汎化性能の推定値とする手法。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 336, "q": "通常の2値論理（0か1）ではなく，量子ビットで計算し特定問題を超高速で解く技術はどれか。", "opts": ["エッジコンピューティング", "GPU並列処理", "ニューラルプロセッシングユニット", "量子コンピュータ"], "ans": 3, "exp": "量子コンピュータは量子ビット（0と1の重ね合わせ状態）を使い，素因数分解・組合せ最適化等で指数的高速化が期待される技術。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 337, "q": "エッジコンピューティングの説明として最も適切なものはどれか。", "opts": ["ブロックチェーンで分散処理する", "データ発生源の近くでリアルタイム処理し，遅延を最小化する", "クラウドに全てのデータを送って処理する", "中央の大型コンピュータで処理する"], "ans": 1, "exp": "エッジコンピューティングはIoTデバイスなどデータ発生源の近くで処理。ネットワーク遅延・帯域節約・プライバシー保護に有効。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 338, "q": "アプリケーションの機能を部品化し，APIで連携させる軽量なアーキテクチャはどれか。", "opts": ["マイクロサービスアーキテクチャ", "モノリシックアーキテクチャ", "SOA", "クライアントサーバモデル"], "ans": 0, "exp": "マイクロサービスアーキテクチャはアプリを独立した小さなサービスに分割，API連携。独立デプロイ・スケーリングが可能。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 339, "q": "プログラムのテストで，全ての条件分岐の真偽を少なくとも1回は実行するカバレッジ基準はどれか。", "opts": ["分岐網羅（C1）", "命令網羅（CO）", "条件網羅（C2）", "パス網羅"], "ans": 0, "exp": "分岐網羅（C1カバレッジ）は全ての条件分岐でTrueとFalseの両方を少なくとも1回テストする基準。命令網羅（C0）より厳しい。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 340, "q": "プログラム言語のコンパイラとインタプリタの違いとして正しいものはどれか。", "opts": ["両者に性能差はない", "コンパイラはWebシステム専用，インタプリタはOS専用", "コンパイラは一括して機械語に変換，インタプリタは逐次解釈実行", "コンパイラは行ごとに解釈実行，インタプリタは一括機械語変換"], "ans": 2, "exp": "コンパイラは実行前にソース全体を機械語に変換（C言語等）。インタプリタは実行時に逐次解釈（Python等）。コンパイラは実行速度が速い。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 341, "q": "情報セキュリティの「完全性」を損なう事象として最も適切なものはどれか。", "opts": ["システムの遅延", "サービス停止", "不正なデータの書き換え", "機密データの漏洩"], "ans": 2, "exp": "完全性（Integrity）はデータが正確かつ完全であること。不正改ざん・誤記・削除が完全性の損失。機密性はデータ漏洩，可用性はサービス停止。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 342, "q": "インターネット上で匿名性を高め，通信経路を秘匿するために多数のノードで暗号化・中継する技術はどれか。", "opts": ["SSH", "プロキシ", "VPN", "TOR（Onion Routing）"], "ans": 3, "exp": "TOR（The Onion Router）は暗号化した通信を複数のリレーノードで多段中継し，送信元を隠匿するプライバシー保護技術。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 343, "q": "OSのプロセス管理で，CPU時間を小さく分割して複数プロセスを交互に実行する方式はどれか。", "opts": ["リアルタイム処理", "マルチプロセッシング", "バッチ処理", "タイムシェアリング（時分割処理）"], "ans": 3, "exp": "タイムシェアリングはCPU時間をタイムスライスに分割し，複数ユーザー・プロセスを擬似同時実行する方式。現代OSの基本。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 344, "q": "データの整合性確認に用いるチェックサムの説明として正しいものはどれか。", "opts": ["デジタル署名の一種", "データのビット列に対して計算した検証値", "データを暗号化する技術", "データ圧縮アルゴリズム"], "ans": 1, "exp": "チェックサムはデータのビット列から計算した検証値。転送・保存後に再計算して一致を確認することでデータ完全性を検証する。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 345, "q": "クラウドサービスの冗長化構成で，主サーバ障害時に自動的に予備サーバに切り替わる仕組みはどれか。", "opts": ["コールドスタンバイ", "ホットスタンバイ", "フェールオーバー", "ロードバランシング"], "ans": 2, "exp": "フェールオーバーは主系の障害を検知して自動的に副系（スタンバイ）に切り替え，サービスを継続する仕組み。高可用性の基本技術。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 346, "q": "IoTの説明として最も適切なものはどれか。", "opts": ["人工知能によるロボット制御技術", "様々なモノをインターネットに接続しデータを収集・活用する仕組み", "仮想通貨の取引技術", "インターネット上での大量データ処理"], "ans": 1, "exp": "IoT（Internet of Things）は家電・センサ・車等の「モノ」をインターネットに接続し，データ収集・遠隔制御・自動化を実現する技術。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 347, "q": "ビッグデータの分析で，過去のデータから傾向を発見して将来を予測する分析はどれか。", "opts": ["規範的分析", "記述的分析", "診断的分析", "予測的分析"], "ans": 3, "exp": "予測的分析（Predictive Analytics）は過去データのパターンから将来の結果を予測する分析。機械学習・統計モデルを活用。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 348, "q": "人工知能の一つで，人間の脳神経回路を模した計算モデルを何というか。", "opts": ["遺伝的アルゴリズム", "ファジィ理論", "ニューラルネットワーク", "エキスパートシステム"], "ans": 2, "exp": "ニューラルネットワークは人間の神経回路（ニューロン間のシナプス）を模した数学モデル。入力層・隠れ層・出力層で構成。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 349, "q": "多数のサービスをクラウドで組み合わせて新しいサービスを提供するプラットフォームモデルはどれか。", "opts": ["APIエコノミー", "SaaS", "ASP", "IaaS"], "ans": 0, "exp": "APIエコノミーはAPIを公開・利用して異サービスを組み合わせ，新たな価値を生み出すエコシステム。金融・物流等で活発。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 350, "q": "リモートワーク環境でのセキュリティ対策として，社員の端末にソフトウェアをインストールせずWebブラウザだけで業務する方式はどれか。", "opts": ["VDI", "MDM", "BYOD", "シンクライアント"], "ans": 0, "exp": "VDI（Virtual Desktop Infrastructure）はサーバ側で仮想デスクトップを動かし，端末はブラウザ等で表示するみでアクセスする方式。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 351, "q": "医療分野でAIを活用する事例として最も適切なものはどれか。", "opts": ["AIによる画像診断支援（レントゲン・CT異常検出）", "病院の受付事務", "薬剤の在庫管理", "電子カルテシステムの管理"], "ans": 0, "exp": "AIの医療画像診断支援は放射線画像・眼底写真等の異常を高精度で検出。専門医不足の補完や見落とし防止に活用されている。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 352, "q": "オープンデータの活用により実現できるメリットとして最も適切なものはどれか。", "opts": ["データ取得コストが増える", "透明性の向上と第三者による新サービス創出", "個人情報が守られる", "データのセキュリティが向上する"], "ans": 1, "exp": "オープンデータは行政・研究データの公開で，透明性向上・外部開発者による新サービス創出・研究促進等のメリットがある。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 353, "q": "企業が顧客満足度を測るシンプルな質問「他社・他者に薦めたいか（0〜10点）」で測定するスコアはどれか。", "opts": ["CES", "CSAT", "NPS（ネットプロモータースコア）", "CS指数"], "ans": 2, "exp": "NPS（Net Promoter Score）は「このサービスを他者に薦めたいか（0〜10）」の一問で忠誠度を測る。推奨者%－批判者%。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 354, "q": "フランチャイズ契約の特徴として最も適切なものはどれか。", "opts": ["加盟店は本部のブランド・ノウハウを使う代わりに対価を支払い，本部のサポートを受ける", "本部と加盟店は資本関係がある", "加盟店は本部に雇われた従業員の関係", "加盟店は本部の商号・ノウハウを使えるが独立した経営判断は禁止"], "ans": 0, "exp": "フランチャイズは本部（フランチャイザー）がブランド・ノウハウを加盟店（フランチャイジー）に提供し，ロイヤリティを受取る仕組み。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 355, "q": "自社の事業活動に関わる多数の利害関係者（ステークホルダー）として含まれないものはどれか。", "opts": ["株主", "競合他社", "従業員", "地域社会"], "ans": 1, "exp": "ステークホルダーは株主・顧客・従業員・取引先・地域社会・政府等の利害関係者。競合他社は直接の利害関係者ではなく含まない。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 356, "q": "テレワーク導入によりオフィスにいる全員が固定席を持たず，空いた席を自由に使う制度はどれか。", "opts": ["サテライトオフィス", "フリーアドレス", "在宅勤務", "フレックスタイム"], "ans": 1, "exp": "フリーアドレスは固定席を廃止し，出社者が自由に席を選んで使うオフィス形態。テレワーク普及で有効活用が進む。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 357, "q": "個人情報保護法に規定する「個人情報」として正しいものはどれか。", "opts": ["統計情報", "生存する個人を特定できる氏名・住所等の情報", "企業の財務情報", "匿名加工情報"], "ans": 1, "exp": "個人情報とは生存する個人に関する情報で，氏名・生年月日等により特定の個人を識別できるもの（個人情報保護法第2条）。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 358, "q": "消費者保護を目的に，通信販売の購入者が一定期間内に理由なく申し込みを撤回・解除できる制度はどれか。", "opts": ["返品制度", "保証制度", "リコール制度", "クーリングオフ"], "ans": 3, "exp": "クーリングオフは特定商取引法の制度。訪問販売・電話勧誘等で一定期間（8日等）内は書面で無条件に契約解除できる。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 359, "q": "会社を解散せず組織の一部を分離して新会社を設立する手法はどれか。", "opts": ["IPO", "MBO", "会社分割（スピンオフ）", "M&A"], "ans": 2, "exp": "スピンオフ（会社分割）は事業の一部を分離して独立した新会社を設立する手法。特定事業への集中・価値顕在化が目的。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 360, "q": "経営陣が自社株式を取得して独立する手法として最も適切なものはどれか。", "opts": ["MBO（マネジメントバイアウト）", "IPO", "TOB（株式公開買い付け）", "LBO（レバレッジバイアウト）"], "ans": 0, "exp": "MBO（Management Buyout）は経営陣が銀行借入等を活用して自社株を買い取り，オーナーとして独立する企業買収手法。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 361, "q": "電子契約や電子署名において，契約の成立時刻を第三者が証明するサービスはどれか。", "opts": ["デジタルフォレンジックス", "電子認証", "タイムスタンプ", "電子公証"], "ans": 2, "exp": "タイムスタンプ（時刻認証）は電子データが特定の時刻に存在したこと・その後改ざんされていないことを第三者が証明するサービス。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 362, "q": "サービス利用料が月次・年次で定額となるビジネスモデルはどれか。", "opts": ["従量課金", "フリーミアム", "サブスクリプション", "シェアリング"], "ans": 2, "exp": "サブスクリプションは一定期間の利用権を定額で提供するビジネスモデル（Netflix・Spotify等）。継続収益（MRR）を安定化できる。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 363, "q": "新製品を市場に最初に投入した先発企業が獲得する優位性をどれか。", "opts": ["差別化優位", "コスト優位", "規模の経済", "先発優位（ファーストムーバーアドバンテージ）"], "ans": 3, "exp": "先発優位はブランド認知・顧客獲得・特許・スケール等の点で先行者が享受できる優位性。一方でリスクと開拓コストも高い。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 364, "q": "工場などの製造業で自動化・ロボット化・AIを活用した生産形態を何というか。", "opts": ["スマートファクトリー", "アジャイル生産", "ライン生産", "セル生産"], "ans": 0, "exp": "スマートファクトリーはIoT・AI・ロボット・ビッグデータを活用して製造プロセスを自動化・最適化した次世代工場。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 365, "q": "環境・社会・ガバナンスの観点から企業のリスクと機会を財務情報として開示を求めるフレームワークはどれか。", "opts": ["統合報告書", "TCFD（気候関連財務情報開示タスクフォース）", "ISO 14001", "GRI基準"], "ans": 1, "exp": "TCFDは気候変動リスクを財務情報として開示するフレームワーク。企業のガバナンス・戦略・リスク管理・指標目標の開示を推奨。", "cat": "ストラテジ", "diff": "hard", "year": 2021}, {"id": 366, "q": "Webサービスの収益モデルとして，第三者への広告掲載スペースを提供して収益を得るモデルはどれか。", "opts": ["EC", "サブスクリプション", "広告モデル", "フリーミアム"], "ans": 2, "exp": "広告モデルはユーザーに無料でサービス提供し，広告主から広告費を受け取って収益化するビジネスモデル（Google, YouTube等）。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 367, "q": "ある月の売上が計画比+20%，利益が計画比-10%の場合，考えられる原因として最も適切なものはどれか。", "opts": ["価格が上昇した", "コストが増加して利益率が低下した", "販売数量が予定を下回った", "製造効率が改善した"], "ans": 1, "exp": "売上は増えたが利益が減ったということは，原価・経費等のコストが計画以上に増えて利益率が低下したと考えられる。", "cat": "ストラテジ", "diff": "hard", "year": 2021}, {"id": 368, "q": "行政手続きのデジタル化推進において，紙書類への押印を廃止しデジタル手続きを原則とする原則はどれか。", "opts": ["デジタルファースト", "ペーパーレス化", "電子政府", "DX戦略"], "ans": 0, "exp": "デジタルファーストは2019年のデジタル手続法等で示された原則。行政手続きを紙→デジタル，対面→オンラインを原則とする。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 369, "q": "健康診断や医療記録を電子的に管理し，複数医療機関で共有する仕組みはどれか。", "opts": ["EHR（電子健康記録）", "PACS", "HIS", "PHR（個人健康記録）"], "ans": 0, "exp": "EHR（Electronic Health Record）は複数の医療機関が共有できる電子的な医療記録。PHRは個人が主体的に管理する健康情報。", "cat": "ストラテジ", "diff": "hard", "year": 2021}, {"id": 370, "q": "コンテンツやサービスの利用者が少数のロングテール（長い尾）部分でも収益を上げられるビジネスモデルはどれか。", "opts": ["ブロックバスター戦略", "ニッチ戦略", "ロングテール戦略", "マスマーケティング"], "ans": 2, "exp": "ロングテール戦略はAmazon等が体現。インターネットを活用し，需要の少ない多品種商品の集積でも大きな収益を得るモデル。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 371, "q": "会計上の費用のうち，現金支出を伴わない費用として計上する項目はどれか。", "opts": ["仕入費用", "広告宣伝費", "人件費", "減価償却費"], "ans": 3, "exp": "減価償却費は固定資産の取得コストを耐用年数にわたって費用配分する会計処理。現金は取得時に支出済みで，期間配分時は非現金支出。", "cat": "ストラテジ", "diff": "hard", "year": 2021}, {"id": 372, "q": "AIを活用したチャットボットの主要な技術として，ユーザーの意図を理解する部分を何というか。", "opts": ["OCR", "TTS（音声合成）", "画像認識", "自然言語理解（NLU）"], "ans": 3, "exp": "NLU（Natural Language Understanding）はユーザーの入力テキストの意図（インテント）を理解する技術。チャットボットの核となる部分。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 373, "q": "複数の指標を組み合わせて企業の総合的な健全性を評価するレーティングを行うのはどれか。", "opts": ["内部監査", "会計監査人", "格付け機関（信用格付け）", "証券アナリスト"], "ans": 2, "exp": "格付け機関（S&P, Moody's等）は企業・国の信用力を評価したレーティングを発表。投資家が債券投資の判断に活用する。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 374, "q": "AI技術の一つで，画像を生成・加工する際に本物らしい偽画像・動画を作成する技術をどれか。", "opts": ["GAN（生成的敵対ネットワーク）", "RNN", "自己符号化器", "CNN"], "ans": 0, "exp": "GAN（Generative Adversarial Network）は生成器と識別器が競い合いながら学習するモデル。ディープフェイク等のリアルな画像生成に使用。", "cat": "ストラテジ", "diff": "hard", "year": 2021}, {"id": 375, "q": "会社組織で取締役会・監査役・株主総会の相互牽制により経営の透明性・公正性を確保する仕組みはどれか。", "opts": ["コーポレートガバナンス", "リスクマネジメント", "コンプライアンス", "CSR"], "ans": 0, "exp": "コーポレートガバナンスは取締役会・監査役・株主等が相互に監視・牽制し，経営の透明性・健全性・説明責任を確保する仕組み。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 376, "q": "クラウドサービスの利用者側が管理・設定する部分はどれか（IaaSの場合）。", "opts": ["ネットワーク機器", "データセンター空調", "物理的なサーバ機器", "OS・ミドルウェア・アプリケーション"], "ans": 3, "exp": "IaaSでは仮想ハードウェア（CPU・メモリ・ストレージ）をクラウドが提供。利用者はOSから上（ミドル・アプリ等）を管理する。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 377, "q": "企業のSNS活用で，投稿内容が炎上した際に優先すべき対応はどれか。", "opts": ["問題の投稿を即削除して黙っている", "別のSNSに移行する", "問題のある投稿者を特定して処罰する", "事実確認の上，誠実に状況を説明・謝罪し再発防止策を公表する"], "ans": 3, "exp": "SNS炎上対応は事実確認→迅速かつ誠実な情報開示→謝罪→再発防止策の順が基本。隠蔽・沈黙は炎上を拡大させることが多い。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 378, "q": "農業分野でIoT・AIを活用し，作物の生育状況・気象データを分析して最適な栽培管理を行う農業をどれか。", "opts": ["アグリテック（スマート農業）", "有機農業", "水耕栽培", "大規模農業"], "ans": 0, "exp": "スマート農業（アグリテック）はIoTセンサ・ドローン・AIで栽培管理を自動化・最適化し，農業人手不足と生産性向上を解決する。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 379, "q": "モバイル決済・仮想通貨・クラウド会計など金融とITを融合した産業・技術の総称はどれか。", "opts": ["PayTech", "InsurTech", "RegTech", "FinTech"], "ans": 3, "exp": "FinTech（Financial Technology）は金融とテクノロジーを融合した新しい金融サービスの総称。モバイル決済・AI投資等が代表例。", "cat": "ストラテジ", "diff": "easy", "year": 2021}, {"id": 380, "q": "ハードウェア製品を購入せず，必要な期間だけ借り受けて利用料を支払う調達方法はどれか。", "opts": ["リース", "サブスクリプション", "レンタル", "分割購入"], "ans": 2, "exp": "レンタルは月単位等の短期契約で随時解約可能。リースは長期（3〜7年）固定契約で中途解約困難。コストはレンタルが割高だが柔軟性が高い。", "cat": "ストラテジ", "diff": "mid", "year": 2021}, {"id": 381, "q": "プロジェクトマネジメントで，プロジェクトの終了時に実施する教訓・ベストプラクティスを文書化する活動はどれか。", "opts": ["プロジェクト終結（教訓収集）", "プロジェクト憲章作成", "キックオフミーティング", "リスクアセスメント"], "ans": 0, "exp": "プロジェクト終結フェーズでは教訓（Lessons Learned）を文書化し，次プロジェクトへの知識移転と組織ナレッジ蓄積を行う。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 382, "q": "テスト戦略において，ブラックボックステストの説明として最も適切なものはどれか。", "opts": ["内部構造を把握してコードパスを検証する", "内部構造を考慮せず入出力のみでテストする", "メモリの使用状況をテストする", "コードカバレッジを測定する"], "ans": 1, "exp": "ブラックボックステストは内部実装を知らずに入力→期待出力を検証する手法。同値分割・境界値分析が代表的な技法。", "cat": "マネジメント", "diff": "easy", "year": 2021}, {"id": 383, "q": "ホワイトボックステストの説明として最も適切なものはどれか。", "opts": ["本番データを使った検証", "セキュリティの脆弱性を探す", "利用者視点で機能の入出力のみ検証", "内部構造（コード）を把握して，全命令・分岐を網羅するテスト"], "ans": 3, "exp": "ホワイトボックステストは内部ロジック・コードを把握してカバレッジ基準（命令・分岐等）を満たすようテストを設計する手法。", "cat": "マネジメント", "diff": "easy", "year": 2021}, {"id": 384, "q": "プロジェクトの品質管理計画に含める内容として最も適切なものはどれか。", "opts": ["品質の定義・測定指標・品質保証・品質管理の計画", "プロジェクトの予算", "顧客への請求方法", "チームメンバーの経歴"], "ans": 0, "exp": "品質管理計画には品質の基準・測定方法・QAとQCの活動・成果物の受入基準等を定める。PMBOKの品質マネジメント計画。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 385, "q": "ITILのサービスライフサイクルの段階のうち，新しいサービスや変更サービスを本番移行する段階はどれか。", "opts": ["サービスストラテジ", "サービスオペレーション", "サービスデザイン", "サービストランジション"], "ans": 3, "exp": "サービストランジション（移行）はサービスのビルド・テスト・本番移行を担当するライフサイクル段階。変更管理・リリース管理が中心。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 386, "q": "作業管理ツールのカンバンボードで「To Do / In Progress / Done」の列でタスクを管理するアジャイルプラクティスはどれか。", "opts": ["カンバン（Kanban）", "スクラム", "スプリントプランニング", "XP（エクストリームプログラミング）"], "ans": 0, "exp": "カンバンはトヨタ生産方式に由来するアジャイルフレームワーク。ボード上のカード移動でタスクの流れを可視化しWIPを制限する。", "cat": "マネジメント", "diff": "easy", "year": 2021}, {"id": 387, "q": "プロジェクトのコミュニケーション管理計画で考慮すべき事項として最も適切なものはどれか。", "opts": ["コードの設計方針", "誰に何を，いつ，どの手段で伝えるかの計画", "予算計画", "テスト結果"], "ans": 1, "exp": "コミュニケーション管理計画はステークホルダーに必要な情報を適切なタイミング・手段・頻度で届けるための計画。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 388, "q": "システム開発のフェーズで，作成した設計を元に実際のプログラムコードを記述する工程はどれか。", "opts": ["要件定義", "実装（コーディング）", "概要設計", "テスト"], "ans": 1, "exp": "実装（コーディング）は詳細設計に基づいてプログラマが実際のソースコードを記述する工程。コードレビューも含む。", "cat": "マネジメント", "diff": "easy", "year": 2021}, {"id": 389, "q": "サービスマネジメントで，計画外の停止や品質低下を「インシデント」と定義したとき，インシデント発生を記録する最初のステップはどれか。", "opts": ["解決", "エスカレーション", "診断", "登録（ロギング）"], "ans": 3, "exp": "インシデント管理のフロー：検出→登録→分類→優先度付け→診断→解決→終了。最初のステップは必ず登録（ロギング）。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 390, "q": "プロジェクトで見積もった予算より実際のコストが少なく，予定より多くの成果を達成しているとき，EVMでのCPIとSPIの状態はどれか。", "opts": ["CPI<1，SPI<1", "CPI<1，SPI>1", "CPI>1，SPI>1", "CPI>1，SPI<1"], "ans": 2, "exp": "コスト節約（CPI>1）かつスケジュール前倒し（SPI>1）の状態。CPI=EV/AC>1はコスト節減，SPI=EV/PV>1は進捗良好。", "cat": "マネジメント", "diff": "hard", "year": 2021}, {"id": 391, "q": "品質管理で，特性要因図（フィッシュボーン図）の用途として最も適切なものはどれか。", "opts": ["作業の流れを図解する", "データの分布を可視化する", "問題の発生件数をグラフ化する", "問題の原因と結果の関係を魚の骨型で整理する"], "ans": 3, "exp": "特性要因図（石川図・フィッシュボーン図）は問題（結果）の原因を「人・機械・材料・方法・環境」等の骨として整理する品質管理ツール。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 392, "q": "システム移行で，新旧システムを一定期間並行稼働させてから切り替える方式の最大のデメリットはどれか。", "opts": ["段階的移行ができない", "ユーザーへの影響が大きい", "並行稼働中のコスト・運用負担が大きい", "移行失敗時に旧システムへ戻せない"], "ans": 2, "exp": "並行稼働は安全性が高いが，新旧両システムを同時稼働するため運用コスト・人的負担が最も大きいデメリットがある。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 393, "q": "ITサービスマネジメントにおいて，既知の問題（Known Error）を記録・管理するデータベースはどれか。", "opts": ["ITSM", "CMDB", "SLA", "KEDB"], "ans": 3, "exp": "KEDB（Known Error Database）は既知エラーとその回避策・解決策を記録するデータベース。インシデント解決の効率化に使用。", "cat": "マネジメント", "diff": "hard", "year": 2021}, {"id": 394, "q": "情報システム戦略において，情報化投資の方向性を示す上位の計画はどれか。", "opts": ["システム化計画", "個別開発計画", "テスト計画", "情報化戦略計画"], "ans": 3, "exp": "情報化戦略計画は経営戦略に基づき，組織全体のIT活用方針・優先順位・投資計画を定める上位計画。個別システム計画はその下位。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 395, "q": "アジャイル開発でスプリントごとにチームの生産量（完了ストーリーポイント数）を計測する指標はどれか。", "opts": ["スループット", "リードタイム", "ベロシティ", "バーンダウン"], "ans": 2, "exp": "ベロシティはスプリントごとにチームが完了するストーリーポイントの平均値。次スプリントの計画基準として使用。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 396, "q": "不正のトライアングルにおける「機会」を排除する対策として最も効果的なものはどれか。", "opts": ["アクセス権限の適切な設定と監視ログの取得", "従業員の給与を上げる", "業務の意義を社員に伝える", "経営理念を掲示する"], "ans": 0, "exp": "不正トライアングルの「機会」排除にはアクセス制限・権限分離・ログ監視等の物理的・技術的管理が最も効果的。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 397, "q": "システム開発で，発見したバグを修正した結果，別の個所に新たなバグが生じることを何というか。", "opts": ["リファクタリング", "リリース", "デグレード（デグレッション）", "デプロイ"], "ans": 2, "exp": "デグレード（デグレッション）は修正・変更によって以前は正常動作していた部分に新たな不具合が生じること。リグレッションテストで防止。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 398, "q": "ITサービスマネジメントでリリース管理の目的として最も適切なものはどれか。", "opts": ["インシデントの根本原因を除去する", "ユーザーからの問い合わせに対応する", "SLAの遵守状況を確認する", "サービス変更を安全かつ確実に本番環境に移行する"], "ans": 3, "exp": "リリース管理は変更されたサービス・システムをビルド・テストして安全に本番環境にデプロイ（リリース）する管理活動。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 399, "q": "プロジェクトの品質管理で，工程終了の可否を判断するための審査を何というか。", "opts": ["QC（品質管理）", "スプリントレビュー", "コードレビュー", "フェーズゲートレビュー"], "ans": 3, "exp": "フェーズゲートレビュー（ステージゲート）は各開発フェーズの終了時に成果物の品質・完了基準を審査し，次フェーズへの移行可否を決定。", "cat": "マネジメント", "diff": "mid", "year": 2021}, {"id": 400, "q": "ITガバナンスフレームワークの一つで，ITプロセスを34のコントロール目標に体系化したものはどれか。", "opts": ["ISO 27001", "ITIL", "COBIT", "PMBOK"], "ans": 2, "exp": "COBIT（Control Objectives for Information and Related Technology）はITガバナンスのフレームワーク。経営目標とITプロセスを体系的に連結。", "cat": "マネジメント", "diff": "hard", "year": 2021}, {"id": 401, "q": "Wi-Fiのセキュリティで，WEPよりも強固な暗号化方式を採用した規格はどれか。", "opts": ["WPA2", "WEP", "WPA3", "WPA"], "ans": 0, "exp": "WPA2はAES暗号を採用しWEP（RC4）より安全。最新はWPA3でさらに強固。WEPは脆弱性が発覚し現在推奨されない。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 402, "q": "SMTP認証（SMTP-AUTH）の目的として最も適切なものはどれか。", "opts": ["大容量ファイルを送信する", "メールを暗号化する", "メールの遅延を防ぐ", "送信者がSMTPサーバに認証し，スパム送信を防止する"], "ans": 3, "exp": "SMTP認証はメール送信時にユーザーIDとパスワードで認証し，不正なメール中継（スパム送信）を防止するセキュリティ機能。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 403, "q": "クラウドサービスのうち，インフラ管理は不要でコードをデプロイするだけでアプリを実行できる形態はどれか。", "opts": ["PaaS", "IaaS", "FaaS（Functions as a Service）", "SaaS"], "ans": 2, "exp": "FaaSは関数単位でコードをデプロイし，イベント発生時のみ実行・課金するサーバレスアーキテクチャ（AWS Lambda等）。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 404, "q": "Webシステムで，ファイルパスを細工することでサーバの非公開ディレクトリにアクセスする攻撃はどれか。", "opts": ["CSRF", "SQLインジェクション", "XSS", "ディレクトリトラバーサル"], "ans": 3, "exp": "ディレクトリトラバーサルは「../../../etc/passwd」のようにパスを遡ってサーバの重要ファイルに不正アクセスする攻撃。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 405, "q": "電子メールが正規のサーバから送信されたかを送信元IPアドレスのDNSレコードで検証するメール認証技術はどれか。", "opts": ["SPF（Sender Policy Framework）", "DMARC", "S/MIME", "DKIM"], "ans": 0, "exp": "SPFはDNSに正規の送信メールサーバIPアドレスを登録し，受信側がIPアドレスと突合することで送信元ドメインのなりすましを検知。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 406, "q": "Webサービスで使われる，アクセストークンを使った権限委譲の標準プロトコルはどれか。", "opts": ["OAuth 2.0", "OpenID", "SAML", "LDAP"], "ans": 0, "exp": "OAuth 2.0はアクセストークンを使いリソースへの限定的なアクセス権を安全に委譲するプロトコル。SNSログインの裏側で使用。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 407, "q": "IPv4アドレスの枯渇対応として一般的なプライベートアドレスをグローバルアドレスに変換する技術はどれか。", "opts": ["VPN", "DNS", "DHCP", "NAT/NAPT"], "ans": 3, "exp": "NAT（Network Address Translation）/NAPT（IPマスカレード）は複数台のプライベートIPを1つのグローバルIPに変換する技術。IPv4節約に貢献。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 408, "q": "機械学習でデータの次元数を減らし，可視化や計算効率向上を図る技法はどれか。", "opts": ["回帰分析", "次元削減（PCA等）", "クラスタリング", "アンサンブル学習"], "ans": 1, "exp": "主成分分析（PCA）等の次元削減技術は多変量データの情報を保持しながら変数数を圧縮する。可視化・ノイズ除去・高速化に活用。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 409, "q": "センサが0.01秒ごとにデータを送信するとき，1時間に送られるデータ数はいくらか。", "opts": ["360", "36,000", "360,000", "3,600"], "ans": 2, "exp": "1秒=100回，1分=6,000回，1時間=360,000回。0.01秒間隔=100回/秒×3600秒=360,000。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 410, "q": "OS管理のうちプロセスが競合してリソースを奪い合い，互いが永遠に待ち続ける問題を何というか。", "opts": ["デッドロック", "スラッシング", "フラグメンテーション", "ページフォールト"], "ans": 0, "exp": "デッドロックは複数プロセスが互いに相手のリソース解放を待ち，処理が進まなくなる状態。ロック順序の統一・タイムアウト設定で防止。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 411, "q": "フローチャートにおいて，条件の真偽で処理を分岐するときに使う記号はどれか。", "opts": ["ひし形", "楕円", "矢印", "長方形"], "ans": 0, "exp": "フローチャートの記号：長方形=処理，ひし形=判断（条件分岐），楕円=端子（開始・終了），矢印=流れ線。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 412, "q": "浮動小数点数の表現で，指数部を増やすとどうなるか。", "opts": ["精度が上がる", "メモリ使用量が減る", "表現できる数の範囲が広がる", "計算速度が遅くなる"], "ans": 2, "exp": "IEEE 754の浮動小数点数は符号・指数部・仮数部で構成。指数部ビット数増加→表現範囲拡大，仮数部増加→精度向上。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 413, "q": "スマートフォンのNFCを使った決済（タッチ決済）の通信距離として適切なものはどれか。", "opts": ["10m以内", "10cm以内", "1km以内", "100m以内"], "ans": 1, "exp": "NFC（Near Field Communication）は数cm（一般的に10cm以内）の至近距離での通信技術。かざすだけで決済・改札通過が可能。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 414, "q": "不正アクセスに関する問題解決後に行う，再発防止のための根本原因分析を何というか。", "opts": ["ハードニング", "インシデント対応", "フォレンジクス", "ポストモーテム（事後分析）"], "ans": 3, "exp": "ポストモーテム（Post-mortem）はインシデント後に根本原因・影響範囲・改善策を体系的に分析する振り返り活動。Google等が普及させた手法。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 415, "q": "データの保管・処理において，機密データを暗号化したまま計算できる暗号技術はどれか。", "opts": ["準同型暗号", "ストリーム暗号", "ブロック暗号", "ハッシュ関数"], "ans": 0, "exp": "準同型暗号は暗号化データのまま計算を行い，復号なしに計算結果を得られる技術。プライバシー保護AI等への応用が研究されている。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 416, "q": "ディスク書き込みをキャッシュして後で非同期に書き込む方式で，障害時のデータ損失リスクがある技術はどれか。", "opts": ["ライトアラウンド", "ライトバック", "RAID 1", "ライトスルー"], "ans": 1, "exp": "ライトバック（Write-Back）はキャッシュに書いて後でディスクに書き込む方式。高速だが電源断等でキャッシュが消えるとデータ損失リスクがある。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 417, "q": "AIの誤認識を引き起こすため，人間には見えないノイズを画像に加える攻撃手法はどれか。", "opts": ["モデル抽出攻撃", "ポイズニング攻撃", "敵対的サンプル（アドバーサリアルサンプル）", "プロンプトインジェクション"], "ans": 2, "exp": "敵対的サンプルは人間に知覚できない微細なノイズを付加した画像で，AIの分類モデルを意図的に誤動作させる攻撃技術。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 418, "q": "関係データベースでGROUP BY句の用途として正しいものはどれか。", "opts": ["指定した列でデータをグループ化し，集計関数を適用する", "テーブルを結合する", "新しいテーブルを作成する", "データを昇順・降順に並べる"], "ans": 0, "exp": "GROUP BY句は指定した列の同一値ごとにデータをグループ化する。COUNT・SUM・AVG等の集計関数と組み合わせて使用。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 419, "q": "プログラムを書かずに視覚的な操作だけでシステムを構築できる開発ツールの総称はどれか。", "opts": ["ローコード/ノーコード開発", "IDE（統合開発環境）", "フレームワーク", "CMS"], "ans": 0, "exp": "ノーコード/ローコード開発ツール（OutSystems, kintone等）はプログラミング不要または最小限でアプリを構築できるツール群。DXを加速させる。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 420, "q": "ファイルシステムにおいて，ファイル名の末尾（ドットの後）でファイル種類を示す部分はどれか。", "opts": ["パス", "拡張子", "パーミッション", "ディレクトリ"], "ans": 1, "exp": "拡張子（Extension）はファイル名の末尾（.txt, .jpg, .pdf等）でファイルの種類・形式を示す。OSがアプリケーション関連付けに利用。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 421, "q": "コンピュータグラフィックスで，3D空間の物体をリアルに描画するための光と影の計算処理を何というか。", "opts": ["レイトレーシング", "モデリング", "ラスタライズ", "テクスチャマッピング"], "ans": 0, "exp": "レイトレーシングは光線の反射・屈折・影をリアルに計算してリアルな画像を生成する手法。GPUの進化でゲーム等でもリアルタイム活用が進む。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 422, "q": "AIが人間の能力を超えて自己改善を続け，技術的・社会的な急激な変化が起きる仮説上の時点はどれか。", "opts": ["シンギュラリティ（技術的特異点）", "ムーアの法則", "ダーウィンの進化論", "メトカーフの法則"], "ans": 0, "exp": "シンギュラリティ（技術的特異点）はレイ・カーツワイルが提唱。AI等の技術が人間の知性を超え，急激に自己改善が進む仮説上の時点。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 423, "q": "クラウドコンピューティングの利点として最も適切なものはどれか。", "opts": ["初期投資なしで必要な分だけITリソースを利用でき，スケールアップ・ダウンが容易", "セキュリティが物理的に管理できる", "自社データセンターの管理が簡単になる", "ベンダーに依存しないシステムが構築できる"], "ans": 0, "exp": "クラウドは従量課金・スケーラビリティ・初期投資不要が主なメリット。物理管理不要で変化への迅速な対応が可能。", "cat": "ストラテジ", "diff": "easy", "year": 2020}, {"id": 424, "q": "FinTechで普及した，銀行等の金融機関がAPIを公開してサードパーティがサービスを開発できるようにする概念はどれか。", "opts": ["仮想通貨", "オープンバンキング", "電子決済", "電子マネー"], "ans": 1, "exp": "オープンバンキングは金融機関が口座情報等のAPIを外部に公開し，フィンテック企業が新サービスを構築できるようにする仕組み。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 425, "q": "Society 5.0が目指す，サイバー空間と物理空間を融合したイメージを最もよく表す事例はどれか。", "opts": ["スマートフォンで地図を見る", "PCでメールを送る", "AIとIoTで農作物の生育をリアルタイムに監視し自動で最適灌漑する", "紙の地図を電子化する"], "ans": 2, "exp": "Society 5.0はサイバーフィジカルシステム（CPS）で現実世界とデジタルが融合。AIとIoTによる農業最適化は典型的なSociety 5.0の事例。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 426, "q": "企業の価値創造の過程を主要活動と支援活動に分解して競争優位の源泉を分析するフレームワークはどれか。", "opts": ["SWOT分析", "5フォース分析", "BCGマトリクス", "バリューチェーン分析"], "ans": 3, "exp": "バリューチェーン（価値連鎖）分析はポーターが提唱。購買物流→製造→出荷→販売→サービスの主活動と支援活動でコスト優位・差別化を分析。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 427, "q": "著作物を作成した時点で著作権が自動的に発生するという原則を何というか。", "opts": ["登録制", "商標登録", "特許制度", "無方式主義"], "ans": 3, "exp": "著作権は無方式主義（ベルヌ条約）により，創作した時点で自動的に発生。特許・商標と異なり登録不要。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 428, "q": "競争戦略論でニッチ戦略を選択する場合，最も適切な状況はどれか。", "opts": ["特定の顧客セグメントや地理的市場に集中して差別化・コスト優位を追求", "市場シェアが最も大きい", "業界全体に向けてコスト最低を目指す", "差別化戦略と同時に展開する"], "ans": 0, "exp": "ニッチ（集中）戦略は特定の市場セグメントに経営資源を集中し，そのセグメントで差別化またはコスト優位を追求するポーターの競争戦略。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 429, "q": "大量生産・一律提供から個々の顧客ニーズに合わせた製品・サービスを大規模に提供する生産方式はどれか。", "opts": ["ライン生産", "セル生産", "JIT生産", "マス・カスタマイゼーション"], "ans": 3, "exp": "マス・カスタマイゼーションは大量生産の効率性と個別カスタマイズを両立させる生産・販売方式。デジタル技術で可能になった。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 430, "q": "小売業でPOSシステムから収集した購買データを分析し，一緒に購入される商品の組み合わせを発見する分析はどれか。", "opts": ["クラスタリング", "バスケット分析（マーケットバスケット分析）", "時系列分析", "回帰分析"], "ans": 1, "exp": "マーケットバスケット分析はPOSデータから「一緒に買われる商品」の組み合わせ（アソシエーションルール）を抽出する分析。陳列・推薦に活用。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 431, "q": "経営環境分析で，自社の強み・弱みと外部の機会・脅威を掛け合わせて4つの戦略を導く手法はどれか。", "opts": ["3C分析", "5フォース分析", "クロスSWOT分析", "PEST分析"], "ans": 2, "exp": "クロスSWOT分析はSWOTの4要素を掛け合わせ，S×O（強みで機会活用）・W×O・S×T・W×Tの4種類の戦略オプションを導く発展手法。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 432, "q": "企業が法令・規制・倫理・社内ルールを遵守することをどれか。", "opts": ["コンプライアンス", "コーポレートガバナンス", "ERM", "CSR"], "ans": 0, "exp": "コンプライアンス（法令遵守）は法律・規制・倫理・社内規程を遵守すること。不正行為防止・企業価値維持の基本。", "cat": "ストラテジ", "diff": "easy", "year": 2020}, {"id": 433, "q": "電子書籍・音楽・映像のデジタルコンテンツに適用される，複製・利用制限技術の総称はどれか。", "opts": ["コピーレフト", "著作権表示", "コンテンツフィルタ", "DRM（デジタル著作権管理）"], "ans": 3, "exp": "DRM（Digital Rights Management）はデジタルコンテンツの不正複製・利用を技術的に防ぐ保護技術。電子書籍・音楽配信で広く使用。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 434, "q": "市場の成長性と自社のシェアから事業ポートフォリオを分析するBCGのPPMで，「問題児」の特徴はどれか。", "opts": ["高成長・高シェア", "低成長・高シェア", "高成長・低シェア", "低成長・低シェア"], "ans": 2, "exp": "PPMの問題児（Problem Child）は成長市場にいるが自社シェアが低い事業。投資か撤退かの判断が必要。将来の花形候補。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 435, "q": "日本のマイナンバー制度で，マイナンバーを利用できる行政分野として定められているものはどれか。", "opts": ["医療・健康情報のみ", "全ての行政手続き", "商取引のみ", "社会保障・税・災害対策"], "ans": 3, "exp": "マイナンバー（個人番号）は法定の3分野（社会保障・税・災害対策）での使用が原則。民間での使用は限定的。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 436, "q": "プロダクトアウトとマーケットインの違いとして正しいものはどれか。", "opts": ["プロダクトアウトは自社技術・製品能力優先，マーケットインは顧客ニーズ優先", "どちらも同じ概念", "プロダクトアウトは新規市場，マーケットインは既存市場", "プロダクトアウトは顧客ニーズ優先，マーケットインは自社技術優先"], "ans": 0, "exp": "プロダクトアウトは「良い製品を作れば売れる」という製造側の論理。マーケットインは「顧客が求めるものを作る」顧客起点の考え方。", "cat": "ストラテジ", "diff": "easy", "year": 2020}, {"id": 437, "q": "ROE（自己資本利益率）の計算式として正しいものはどれか。", "opts": ["ROE = 自己資本÷総資産", "ROE = 総資産÷純利益", "ROE = 売上高÷純利益", "ROE = 純利益÷自己資本"], "ans": 3, "exp": "ROE（Return on Equity）= 当期純利益÷自己資本×100(%)。株主資本に対する収益率を示す。10%以上が優良の目安。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 438, "q": "デジタルマーケティングで，ユーザーがWebサイトに訪問してから目的のアクション（購入等）を完了した割合はどれか。", "opts": ["セッション数", "コンバージョン率", "直帰率", "PV（ページビュー）"], "ans": 1, "exp": "コンバージョン率（CVR）= 購入等の目的達成数÷訪問者数×100。Webマーケティングの重要KPI。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 439, "q": "企業が株主や投資家へ財務情報・経営戦略等を積極的に開示する活動をどれか。", "opts": ["コーポレートガバナンス", "CSR", "PR", "IR（インベスター・リレーションズ）"], "ans": 3, "exp": "IR（Investor Relations）は株主・投資家に対して財務状況・経営方針・リスク情報等を積極開示して信頼関係を築く活動。", "cat": "ストラテジ", "diff": "easy", "year": 2020}, {"id": 440, "q": "大量の構造化・非構造化データを蓄積・統合して分析するデータウェアハウスの目的として最も適切なものはどれか。", "opts": ["経営意思決定支援のためのデータ分析基盤", "個人情報の管理", "Webサーバの負荷分散", "リアルタイムのトランザクション処理"], "ans": 0, "exp": "データウェアハウス（DWH）は複数ソースのデータを統合・蓄積してBIツール等で分析するための基盤。OLTPとは分離して設計される。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 441, "q": "スタートアップが最小限の機能を備えた製品を早期にリリースしてフィードバックを得る製品をどれか。", "opts": ["プロトタイプ", "α版", "MVP（最小実行可能製品）", "PoC"], "ans": 2, "exp": "MVP（Minimum Viable Product）はリーンスタートアップの核心概念。最低限の機能で早期にリリースし，顧客フィードバックで方向を決める。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 442, "q": "企業の経営目標達成のために，財務・顧客・プロセス・学習の4視点でKPIを設定する経営管理手法はどれか。", "opts": ["OKR", "KGI", "MBO", "BSC"], "ans": 3, "exp": "BSC（Balanced Scorecard）はKaplan&Nortonが提唱。財務・顧客・内部プロセス・学習と成長の4視点でKPIを設定して戦略を実行管理。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 443, "q": "AIを使って大量の求職者情報から採用候補者を自動選別するシステムの導入で注意すべき倫理的課題はどれか。", "opts": ["処理速度が不足する", "データ保管容量が増える", "学習データに含まれる偏見がAIの判定に反映される可能性", "コストが高くなる"], "ans": 2, "exp": "AIが過去の採用実績データで学習すると，性別・年齢等の属性に対する歴史的偏見が再現される問題（アルゴリズムバイアス）がある。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 444, "q": "電力消費を抑えてCO2排出削減に貢献するためのITシステムの取り組みを何というか。", "opts": ["GX（グリーントランスフォーメーション）", "省エネ法", "グリーンITとサステナブルIT", "グリーンウォッシング"], "ans": 2, "exp": "グリーンIT・サステナブルITはIT機器・データセンターの電力効率向上，廃熱利用，廃棄物削減等でCO2排出を削減する取り組み。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 445, "q": "プラットフォームビジネスで，サービスの利用者が多いほど他の利用者にとっての価値も増す効果をどれか。", "opts": ["スコープの経済", "ネットワーク外部性", "規模の経済", "学習効果"], "ans": 1, "exp": "ネットワーク外部性（ネットワーク効果）は利用者増加でサービス価値が増大する現象。SNS・通信サービスで顕著。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 446, "q": "クリエイティブコモンズ（CC）ライセンスの説明として最も適切なものはどれか。", "opts": ["著作権を完全に放棄する", "全て無料で使えることを意味する", "著作者が利用条件を指定して作品を公開できるライセンス体系", "商用利用は常に禁止される"], "ans": 2, "exp": "Creative Commons（CC）は著作者が帰属表示・商用利用・改変可否等の条件を組み合わせてライセンスを設定できるツール体系。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 447, "q": "デジタルトランスフォーメーションで組織変革が困難な理由として，既存の成功体験・慣行・組織文化が変化を阻む現象はどれか。", "opts": ["ビジョンの欠如", "レガシー思考", "イノベーターのジレンマ", "デジタルデバイド"], "ans": 2, "exp": "イノベーターのジレンマ（クリステンセン）は既存の成功企業が破壊的イノベーションに対応できず市場を失う現象。DX推進の主要障壁。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 448, "q": "GDPRで規定される「データ保護責任者（DPO）」を任命することが義務付けられる組織はどれか。", "opts": ["大量の個人データを処理する組織や公的機関", "製造業のみ", "全てのEU企業", "小規模企業のみ"], "ans": 0, "exp": "GDPRのDPO（Data Protection Officer）は大量データ処理・公的機関等に任命義務。個人データ保護の実施監督を担う独立した担当者。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 449, "q": "ある製品のライフサイクルで，成熟期の戦略として最も適切なものはどれか。", "opts": ["新技術に全面切り替え", "コスト管理・差別化・市場浸透で維持・収益最大化", "大規模投資で市場開拓", "製品撤退の準備"], "ans": 1, "exp": "製品ライフサイクルの成熟期は競合激化・成長鈍化。コスト低減・バリエーション拡充・顧客維持等で収益最大化を図る時期。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 450, "q": "大量のデータを素早く活用するために，データ変換処理を最小限にしてそのまま蓄積しておくストレージをどれか。", "opts": ["データレイク", "データベース", "データウェアハウス", "データマート"], "ans": 0, "exp": "データレイクは構造化・非構造化を問わず大量の生データをそのまま保存するストレージ。後で必要な形式に変換して分析に使用。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 451, "q": "日本の改正個人情報保護法で追加された「要配慮個人情報」に該当するものはどれか。", "opts": ["氏名と住所", "電話番号", "病歴や障害・犯罪歴などの差別につながりうる情報", "会社名"], "ans": 2, "exp": "要配慮個人情報は病歴・障害・犯罪歴・人種・信条等のセンシティブ情報。取得に原則として本人の同意が必要。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 452, "q": "組織のITシステム全体のアーキテクチャを業務・データ・アプリ・技術の4層で整理・管理する手法はどれか。", "opts": ["ITSM", "EA（エンタープライズアーキテクチャ）", "CMM", "TOGAF"], "ans": 1, "exp": "EA（Enterprise Architecture）はBusiness/Data/Application/Technologyの4層で企業ITを体系化し，現状から理想への移行計画を策定する手法。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 453, "q": "AIが対話・質問応答できる仕組みで，質問に対する応答を事前に定義したシナリオ型ではなく，学習データから生成するタイプはどれか。", "opts": ["シナリオ型チャットボット", "IVR（自動音声応答）", "FAQシステム", "生成AIベースの対話システム"], "ans": 3, "exp": "生成AIベースの対話は学習データから文脈に応じた返答を生成する。シナリオ型は事前定義のパターンのみ対応。GPT系モデルが代表例。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 454, "q": "サービス業での顧客体験の品質向上に，顧客が実際に感じる価値の要素として「感情的価値」を重視する考え方はどれか。", "opts": ["品質機能展開", "機能的品質管理", "CX（カスタマーエクスペリエンス）", "サービスレベル管理"], "ans": 2, "exp": "CX（Customer Experience）は製品・サービスの機能的品質だけでなく，顧客が接点全体で感じる感情的な体験・価値を重視する考え方。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 455, "q": "情報システムが法令・規制・内部ポリシーに準拠しているかを確認する活動はどれか。", "opts": ["ITキャパシティ管理", "ITパフォーマンス管理", "ITコンプライアンス", "ITアーキテクチャ管理"], "ans": 2, "exp": "ITコンプライアンスはITシステム・プロセスが関連法令（個人情報保護法等）・規制・内部ポリシーに準拠しているかを確認・維持する活動。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 456, "q": "プロジェクトの開始を宣言し，プロジェクトマネージャに権限を与える公式文書はどれか。", "opts": ["リスク登録簿", "プロジェクト計画書", "ステークホルダー台帳", "プロジェクト憲章"], "ans": 3, "exp": "プロジェクト憲章（Project Charter）はプロジェクト開始を正式に承認し，PMの権限・目的・概要予算・マイルストーンを記載した公式文書。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 457, "q": "ソフトウェア開発のコスト見積もり手法で，過去の類似プロジェクトの実績データをもとに見積もる手法はどれか。", "opts": ["類推見積もり", "ボトムアップ見積もり", "パラメトリック見積もり", "ファンクションポイント法"], "ans": 0, "exp": "類推見積もり（Analogous Estimating）は過去の類似プロジェクトのコスト・期間を参考に，差異を調整して新プロジェクトを見積もる手法。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 458, "q": "ITサービスマネジメントで，本番環境のソフトウェア・ハードウェア構成を記録・管理するデータベースはどれか。", "opts": ["KEDB", "CMDB（構成管理データベース）", "サービスカタログ", "インシデントDB"], "ans": 1, "exp": "CMDB（Configuration Management Database）は本番環境のCI（構成アイテム）とその関係を記録・管理するITSMの中核データベース。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 459, "q": "プロジェクト管理で，依存関係のない作業が並行実施できる場合に，最も早く完成できるスケジュールを求めることを何というか。", "opts": ["WBS", "フローチャート", "ガントチャート", "クリティカルパス法"], "ans": 3, "exp": "クリティカルパス法（CPM）はネットワーク図の最長経路を求め，最短プロジェクト期間とクリティカルパス上の作業を特定する手法。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 460, "q": "ソフトウェアテストで，境界となる値の前後をテストする技法はどれか。", "opts": ["デシジョンテーブル", "境界値分析", "ユースケーステスト", "同値分割"], "ans": 1, "exp": "境界値分析はバグが境界付近に多い傾向を利用。有効範囲の最小値・最大値・境界値±1をテストケースに選ぶ効率的なテスト技法。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 461, "q": "情報システムの調達において，ベンダ各社に具体的な提案書・見積書の提出を求める文書はどれか。", "opts": ["RFI（情報提供依頼書）", "RFP（提案依頼書）", "NDA", "SLA"], "ans": 1, "exp": "RFP（Request for Proposal）はシステム要件・条件を明示してベンダに具体的な提案・見積もり提出を求める文書。RFIは情報収集が目的。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 462, "q": "サービス運用で，知識ベースを活用して問い合わせを自動・半自動で解決する仕組みはどれか。", "opts": ["チケット管理", "IVR", "AI自動応答", "セルフサービスポータル"], "ans": 3, "exp": "セルフサービスポータルはFAQ・ナレッジベースをユーザーが自分で検索して解決できるITSMのサービス。電話問い合わせを削減する。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 463, "q": "プロジェクトのリスク対応策のうち，リスクの発生確率または影響度を下げる対策はどれか。", "opts": ["リスク回避", "リスク軽減", "リスク受容", "リスク移転"], "ans": 1, "exp": "リスク軽減（緩和）は発生確率や影響度を下げる予防的対策（テスト強化・冗長化等）。リスク移転は保険・外注等での負担転嫁。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 464, "q": "IT資産管理の目的として最も適切なものはどれか。", "opts": ["社員の個人情報管理", "セキュリティ脅威の検出", "ハードウェア・ソフトウェア資産の把握・コスト最適化・ライセンス管理", "ネットワーク帯域の管理"], "ans": 2, "exp": "IT資産管理（ITAM）はPCや機器の棚卸し・ライセンス管理・ライフサイクル管理で，コンプライアンス・コスト最適化を実現する。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 465, "q": "サービスデスクで，問い合わせの対応を件数・種類・解決率等で定量的に把握・改善する活動はどれか。", "opts": ["問題管理", "変更管理", "サービスデスクレポーティング・分析", "SLM"], "ans": 2, "exp": "サービスデスクの定量分析は問い合わせ件数・種類・解決時間・初回解決率等のKPIを測定し，品質・効率改善に活用する活動。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 466, "q": "アジャイル開発でスプリント計画会議の主な目的はどれか。", "opts": ["スプリントで実施する作業とゴールを計画する", "チームのプロセスを振り返る", "プロダクトバックログを更新する", "完了済みの成果物をステークホルダーに見せる"], "ans": 0, "exp": "スプリントプランニングはスプリント開始前にPBLから優先度の高いアイテムを選択し，スプリントゴールと実施タスクを確定する会議。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 467, "q": "情報システム監査で監査人が監査の目的・範囲・手続き等を文書化したものをどれか。", "opts": ["監査調書", "監査報告書", "監査計画書", "監査証拠"], "ans": 2, "exp": "監査計画書は監査の目的・範囲・対象・手続き・スケジュール等を定めた文書。実施前に被監査組織と合意する場合が多い。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 468, "q": "エンタープライズシステムのデータ整合性を維持するために，全システム共通のデータ定義・標準を管理するツールはどれか。", "opts": ["データカタログ／メタデータ管理", "ERP", "DWH", "MDM（マスタデータ管理）"], "ans": 3, "exp": "MDM（Master Data Management）は顧客・製品・従業員等のマスタデータを全社で統一・整合させ，データ品質を管理するシステム。", "cat": "マネジメント", "diff": "hard", "year": 2020}, {"id": 469, "q": "アジャイルの原則で，短い反復の終わりに動くソフトウェアを届けることを重視する理由として最も適切なものはどれか。", "opts": ["ドキュメントを減らすため", "テストを省略するため", "コストを削減するため", "継続的に価値を提供し，フィードバックを早く得るため"], "ans": 3, "exp": "アジャイル宣言の核心。動くソフトウェアを頻繁にリリースすることで，ユーザーフィードバックを早期に取り込み方向修正できる。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 470, "q": "コンティンジェンシー計画の目的として最も適切なものはどれか。", "opts": ["プロジェクトスコープを拡大する", "プロジェクトの予算を削減する", "特定リスクが顕在化した場合に備えた対応計画を事前に準備する", "チームのスキルを向上させる"], "ans": 2, "exp": "コンティンジェンシー計画は特定のリスクが発生した際の対応手順を事前に定めておく計画。発動条件（トリガー）も明確にする。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 471, "q": "スクラムのスプリントレビューの説明として正しいものはどれか。", "opts": ["完成したインクリメントをステークホルダーに実演しフィードバックを得る", "スプリントの目標・計画を立てる", "デイリーの進捗確認", "チームの作業プロセスの振り返り"], "ans": 0, "exp": "スプリントレビューはPO・ステークホルダーに完成成果物をデモして意見収集し，プロダクトバックログを更新するイベント。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 472, "q": "情報システムの調達・運用コスト全体を見える化して最適化する考え方をどれか。", "opts": ["コストベンチマーク", "NPV", "TCO（Total Cost of Ownership）", "ROI"], "ans": 2, "exp": "TCOは取得コストだけでなく，保守・運用・サポート・廃棄まで含む全ライフサイクルコストを把握してIT投資を最適化する考え方。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 473, "q": "システム障害の対応記録で，「誰が・いつ・何をしたか」を時系列で記録したものをどれか。", "opts": ["問題管理記録", "監査ログ", "インシデントチケット", "インシデント対応タイムライン"], "ans": 3, "exp": "インシデント対応タイムラインは障害発生から復旧までの全アクションを時系列で記録。事後分析・レポート・再発防止策の根拠になる。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 474, "q": "ソフトウェアの品質特性ISO/IEC 25010で「様々な環境に移植できる度合い」を表す特性はどれか。", "opts": ["移植性", "信頼性", "保守性", "互換性"], "ans": 0, "exp": "移植性（Portability）はソフトウェアを異なる環境（OS・ハードウェア等）に移行できる容易さを示す品質特性。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 475, "q": "プロジェクト終了後に，次プロジェクトに活かす知見を文書にまとめる成果物をどれか。", "opts": ["プロジェクト計画書", "プロジェクト憲章", "リスク登録簿", "教訓（Lessons Learned）"], "ans": 3, "exp": "教訓（Lessons Learned）はプロジェクトを通じて得た成功・失敗の知見を記録した文書。組織ナレッジとして次プロジェクトに活用。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 476, "q": "IPアドレスの自動割り当てを行うサーバはどれか。", "opts": ["メールサーバ", "DHCPサーバ", "プロキシサーバ", "DNSサーバ"], "ans": 1, "exp": "DHCPサーバはネットワーク上の端末にIPアドレス・サブネットマスク・デフォルトゲートウェイ等を自動配布するサーバ。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 477, "q": "ネットワークのトポロジのうち，全ての端末が1本の幹線（バス）に接続される構造はどれか。", "opts": ["バス型", "スター型", "メッシュ型", "リング型"], "ans": 0, "exp": "バス型トポロジは1本の幹線（バス）に全端末を接続。設置が容易で安価だが，幹線障害で全体停止するリスクがある。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 478, "q": "論理演算でAND（両方1のとき1）の真理値表として正しいのはどれか（A=0,B=0の結果）。", "opts": ["1", "不定", "エラー", "0"], "ans": 3, "exp": "AND演算は両入力が1のときのみ1。0 AND 0=0，0 AND 1=0，1 AND 0=0，1 AND 1=1。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 479, "q": "セキュリティの多層防御（Defense in Depth）の考え方として正しいものはどれか。", "opts": ["1つの強力な防衛手段で全てのリスクを防ぐ", "複数の異なるセキュリティ対策を重ねて，1層突破されても次の層で防御する", "外部のみを防御し内部は信頼する", "最新の脅威にのみ対応する"], "ans": 1, "exp": "多層防御は複数のセキュリティ対策を重ねる考え方。ファイアウォール→IDS→ウイルス対策→暗号化等を組み合わせ，1層突破時のリスクを減らす。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 480, "q": "2要素認証として，パスワードとスマートフォンの認証アプリによる確認を組み合わせた場合，使っている認証要素の組み合わせはどれか。", "opts": ["知識×生体", "所有物×生体", "知識×知識", "知識×所有物"], "ans": 3, "exp": "パスワードは「知識」，スマートフォン（TOTP等）は「所有物」。認証の三要素（知識・所有物・生体）のうち知識×所有物の組み合わせ。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 481, "q": "記憶容量の単位で1TB（テラバイト）はおよそどれか。", "opts": ["10,000GB", "1,000GB", "100GB", "10億バイト（GB）"], "ans": 1, "exp": "1TB（テラバイト）= 約1,000GB（正確には2^40バイト≒1.1TB）。1GB=約10億バイト，1TB=約1兆バイト。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 482, "q": "インターネットバンキングで，攻撃者が正規サイトに見せかけた偽サイトへ誘導して口座情報を盗む攻撃はどれか。", "opts": ["スニッフィング", "フィッシング", "ブルートフォース", "スパム"], "ans": 1, "exp": "フィッシング攻撃は正規サービスに見せかけた偽メール・偽サイトでID・パスワード等を入力させて情報を盗む攻撃。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 483, "q": "プログラムのデバッグにおいて，特定の行でプログラムを一時停止させる機能をどれか。", "opts": ["ビルド", "コンパイル", "リンク", "ブレークポイント"], "ans": 3, "exp": "ブレークポイントはデバッガ機能の一つ。指定した行でプログラムを一時停止させ，変数値・メモリ状態を確認できる。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 484, "q": "ディープラーニングの学習で，訓練データのラベルあり・なしを半々で使って効率的に学習する手法はどれか。", "opts": ["アンサンブル学習", "転移学習", "半教師あり学習", "強化学習"], "ans": 2, "exp": "半教師あり学習はラベルあり（少量）＋ラベルなし（大量）データを組み合わせて学習。ラベル付けコストを削減できる。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 485, "q": "データベースで，あるテーブルの外部キーが参照先テーブルに存在しない値を持つことを禁止する制約はどれか。", "opts": ["主キー制約", "NOT NULL制約", "一意制約", "参照整合性制約（外部キー制約）"], "ans": 3, "exp": "参照整合性制約（外部キー制約）は外部キー値が参照先の主キーに必ず存在することを保証。整合性のないデータ挿入・削除を防ぐ。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 486, "q": "2進数の加算で 1011 + 0101 の結果はどれか。", "opts": ["10001", "1111", "1110", "10000"], "ans": 3, "exp": "1011(11)+0101(5)=16。2進数で16=10000。桁上がり：1011+0101→桁ごと計算すると10000になる。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 487, "q": "AIモデルのハイパーパラメータ（学習率・隠れ層数等）を最適化する作業をどれか。", "opts": ["モデルデプロイ", "データ収集", "前処理", "ハイパーパラメータチューニング"], "ans": 3, "exp": "ハイパーパラメータチューニングはモデルの学習率・バッチサイズ・層数等の設定値を試行錯誤して最良値を探す作業。グリッドサーチ等の手法がある。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 488, "q": "プログラミングで，同じ型の複数の変数をまとめて扱うデータ構造をどれか。", "opts": ["スタック", "変数", "ポインタ", "配列"], "ans": 3, "exp": "配列は同じデータ型の要素をメモリの連続領域に並べたデータ構造。インデックスで各要素にO(1)でアクセスできる。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 489, "q": "Webサーバが大量のリクエストを分散して処理するために複数サーバに振り分ける装置はどれか。", "opts": ["スイッチ", "ルータ", "ロードバランサ", "ファイアウォール"], "ans": 2, "exp": "ロードバランサは複数のWebサーバにリクエストを分散することで高可用性・高性能を実現する装置。ラウンドロビン・最小接続数等の分散方式がある。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 490, "q": "変数宣言なしに使用できるインタプリタ型のスクリプト言語として広く使われるWebフロントエンド言語はどれか。", "opts": ["JavaScript", "Java", "C言語", "COBOL"], "ans": 0, "exp": "JavaScriptはWebブラウザで動作するインタプリタ型スクリプト言語。動的型付けで変数宣言が柔軟。HTMLとCSSと組み合わせてWeb UI を実装。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 491, "q": "ネットワーク機器のMACアドレスの長さは何ビットか。", "opts": ["48ビット", "128ビット", "32ビット", "64ビット"], "ans": 0, "exp": "MACアドレス（物理アドレス）は48ビット（6バイト）。16進数12桁（例：00:1A:2B:3C:4D:5E）で表記。製造時にNICに割り当てられる。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 492, "q": "ソフトウェアの国際化対応で，日本語・英語・中国語等の多言語と各地域の日付・数値フォーマット対応を何というか。", "opts": ["フォントの埋め込み", "ローカライゼーション（L10n）", "国際化（i18n）＋地域化（L10n）", "ユニコード対応"], "ans": 2, "exp": "国際化（i18n）はソフトウェアを多言語化しやすい設計にすること，地域化（L10n）はその地域向けに言語・日付等を適用すること。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 493, "q": "電子マネーや決済システムで，取引のたびに変化するワンタイムパスワードを生成する方式はどれか。", "opts": ["TOTP（時刻ベースワンタイムパスワード）", "静的パスワード", "パスフレーズ", "ハッシュ認証"], "ans": 0, "exp": "TOTP（Time-based One-Time Password）は現在時刻をもとに30秒ごとに変化するパスワードを生成。Google Authenticator等で使用。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 494, "q": "バイオメトリクス認証のうち，本人なのに認証が失敗する確率をどれか。", "opts": ["認証精度", "他人受入率（FAR）", "本人拒否率（FRR）", "スループット"], "ans": 2, "exp": "FRR（False Rejection Rate：本人拒否率）は正当な本人が拒否される確率。FAR（False Acceptance Rate）は他人が誤って認証される確率。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 495, "q": "光ファイバー通信で，単一モードファイバーと比べてコアが太く，短距離に使われるファイバーはどれか。", "opts": ["CAT6", "同軸ケーブル", "シングルモードファイバー", "マルチモードファイバー"], "ans": 3, "exp": "マルチモードファイバーはコアが太く（50/62.5μm）複数の光路を使用。短距離向けで安価。シングルモード（9μm）は長距離向け。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 496, "q": "稼働率0.9のサーバが2台の直列システムでの全体稼働率はどれか。", "opts": ["0.95", "0.81", "0.99", "0.9"], "ans": 1, "exp": "直列システム稼働率 = 各稼働率の積 = 0.9×0.9 = 0.81。並列では1-(1-0.9)²=0.99。直列は最も弱い部分がボトルネックになる。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 497, "q": "企業の内部環境（強み・弱み）と外部環境（機会・脅威）を整理するフレームワークはどれか。", "opts": ["5フォース分析", "SWOT分析", "PEST分析", "3C分析"], "ans": 1, "exp": "SWOT分析はStrengths（強み）・Weaknesses（弱み）・Opportunities（機会）・Threats（脅威）の4要素で経営環境を体系的に分析するフレームワーク。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 498, "q": "製品の差別化戦略のうち，競合より低いコストで同質の価値を提供してシェアを奪う戦略はどれか。", "opts": ["コストリーダーシップ戦略", "集中戦略", "差別化戦略", "多角化戦略"], "ans": 0, "exp": "コストリーダーシップ戦略はポーターの3つの基本戦略の一つ。業界最低コストを実現して価格競争力を持つ戦略。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 499, "q": "クラウドソーシングとはどれか。", "opts": ["不特定多数の外部人材にインターネットで業務を依頼する手法", "クラウドストレージの管理", "社内の人材育成手法", "クラウドサービスへのデータ移行"], "ans": 0, "exp": "クラウドソーシングはインターネットを介して不特定多数の外部人材に翻訳・デザイン・データ入力等を依頼する手法。", "cat": "ストラテジ", "diff": "easy", "year": 2024}, {"id": 500, "q": "コーポレートガバナンスの観点から，社外取締役の主な役割はどれか。", "opts": ["日常業務の執行", "株主利益を守る観点から経営の監督・牽制を行う", "IRの実施", "ESGレポートの作成"], "ans": 1, "exp": "社外取締役は業務執行から独立した立場で取締役会に参加し，経営を監視・牽制することで株主利益の保護とガバナンス強化を図る。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 501, "q": "労働基準法の定める1週間の法定労働時間はどれか。", "opts": ["48時間", "40時間", "35時間", "44時間"], "ans": 1, "exp": "労働基準法第32条は1週40時間・1日8時間を法定労働時間と定める。これを超える時間外労働には36協定締結と割増賃金が必要。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 502, "q": "景品表示法で禁止される優良誤認表示の例として最も適切なものはどれか。", "opts": ["正確な効果・成分を表示した広告", "実際より著しく優れていると誤認させる表示", "新製品の発売告知", "価格の比較広告"], "ans": 1, "exp": "優良誤認表示は実際より品質・性能・効果が優れているかのように消費者を誤認させる表示。景品表示法で禁止・措置命令の対象。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 503, "q": "企業が気候変動リスクを財務情報として開示することを求めるフレームワークの略称はどれか。", "opts": ["ESG", "SASB", "GRI", "TCFD"], "ans": 3, "exp": "TCFD（Task Force on Climate-related Financial Disclosures）は気候変動に関するリスク・機会を財務情報として開示するためのフレームワーク。", "cat": "ストラテジ", "diff": "hard", "year": 2024}, {"id": 504, "q": "デザイン思考の5つのプロセスを正しい順序で並べたものはどれか。", "opts": ["定義→共感→試作→テスト→アイデア", "共感→定義→アイデア創出→試作→テスト", "試作→定義→共感→アイデア→テスト", "アイデア→共感→定義→テスト→試作"], "ans": 1, "exp": "デザイン思考はEmpatize（共感）→Define（定義）→Ideate（アイデア）→Prototype（試作）→Test（テスト）の5段階。Stanfordが提唱。", "cat": "ストラテジ", "diff": "mid", "year": 2024}, {"id": 505, "q": "SaaSとASPの違いとして最も適切なものはどれか。", "opts": ["ASPはクラウドのみ，SaaSはオンプレも含む", "SaaSはマルチテナントでカスタマイズ不要，ASPは顧客ごとにシステムを提供", "ASPはマルチテナント対応，SaaSはシングルテナント", "両者は完全に同一の概念"], "ans": 1, "exp": "SaaSはマルチテナント（共有基盤）で拡張性・コスト効率が高い。ASPは顧客ごとに独立したシステムを提供する旧来のモデル。", "cat": "ストラテジ", "diff": "hard", "year": 2024}, {"id": 506, "q": "プラットフォームビジネスで，供給側と需要側の両者を引きつける効果をどれか。", "opts": ["スイッチングコスト", "ロックイン", "両面ネットワーク効果", "ブランド効果"], "ans": 2, "exp": "両面ネットワーク効果はプラットフォームで供給側（出品者）が増えると需要側（購入者）の価値も増し，逆も同様の相互強化効果。", "cat": "ストラテジ", "diff": "hard", "year": 2024}, {"id": 507, "q": "エンジニアが書いた機能仕様書を自動的にテストケースに変換するアプローチはどれか。", "opts": ["BDD（振る舞い駆動開発）", "ペアプログラミング", "ウォーターフォール", "TDD（テスト駆動開発）"], "ans": 0, "exp": "BDD（Behavior Driven Development）は自然言語に近い形で振る舞い仕様を記述し，テスト自動化に活用する開発手法。Cucumberが代表ツール。", "cat": "マネジメント", "diff": "hard", "year": 2024}, {"id": 508, "q": "システム監査の目的として最も適切なものはどれか。", "opts": ["情報システムの設計を改善する", "情報システムのリスク管理・内部統制の有効性を独立した立場で評価する", "情報システムの運用を管理する", "情報システムの開発コストを削減する"], "ans": 1, "exp": "システム監査は独立・客観的な立場でITシステムのリスク管理・内部統制・信頼性を評価・検証し，改善勧告を行う活動。", "cat": "マネジメント", "diff": "mid", "year": 2024}, {"id": 509, "q": "コンピュータの処理において，複数CPUコアが同時に異なる命令を実行する処理方式はどれか。", "opts": ["シリアル処理", "マルチコア並列処理", "タイムシェアリング", "パイプライン処理"], "ans": 1, "exp": "マルチコア並列処理は複数CPUコアが同時に異なるスレッドを実行する。シングルコアより高スループットを実現する。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 510, "q": "OSのスケジューリングで，CPU使用中のプロセスを強制的に中断して別のプロセスに切り替える方式はどれか。", "opts": ["ラウンドロビン", "非プリエンプティブ", "プリエンプティブ", "FIFO"], "ans": 2, "exp": "プリエンプティブ方式はOSが強制的にCPUを横取りして別プロセスに割り当て可能。応答性が高く現代OSに採用。非プリエンプティブは自発的に解放まで待つ。", "cat": "テクノロジ", "diff": "mid", "year": 2024}, {"id": 511, "q": "ITパスポート試験の出題範囲「テクノロジ系」に含まれる内容として最も適切なものはどれか。", "opts": ["コンピュータ・ネットワーク・セキュリティ", "会計・財務", "経営戦略", "プロジェクトマネジメント"], "ans": 0, "exp": "テクノロジ系はハードウェア・ソフトウェア・ネットワーク・セキュリティ・データベース・システム開発等の技術的内容を含む。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 512, "q": "ソーシャルエンジニアリング攻撃の手口として最も典型的なものはどれか。", "opts": ["DDoS攻撃", "SQLインジェクション", "ゼロデイ攻撃", "電話や対話で社員を騙しパスワードを聞き出す"], "ans": 3, "exp": "ソーシャルエンジニアリングはIT技術ではなく人間の心理・行動を悪用して機密情報を取得する攻撃。なりすまし電話・ゴミ箱漁りが典型例。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 513, "q": "メールやWebサイトのフォームに悪意ある内容を入力し，受信者や他ユーザーを攻撃するXSSの対策として最も効果的なものはどれか。", "opts": ["ファイアウォールの設置", "入力値のエスケープ処理", "ウイルス対策ソフト", "SSLの導入"], "ans": 1, "exp": "XSS対策の基本はサーバ側での入力・出力のエスケープ処理（<>&等を無害な文字列に変換）。Content-Security-Policyヘッダも有効。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 514, "q": "ワンタイムパスワード（OTP）の特徴として最も適切なものはどれか。", "opts": ["毎回異なるパスワードを使い，傍受されても再利用できない", "常に同じパスワードを使う", "生体情報を利用する", "パスワードが不要になる"], "ans": 0, "exp": "ワンタイムパスワードは一度しか使えない使い捨てパスワード。リプレイ攻撃を防止し，オンラインバンキング・VPNで広く使用。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 515, "q": "セキュリティの観点で，必要最低限の権限のみをユーザー・システムに与える原則はどれか。", "opts": ["認証強化", "暗号化", "多重防御", "最小権限の原則"], "ans": 3, "exp": "最小権限の原則（Principle of Least Privilege）は業務に必要な最低限の権限のみ付与し，侵害時の被害範囲を最小化するセキュリティ原則。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 516, "q": "ネットワーク機器のうち，同一ネットワーク内でMACアドレスをもとに通信を中継する機器はどれか。", "opts": ["ルータ", "プロキシ", "スイッチ（レイヤ2）", "ファイアウォール"], "ans": 2, "exp": "レイヤ2スイッチはMACアドレステーブルを参照して，同一ネットワーク（同一セグメント）内でフレームを転送する機器。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 517, "q": "ハードウェアの信頼性指標MTBFとMTTRについて，可用性の計算式として正しいものはどれか。", "opts": ["可用性 = MTTR ÷ MTBF", "可用性 = MTBF × MTTR", "可用性 = (MTBF + MTTR) ÷ MTBF", "可用性 = MTBF ÷ (MTBF + MTTR)"], "ans": 3, "exp": "可用性 = MTBF ÷ (MTBF + MTTR)。MTBF（平均故障間隔）が長く，MTTR（平均修復時間）が短いほど可用性が高い。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 518, "q": "プログラムの実行速度を向上させるためにソースコードを解析し無駄を排除する処理をどれか。", "opts": ["デバッグ", "最適化", "テスト", "コンパイル"], "ans": 1, "exp": "最適化（オプティマイゼーション）はコンパイラが実行速度向上やメモリ効率化のため，冗長コードの削除・ループ展開等を自動実行する処理。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 519, "q": "TCP/IPの4層モデルでHTTPが属する層はどれか。", "opts": ["ネットワーク層", "トランスポート層", "アプリケーション層", "インターネット層"], "ans": 2, "exp": "TCP/IPの4層：インターネット層（IP）→トランスポート層（TCP/UDP）→アプリケーション層（HTTP/DNS/SMTP等）→ネットワークアクセス層。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 520, "q": "クラウドサービスで複数の顧客が同一のインフラ・アプリを共有する形態はどれか。", "opts": ["プライベートクラウド", "マルチテナント", "ハイブリッドクラウド", "専用クラウド"], "ans": 1, "exp": "マルチテナントは複数顧客（テナント）が同一のソフトウェア・インフラを共有する形態。SaaSの基本モデルでコスト効率が高い。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 521, "q": "情報システムの3層アーキテクチャで，業務ロジックを担う中間の層はどれか。", "opts": ["アプリケーション層（ビジネスロジック層）", "ネットワーク層", "データ層", "プレゼンテーション層"], "ans": 0, "exp": "3層アーキテクチャはUI（プレゼン層）／ビジネスロジック（アプリ層）／DB（データ層）で構成。各層の独立性が高くメンテナンスしやすい。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 522, "q": "EUの一般データ保護規則（GDPR）の基本原則として定められているものはどれか。", "opts": ["個人データの保管に期限はない", "個人データは特定の目的のみで収集・処理されなければならない", "個人データは目的を問わず収集できる", "個人データは企業間で自由に共有できる"], "ans": 1, "exp": "GDPRの目的限定原則は，個人データは特定・明示・正当な目的のためにのみ収集・処理可能と規定。目的外利用は原則禁止。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 523, "q": "AIのテキスト分類タスクの評価指標として，正解率（Accuracy）とF1スコアの違いはどれか。", "opts": ["F1スコアは回帰問題に使う", "AccuracyはF1スコアの特殊ケース", "F1スコアはクラス不均衡データでも適切に性能評価できる", "F1スコアはAccuracyより常に低い"], "ans": 2, "exp": "クラス不均衡データではAccuracyが高くてもF1スコアが低い場合がある。F1はPrecision・Recallの調和平均でクラス不均衡時に有用。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 524, "q": "SQLのUPDATE文の説明として正しいものはどれか。", "opts": ["新しいレコードを挿入する", "テーブルを削除する", "既存レコードの列値を更新する", "テーブルを作成する"], "ans": 2, "exp": "SQL DML：SELECT（検索），INSERT（挿入），UPDATE（更新），DELETE（削除）。UPDATE文はWHERE条件で対象行を絞って列値を更新。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 525, "q": "フィジカルコンピューティングの代表例として最も適切なものはどれか。", "opts": ["スプレッドシートの計算", "クラウドストレージの利用", "Webブラウザでのゲーム", "マイコンボード（Arduino等）にセンサを接続してLEDを制御"], "ans": 3, "exp": "フィジカルコンピューティングはソフトウェアと現実世界の物理デバイスを連携。Arduino・Raspberry Pi等でセンサ制御・IoT試作が代表例。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 526, "q": "コンピュータネットワークのセグメント分割で，同一物理ネットワーク上に複数の論理ネットワークを作る技術はどれか。", "opts": ["VPN", "VLAN", "DNS", "NAT"], "ans": 1, "exp": "VLAN（Virtual LAN）はスイッチの設定で同一物理ネットワークを論理的に複数のセグメントに分割する技術。トラフィック分離・セキュリティ向上に使用。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 527, "q": "マルチメディアファイルで，元のデータより情報の一部を失うが高圧縮率を実現する方式はどれか。", "opts": ["不可逆圧縮（非可逆圧縮）", "バイナリ変換", "可逆圧縮", "暗号化"], "ans": 0, "exp": "不可逆圧縮（JPEG・MP3・MP4等）は一部のデータを削除して高圧縮を実現するが元に戻せない。可逆圧縮（PNG・ZIP等）は完全復元可能。", "cat": "テクノロジ", "diff": "easy", "year": 2023}, {"id": 528, "q": "機械学習モデルの汎化性能評価で，テストデータを複数回使い結果を平均する評価法の名称はどれか。", "opts": ["バギング", "ホールドアウト法", "k分割交差検証", "ブースティング"], "ans": 2, "exp": "k-fold Cross Validationはデータをk等分し，k回試行してテスト・訓練データを入れ替えることで，バリアンスの少ない安定した性能推定ができる。", "cat": "テクノロジ", "diff": "mid", "year": 2023}, {"id": 529, "q": "コンテナオーケストレーションツールの代表として，大規模コンテナ環境の自動管理を行うOSSはどれか。", "opts": ["Docker", "Kubernetes", "Ansible", "Terraform"], "ans": 1, "exp": "Kubernetes（K8s）はGoogleが開発したOSS。コンテナのデプロイ・スケーリング・自動復旧・ロードバランスを管理するオーケストレーションシステム。", "cat": "テクノロジ", "diff": "hard", "year": 2023}, {"id": 530, "q": "著作権法でソフトウェアを法人が開発した場合の著作者は誰か（職務著作の原則）。", "opts": ["著作権庁", "法人（会社）", "開発した社員個人", "ユーザー"], "ans": 1, "exp": "職務著作（法人著作）は従業員が職務で作成した著作物の著作者は原則として法人（会社）となる（著作権法第15条）。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 531, "q": "電子署名法における電子署名の機能として正しいものはどれか。", "opts": ["書類の暗号化", "紙の署名と完全に同一の法的効力を持つ", "署名者の本人確認と改ざん検知", "電子メールの送受信の認証"], "ans": 2, "exp": "電子署名は秘密鍵で生成・公開鍵で検証し，署名者の同一性と文書の完全性（改ざん検知）を証明する機能を持つ。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 532, "q": "企業がビジネスモデルを変革する際，既存の収益源を意図的に壊す行為を何というか。", "opts": ["ディスラプション", "スピンオフ", "ピボット", "カニバリゼーション"], "ans": 3, "exp": "カニバリゼーション（自食い）は自社の製品・事業Aが別の自社製品・事業Bの顧客を奪う現象。DXで既存ビジネスを自ら破壊することも必要。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 533, "q": "リモートワーク環境でのコミュニケーション課題として，文字コミュニケーションの限界を補う最適な方法はどれか。", "opts": ["全て対面に戻す", "ビデオ会議・画面共有ツールの積極活用", "チャットのみに統一", "メールの本数を増やす"], "ans": 1, "exp": "テキストチャットでは非言語情報（表情・声のトーン等）が伝わらない。ビデオ会議・画面共有でコミュニケーション品質を補完する。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 534, "q": "個人情報保護法の「第三者提供の制限」に対する例外として認められる場合はどれか。", "opts": ["マーケティング目的での提供", "業務委託先への開示（無制限）", "グループ会社内での自由な共有", "法令に基づく場合や人の生命・身体保護のため本人の同意を得ることが困難な場合"], "ans": 3, "exp": "個人情報の第三者提供は原則本人同意が必要。例外は①法令に基づく場合②人命保護等で本人同意困難③公衆衛生④国機関等への協力。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 535, "q": "国内スタートアップが政府系機関や自治体から事業資金を獲得する仕組みの一つはどれか。", "opts": ["銀行融資", "補助金・助成金の活用", "社債の発行", "株式公開"], "ans": 1, "exp": "補助金・助成金は返済不要の資金として政府・自治体・独立行政法人等が提供する。IT導入補助金・ものづくり補助金等が代表。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 536, "q": "BPR（業務プロセス再構築）とは何か。", "opts": ["ゼロベースで業務プロセスを根本的に見直し，大幅な改善を図ること", "組織の人員を削減すること", "業務フローの一部を改善・効率化すること", "ITシステムをリプレースすること"], "ans": 0, "exp": "BPR（Business Process Reengineering）はHammer&Champyが提唱。既存の前提を捨て，コスト・品質・スピードを飛躍的に向上させるプロセス再設計。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 537, "q": "工場の設備が予期しない故障を起こす前に予兆を検知してメンテナンスするIoT活用事例はどれか。", "opts": ["品質管理", "予知保全", "物流管理", "在庫最適化"], "ans": 1, "exp": "予知保全（Predictive Maintenance）はIoTセンサで設備の振動・温度等を監視し，AIで異常を早期検知して故障前に保全を行う。設備稼働率向上・コスト削減が目的。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 538, "q": "店舗のPOSデータ・顧客データを分析し，特定商品の売れ行き予測・発注最適化を行うシステムはどれか。", "opts": ["CRM", "需要予測・発注最適化システム", "SFA", "ERP"], "ans": 1, "exp": "需要予測・発注最適化システムは過去販売データ・天気・イベント等からAIで需要を予測し，在庫コスト・欠品を最小化する仕組み。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 539, "q": "デジタルサイネージとはどれか。", "opts": ["デジタル認証の仕組み", "電子書籍の配信サービス", "屋外・店頭等に設置された電子的な看板・ディスプレイ広告", "デジタルデータの電子署名"], "ans": 2, "exp": "デジタルサイネージは駅・商業施設等に設置したデジタルディスプレイで動画・画像コンテンツを配信する電子広告・情報提供システム。", "cat": "ストラテジ", "diff": "easy", "year": 2022}, {"id": 540, "q": "無体財産権のうち，回路配置の創作を保護する権利はどれか。", "opts": ["特許権", "意匠権", "回路配置利用権", "実用新案権"], "ans": 2, "exp": "回路配置利用権は半導体集積回路の回路配置を保護する権利（半導体集積回路の回路配置に関する法律）。特許権とは別の保護制度。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 541, "q": "経営管理手法のうち，数値目標（Key Results）に対して進捗を可視化して管理するフレームワークはどれか。", "opts": ["MBO", "OKR", "KPI", "BSC"], "ans": 1, "exp": "OKR（Objectives and Key Results）はチャレンジングな定性的目標（O）と測定可能な定量的成果指標（KR）で構成。四半期単位で管理。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 542, "q": "プライバシーバイデザインの原則の一つとして「事後的でなく予防的にプライバシーを設計に組み込む」という原則はどれか。", "opts": ["プライバシー・バイ・デフォルト", "エンドツーエンドセキュリティ", "予防的措置", "データ最小化"], "ans": 2, "exp": "プライバシーバイデザインの7原則の一つは「事後的でなく事前的，救済的でなく予防的」。プライバシーリスクを設計段階から組み込む考え方。", "cat": "ストラテジ", "diff": "hard", "year": 2022}, {"id": 543, "q": "電子商取引で使われるエスクローサービスの目的はどれか。", "opts": ["商品の配送を保証する", "個人情報を保護する", "商品の品質を保証する", "売買の仲介者として代金を一時保管し，取引完了後に支払う信頼性確保の仕組み"], "ans": 3, "exp": "エスクローは買主から代金を預かり，商品受け取り確認後に売主へ支払う第三者仲介サービス。フリマ・輸出入取引等での詐欺防止に使用。", "cat": "ストラテジ", "diff": "mid", "year": 2022}, {"id": 544, "q": "ITサービスマネジメントで，利用者へのサービス種類・内容・条件を一覧にした文書はどれか。", "opts": ["SLA", "OLA", "CMDB", "サービスカタログ"], "ans": 3, "exp": "サービスカタログはITサービス部門が提供するサービスの種類・内容・利用条件・申請方法等を一覧化した文書。利用者の自己サービス選択に使用。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 545, "q": "プロジェクトでステークホルダーの関与度を高めるための施策として最も適切なものはどれか。", "opts": ["プロジェクト完了後に報告する", "要件定義のみ参加させる", "ステークホルダーを意思決定から外す", "定期的な情報共有・レビュー参加・意見反映の機会を設ける"], "ans": 3, "exp": "ステークホルダーエンゲージメントは関係者を継続的に関与させることで，要件の誤解・変更・反発リスクを低減し，受け入れを促進する。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 546, "q": "ソフトウェアのコードを書かずに設計仕様を検証するために，紙やツールで画面操作を模擬する手法はどれか。", "opts": ["モックアップ・ペーパープロトタイプ", "統合テスト", "ユニットテスト", "ユーザー受入テスト"], "ans": 0, "exp": "ペーパープロトタイプ・モックアップは実装前に画面UIの概念を紙やデザインツールで可視化し，ユーザーと早期に設計検証する手法。", "cat": "マネジメント", "diff": "easy", "year": 2022}, {"id": 547, "q": "CI/CD（継続的インテグレーション/継続的デリバリー）の主な目的はどれか。", "opts": ["セキュリティテストの自動化のみ", "開発スピードを下げて品質を向上させる", "ドキュメントの自動生成", "コードの変更を自動的にビルド・テスト・デプロイして高頻度リリースを可能にする"], "ans": 3, "exp": "CI/CDはコード変更をトリガーに自動ビルド・テスト・デプロイを実行するパイプライン。バグの早期発見と高速なサービス改善を実現するDevOpsの中核実践。", "cat": "マネジメント", "diff": "mid", "year": 2022}, {"id": 548, "q": "データセンターのPUE（電力使用効率）の計算式として正しいものはどれか。", "opts": ["PUE = 施設全体消費電力 ÷ IT機器消費電力", "PUE = IT機器消費電力 ÷ 施設全体消費電力", "PUE = 施設全体消費電力 + IT機器消費電力", "PUE = IT機器消費電力 × 施設全体消費電力"], "ans": 0, "exp": "PUE（Power Usage Effectiveness）= 施設全体消費電力 ÷ IT機器消費電力。1.0が理想（空調等の無駄ゼロ）。Google DCは約1.1台。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 549, "q": "クラウドのCDN（コンテンツデリバリネットワーク）の主な目的はどれか。", "opts": ["データバックアップ", "世界各地にコンテンツをキャッシュしてユーザーへの配信を高速化", "データの暗号化", "クラウドストレージの管理"], "ans": 1, "exp": "CDNは世界各地のエッジサーバにコンテンツをキャッシュ配置。ユーザーに最も近いサーバから配信することで遅延を削減し体験を向上させる。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 550, "q": "サーバのログに記録されるIPアドレスから攻撃者を特定する際の注意点として最も適切なものはどれか。", "opts": ["MACアドレスで特定できる", "プロキシ・VPN・踏み台を経由している場合，実際の攻撃者を特定できないことがある", "IPアドレスは必ず攻撃者本人のPCを示す", "IPアドレスだけで全情報が分かる"], "ans": 1, "exp": "IPアドレスは攻撃者の経路上の最後のIPを示すのみ。プロキシ・VPN・踏み台PCを利用されると実際の攻撃者IPが隠蔽される。フォレンジクス上重要な知識。", "cat": "テクノロジ", "diff": "mid", "year": 2022}, {"id": 551, "q": "機械学習の特徴選択（Feature Selection）の目的として最も適切なものはどれか。", "opts": ["モデルの精度維持しながら不要な特徴量を除去して計算効率と解釈性を向上させる", "データの欠損値を補完する", "モデルを複雑にして精度を最大化する", "過学習を意図的に発生させる"], "ans": 0, "exp": "特徴選択は予測に有用な変数のみを選んで不要変数を削除する手法。次元削減・過学習防止・計算コスト削減・解釈性向上に貢献。", "cat": "テクノロジ", "diff": "hard", "year": 2022}, {"id": 552, "q": "ドメイン名をIPアドレスに変換する問い合わせを，階層的に複数のDNSサーバを経由して解決する仕組みはどれか。", "opts": ["再帰的問い合わせと反復的問い合わせ", "NATトラバーサル", "ARPリクエスト", "ルーティング"], "ans": 0, "exp": "DNS解決はまずリゾルバに問い合わせ，ルートDNS→TLDサーバ→権威DNSと再帰的・反復的に解決される仕組み。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 553, "q": "メールのSPAM対策技術として，受信側がメールの送信者ドメインのIPアドレスをDNSで検証する技術はどれか。", "opts": ["PGP", "SPF", "DKIM", "S/MIME"], "ans": 1, "exp": "SPF（Sender Policy Framework）はDNSのTXTレコードに正規送信サーバIPを登録し，受信MTA側でIPを照合してなりすましを検知する技術。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 554, "q": "AIの強化学習において，エージェントが行動を選択する指針として学習するものはどれか。", "opts": ["データセット", "特徴量", "方策（ポリシー）", "損失関数"], "ans": 2, "exp": "強化学習では方策（Policy）は状態→行動のマッピング関数。累積報酬を最大化する最適方策を学習するのが強化学習の目標。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 555, "q": "ブロックチェーンのコンセンサスアルゴリズムのうち，PoW（Proof of Work）の特徴として正しいものはどれか。", "opts": ["投票数で決まる", "信頼できる第三者が承認する", "大量の計算（マイニング）で合意する，エネルギー消費が大きい", "保有するコインの量で権限が決まる"], "ans": 2, "exp": "PoW（プルーフオブワーク）はビットコインが使うコンセンサス方式。計算問題を最初に解いた者がブロックを追加。電力消費・51%攻撃が課題。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 556, "q": "ディープラーニングの時系列データ処理に適したニューラルネットワーク構造はどれか。", "opts": ["RNN（再帰型NN）", "オートエンコーダ", "CNN（畳み込みNN）", "GAN"], "ans": 0, "exp": "RNN（Recurrent Neural Network）は前の時刻の出力を次の入力に使う構造で，時系列・文章等の逐次データ処理に適している。LSTMがRNNの改良版。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 557, "q": "クラウドサービスのオブジェクトストレージの特徴として最も適切なものはどれか。", "opts": ["リレーショナルデータベースである", "ファイルシステム階層でデータ管理する", "データをフラットな構造でIDとメタデータで管理し，大規模・低コストな保存に適す", "データをブロック単位で管理する"], "ans": 2, "exp": "オブジェクトストレージ（S3等）はデータをオブジェクト（ID＋データ＋メタデータ）で管理。階層なし・規模拡張容易・低コスト・Web API対応が特徴。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 558, "q": "OSのメモリ管理でプログラムが必要とするアドレス空間のうち，実際に主記憶にロードされているページ数の割合が低いとどうなるか。", "opts": ["ページフォールトが頻発して処理速度が低下するスラッシングが起きる", "処理速度が上がる", "CPUの使用率が下がる", "メモリ使用量が減る"], "ans": 0, "exp": "スラッシングは物理メモリが不足してページフォールトが多発し，CPUがほぼページ置換処理に費やされて有効な処理が進まない状態。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 559, "q": "インターネットの経路制御で，ルータ間でルーティング情報を交換するプロトコルはどれか。", "opts": ["ICMP", "SNMP", "HTTP", "BGP"], "ans": 3, "exp": "BGP（Border Gateway Protocol）はインターネット上の自律システム（AS）間で経路情報を交換するルーティングプロトコル。インターネットの「背骨」を担う。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 560, "q": "ソフトウェア開発で，Gitなどのバージョン管理システムを使う主な目的はどれか。", "opts": ["テストを自動化する", "コードを自動生成する", "コードを暗号化する", "ソースコードの変更履歴を管理し，複数人での並行開発・変更の巻き戻しを可能にする"], "ans": 3, "exp": "バージョン管理システム（Git等）はソース変更履歴管理・ブランチによる並行開発・マージ・変更の巻き戻しを実現する開発ツール。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 561, "q": "AIのモデル評価指標のうち，「正と予測した中で実際に正の割合」はどれか。", "opts": ["適合率（Precision）", "F1スコア", "正解率（Accuracy）", "再現率（Recall）"], "ans": 0, "exp": "Precision（適合率）= TP/(TP+FP)。正と予測した中で実際に正の割合。Recall（再現率）= TP/(TP+FN)で実際の正例を何割取れたかを示す。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 562, "q": "Webアプリケーションのセッション管理で，セッションIDを推測困難な乱数で生成する理由はどれか。", "opts": ["ユーザーの利便性向上のため", "セッションハイジャック攻撃を防止するため", "処理を高速化するため", "データ圧縮のため"], "ans": 1, "exp": "セッションIDが推測可能だと攻撃者が有効なセッションIDを入手し，他ユーザーのセッションを乗っ取るセッションハイジャックが可能になる。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 563, "q": "WebAPIで、データ形式として人間が読みやすく広く使われる軽量なフォーマットはどれか。", "opts": ["XML", "CSV", "JSON", "バイナリ"], "ans": 2, "exp": "JSON（JavaScript Object Notation）はキー・バリューのテキスト形式でREST APIのデータ交換に広く使用。XMLより軽量で可読性が高い。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 564, "q": "量子コンピュータが実用化された場合に脅かされる可能性があるセキュリティ技術はどれか。", "opts": ["SHA-256ハッシュ", "ワンタイムパッド", "RSA公開鍵暗号", "AES共通鍵暗号"], "ans": 2, "exp": "RSAは素因数分解の計算困難性を安全性の根拠とするが，量子コンピュータのShorアルゴリズムで高速解読される可能性がある。耐量子暗号の研究が進む。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 565, "q": "IT機器の廃棄時に個人情報・機密情報の漏洩を防ぐために行うべき対策として最も適切なものはどれか。", "opts": ["専門業者にデータ消去を依頼するか，物理的に記憶媒体を破壊する", "そのまま廃棄業者に依頼する", "初期化するだけで十分", "機器を解体して廃棄する"], "ans": 0, "exp": "フォーマットや初期化だけではデータ復元ツールで情報を取り出せる。専門業者によるデータ完全消去（上書き方式）や物理破壊が安全な廃棄方法。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 566, "q": "プログラムのコードを他者に読まれても動作は分かるが実装詳細を難読化する技術をどれか。", "opts": ["カプセル化", "暗号化", "難読化（オブファスケーション）", "コンパイル"], "ans": 2, "exp": "難読化は変数名・構造を意図的に分かりにくくしてリバースエンジニアリングを困難にする技術。DRM・セキュリティツールで使用。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 567, "q": "データベースのビューに対してINSERT・UPDATE操作ができない場合の主な理由はどれか。", "opts": ["複数テーブルの結合や集計を含むビューは更新が複雑で制限される場合がある", "ビューには権限がない", "ビューは読み取り専用と法律で決まっている", "インデックスがないから"], "ans": 0, "exp": "ビューへのDML（INSERT/UPDATE/DELETE）はシンプルなビューなら可能だが，GROUP BY・JOIN・集計関数等を含むビューは更新できない制限がある。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 568, "q": "マルウェアのポリモーフィック型（多態型）ウイルスの特徴はどれか。", "opts": ["実行ファイルにのみ感染する", "感染するたびに同じパターンを持つ", "ネットワークを通じてのみ拡散", "感染するたびにコードを変化させてウイルス対策ソフトの検知を回避する"], "ans": 3, "exp": "ポリモーフィック型ウイルスは感染のたびに自身のコードを暗号化・変形させてシグネチャ検知を回避する。ヒューリスティック検知が対策として有効。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 569, "q": "スタックオーバーフロー攻撃の原理として最も適切なものはどれか。", "opts": ["スタックの空き容量を監視する", "再帰呼び出しを無限に繰り返す", "バッファの境界を超えてデータを書き込み，リターンアドレスを書き換えて任意コードを実行させる", "スタックメモリを全て消去する"], "ans": 2, "exp": "バッファオーバーフロー攻撃はスタック上のバッファを溢れさせてリターンアドレスを書き換え，攻撃者コードを実行させる古典的な脆弱性悪用手法。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 570, "q": "サーバの「可用性99.9%」を年間停止時間（分）で表すといくらか。", "opts": ["約8.76時間", "約526分", "約52分", "約52時間"], "ans": 1, "exp": "年間停止時間 = 365×24×60×(1-0.999) = 525,600×0.001 ≈ 526分 ≈ 8.76時間。99.9%（スリーナイン）は約年526分の停止許容。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 571, "q": "情報倫理の観点から，AIが自律的に生死に影響する判断をする場合に最重要視される原則はどれか。", "opts": ["処理速度の最大化", "人間による最終意思決定の保持（人間中心のAI）", "コスト削減", "効率性"], "ans": 1, "exp": "AI倫理・ガバナンスの原則として，特に医療・自動運転等の高リスク判断では人間が最終的に判断する仕組み（Human-in-the-Loop）が重要とされる。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 572, "q": "IT業界の人材区分で，AIやデータサイエンスに特化した高度IT人材を示す職種はどれか。", "opts": ["ネットワークエンジニア", "システムエンジニア", "ITコーディネータ", "データサイエンティスト"], "ans": 3, "exp": "データサイエンティストはデータ分析・機械学習・統計を活用して事業価値を生み出す人材。数理統計・プログラミング・ドメイン知識が必要。", "cat": "テクノロジ", "diff": "easy", "year": 2021}, {"id": 573, "q": "量子暗号通信の理論的な特徴として最も適切なものはどれか。", "opts": ["AESを量子コンピュータで高速化する", "通常の暗号より計算が速い", "量子力学の原理（盗聴すると状態が変化する）を利用して理論上完全な安全性を実現する", "量子コンピュータで暗号化する"], "ans": 2, "exp": "量子暗号（QKD：量子鍵配送）は量子状態の観測問題（盗聴すると状態が変化して検知可能）を利用した暗号鍵配送方式。原理的に盗聴が検知可能。", "cat": "テクノロジ", "diff": "hard", "year": 2021}, {"id": 574, "q": "テクノロジ系のアーキテクチャ設計でAPIファーストの考え方とは何か。", "opts": ["APを全てクラウドに移行する", "モノリシック開発を推進する", "APIを最後に設計する", "UIやDB設計より先にAPIインタフェースを定義し，開発を進める設計手法"], "ans": 3, "exp": "APIファーストはシステム設計時にまずAPIを定義・合意してからフロント・バック各チームが並行開発する手法。マイクロサービス開発で有効。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 575, "q": "コンピュータの基本動作で，CPUが命令を取り出し・解釈・実行する1サイクルの順番として正しいものはどれか。", "opts": ["取り出し→実行→解釈", "取り出し（フェッチ）→解釈（デコード）→実行", "解釈→取り出し→実行", "実行→解釈→取り出し"], "ans": 1, "exp": "CPUの命令実行サイクル：フェッチ（命令取り出し）→デコード（命令解釈）→エグゼキュート（実行）→ライトバック（結果書き込み）が基本。", "cat": "テクノロジ", "diff": "mid", "year": 2021}, {"id": 576, "q": "個人情報保護法の「オプトアウト手続き」の説明として正しいものはどれか。", "opts": ["個人情報保護委員会への届出と本人が拒否できる機会提供を条件に，本人同意なしで第三者提供できる特例手続き", "本人の事前同意なしに提供は一切禁止", "本人の同意があれば自由に利用できる", "政府機関への提供を許可する手続き"], "ans": 0, "exp": "オプトアウト手続きは個人情報保護委員会に届出し本人に通知・拒否機会を与えることで，センシティブ情報以外の第三者提供が同意なし可能。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 577, "q": "AIの倫理指針として「人間中心のAI社会原則」（内閣府）が定める原則に含まれるものはどれか。", "opts": ["AIの活用は大企業のみに限定する", "プライバシー確保・透明性・公平性等を含む人間の権利・尊厳を守る原則", "AI利用を規制するのが最優先", "AIは人間の判断を完全に代替できる"], "ans": 1, "exp": "内閣府の人間中心のAI社会原則（2019）はプライバシー確保・安全・公平性・透明性・説明責任等のAI開発・利用の基本原則を定める。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 578, "q": "企業のデジタル化指標で，2025年の崖を超えるためのDX推進指標としてIPAが定義した尺度はどれか。", "opts": ["COBIT5適用率", "CMMI成熟度レベル", "ISO 27001適合度", "DX推進指標"], "ans": 3, "exp": "DX推進指標（IPA，2019）はDX推進ガバナンス・人材・変革能力等の成熟度を経営者・社内で自己診断するための指標体系。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 579, "q": "IT投資の意思決定に使うNPV（正味現在価値）で，将来キャッシュフローの現在価値を計算するために使う率はどれか。", "opts": ["法人税率", "割引率", "インフレ率", "内部収益率"], "ans": 1, "exp": "NPV計算では将来CFを「割引率（Discount Rate）」で割り引いて現在価値に換算する。割引率は資本コスト・リスクを考慮して設定。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 580, "q": "サイバーセキュリティ基本法の目的として最も適切なものはどれか。", "opts": ["情報システムの統一規格の制定", "個人情報保護の強化", "サイバーセキュリティに関する施策を総合的かつ効率的に推進する", "IT人材の育成"], "ans": 2, "exp": "サイバーセキュリティ基本法（2014年）はサイバーセキュリティ施策の基本理念・国の責務・基本戦略等を定め，NISC設置の根拠法。", "cat": "ストラテジ", "diff": "mid", "year": 2020}, {"id": 581, "q": "フィンテックのスタートアップがAPIで銀行口座へのアクセスを得て新サービスを提供する規制緩和の仕組みはどれか。", "opts": ["デジタル庁の設立", "暗号資産の法制化", "マイナンバーの活用", "オープンバンキング（銀行API開放）"], "ans": 3, "exp": "オープンバンキングは銀行がAPI経由で口座情報・決済機能を第三者（FinTech等）に開放する仕組み。改正銀行法（2018）で推進。", "cat": "ストラテジ", "diff": "hard", "year": 2020}, {"id": 582, "q": "プロジェクト計画で，遅延が許容できるタスクの余裕時間（ゆとり）をどれか。", "opts": ["バッファ", "フロート（スラック）", "マイルストーン", "クリティカルパス"], "ans": 1, "exp": "フロート（Total Float）はクリティカルパス以外のタスクが遅れても全体スケジュールに影響しない余裕時間。CP上のタスクのフロートはゼロ。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 583, "q": "品質マネジメントの手法で，製品・サービスの品質を継続的に改善するPDCAサイクルにおけるA（Act）の内容はどれか。", "opts": ["評価・確認する", "実行する", "目標を設定する", "改善策を実施・標準化する"], "ans": 3, "exp": "PDCAのAction（処置）は確認（Check）で発見した問題・改善策を実施し，成果を次のPlanに反映して標準化する段階。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 584, "q": "プロジェクトで当初の目標が達成できないと判断し，戦略を大きく転換する行為を何というか（スタートアップ文脈）。", "opts": ["ピボット", "スプリント", "スケールアップ", "イテレーション"], "ans": 0, "exp": "ピボット（Pivot）はリーンスタートアップの概念。仮説検証の結果，当初戦略が機能しないと判断し，大きく方向を転換すること。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 585, "q": "ISO/IEC 27001の認証取得により企業が示せることはどれか。", "opts": ["製品品質の高さ", "財務の健全性", "環境マネジメントの実施", "ISMS（情報セキュリティマネジメントシステム）が国際規格に適合して情報セキュリティを体系的に管理している"], "ans": 3, "exp": "ISO/IEC 27001認証はISMSが国際規格要求事項を満たすことを第三者が認定。顧客・取引先への信頼証明として活用される。", "cat": "マネジメント", "diff": "mid", "year": 2020}, {"id": 586, "q": "要件定義フェーズでユーザーストーリーの記述形式として最も適切なものはどれか。", "opts": ["UML図のみ", "「（ユーザーとして）〜したい，なぜならば〜だから」という形式", "フローチャートのみ", "機能要件書のみ"], "ans": 1, "exp": "ユーザーストーリーは「ユーザーロールとして，ゴールを達成したい，なぜならビジネス価値があるから」の形式でアジャイルの要求表現に使用。", "cat": "マネジメント", "diff": "easy", "year": 2020}, {"id": 587, "q": "ネットワークのIPv4における特殊アドレスの説明として正しいものはどれか。", "opts": ["10.0.0.1はグローバルアドレスである", "127.0.0.1はループバックアドレス（自ホスト宛）", "255.255.255.255はデフォルトゲートウェイ", "192.168.0.255はホストアドレスである"], "ans": 1, "exp": "127.0.0.1はローカルループバックアドレス。自ホストのTCP/IPスタックに通信する際に使用。\"localhost\"として自身のサーバにアクセスするときに使用。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 588, "q": "コンピュータグラフィックスで3Dオブジェクトの表面に画像・模様を貼り付ける技術はどれか。", "opts": ["テクスチャマッピング", "シェーダー", "ポリゴン処理", "レイトレーシング"], "ans": 0, "exp": "テクスチャマッピングは3Dモデルのポリゴン表面に2D画像（テクスチャ）を貼り付けてリアルな外観を与える技術。ゲーム・CG・VRで基本技術。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 589, "q": "HTTP/2の特徴として最も適切なものはどれか。", "opts": ["多重化ストリーム・ヘッダ圧縮・サーバプッシュでWebページの表示を高速化する", "HTTP/1.1と全く同じ動作をする", "UDP上で動作する", "セキュリティが低下する"], "ans": 0, "exp": "HTTP/2は1接続で複数リクエストを並行処理（多重化），ヘッダ圧縮（HPACK），サーバプッシュにより，HTTP/1.1より大幅な通信効率化を実現。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 590, "q": "AIのモデル学習で大量データから汎用的な特徴表現を学んだ後，特定タスク向けに追加学習する手法はどれか。", "opts": ["転移学習・ファインチューニング", "強化学習", "ゼロショット学習", "フェデレーテッドラーニング"], "ans": 0, "exp": "転移学習は事前学習済みモデルを新タスクに適用し，ファインチューニングは追加の少量データで最終層等を再学習する。GPT・BERTが代表例。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 591, "q": "複数の端末でデータを共有・同期するためのサービスとして最も広く使われるクラウドサービスはどれか。", "opts": ["FaaS", "IaaS", "SaaS（クラウドストレージ：Dropbox, OneDrive等）", "PaaS"], "ans": 2, "exp": "クラウドストレージ（SaaSの一種）は複数端末・複数ユーザー間でファイルをリアルタイムに同期・共有するサービス。テレワーク普及で必須インフラ化。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 592, "q": "10進数の45を2進数に変換したものはどれか。", "opts": ["101101", "101001", "101011", "110101"], "ans": 0, "exp": "45÷2=22余1, 22÷2=11余0, 11÷2=5余1, 5÷2=2余1, 2÷2=1余0, 1÷2=0余1。下から読むと101101=45。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 593, "q": "ランサムウェア被害を受けた場合に，身代金を支払わずデータを復旧できる唯一の手段はどれか。", "opts": ["OSの再インストール", "ウイルス対策ソフトでの自動復旧", "暗号化キーの総当たり解析", "事前に取得したオフラインバックアップからの復元"], "ans": 3, "exp": "ランサムウェアはファイルを暗号化してキーと引き換えに身代金要求。身代金なしに復旧できるのは暗号化前の状態へのオフラインバックアップのみ。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 594, "q": "BLE（Bluetooth Low Energy）の主な用途として最も適切なものはどれか。", "opts": ["IoTセンサやウェアラブル機器の長期低消費電力通信", "4K動画の高速転送", "PCとプリンタの接続", "Wi-Fiルータへの接続"], "ans": 0, "exp": "BLEはBluetooth 4.0以降の省電力規格。心拍センサ・スマートウォッチ等のウェアラブル，IoTセンサの電池駆動長期運用に最適。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 595, "q": "プログラムでデータを格納するスタック構造で，pop()操作の結果として正しいものはどれか。", "opts": ["最後に追加したデータを取り出して削除する", "末尾のデータを追加する", "全データを削除する", "先頭のデータを追加する"], "ans": 0, "exp": "スタックのpop()は最後にpush()したデータを取り出してスタックから削除するLIFO（後入れ先出し）操作。逆はpush()で先頭に追加。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 596, "q": "ITにおけるAPIの説明として正しいものはどれか。", "opts": ["ネットワークのセキュリティプロトコル", "ソフトウェア間でデータや機能を呼び出せるようにする接続仕様", "コンパイラの一種", "ハードウェアの規格"], "ans": 1, "exp": "API（Application Programming Interface）はソフトウェアが他のソフトウェアの機能・データを呼び出せる標準的なインタフェース仕様。", "cat": "テクノロジ", "diff": "easy", "year": 2020}, {"id": 597, "q": "コンピュータウイルスのワームの特徴として最も適切なものはどれか。", "opts": ["個人情報を収集する", "他のプログラムに感染せず，ネットワーク等を通じて自己複製して拡散する", "実行ファイルに寄生して拡散する", "広告を表示する"], "ans": 1, "exp": "ワームは宿主ファイルを必要とせず，ネットワーク越しに自己複製する。WannaCry等が有名。ウイルスはファイルに寄生，スパイウェアは情報収集が目的。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 598, "q": "解析学でAI学習の勾配降下法において，モデルのパラメータを更新する方向を求めるために計算するものはどれか。", "opts": ["標準偏差", "損失関数の勾配（微分）", "平均値", "分散"], "ans": 1, "exp": "勾配降下法はパラメータに対する損失関数の偏微分（勾配）を計算し，損失が最小になる方向にパラメータを少しずつ更新する最適化アルゴリズム。", "cat": "テクノロジ", "diff": "hard", "year": 2020}, {"id": 599, "q": "組込みシステム（マイコン搭載機器）で，電源投入後に自動的に実行される最初の起動プログラムはどれか。", "opts": ["ファームウェア（BIOS/UEFI相当）", "OS", "アプリケーション", "ドライバ"], "ans": 0, "exp": "ファームウェアはROM/フラッシュに書き込まれた組込みシステムの基本制御プログラム。電源投入後に最初に実行され，ハードウェア初期化・OS起動を担う。", "cat": "テクノロジ", "diff": "mid", "year": 2020}, {"id": 600, "q": "メタデータの説明として最も適切なものはどれか。", "opts": ["データに関するデータ（データの属性・作成日・形式等を記述した情報）", "暗号化されたデータ", "大量のデータ", "構造化データ"], "ans": 0, "exp": "メタデータはデータを説明するデータ。画像のEXIF（撮影日・カメラ機種等），文書のプロパティ（作成者・更新日等）が代表例。", "cat": "テクノロジ", "diff": "easy", "year": 2020}];
